INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('a3f9623817f9deddd9e00', 'Aardonyx', 'Aardonyx celestae', 'Jurassic', 'Early Jurassic', 'Herbivorous', 8.0, NULL, 'uncommon', 'Aardonyx (Afrikaans aard, "earth" + Greek onux, "nail, claw") is a genus of basal sauropodomorph dinosaur. It is known from the type species Aardonyx celestae found from the Early Jurassic Elliot Formation of South Africa. A. celestae was named after Celeste Yates, who prepared much of the first known fossil material of the species. It has arm features that are intermediate between basal sauropodomorphs and more derived sauropods.
Based on the structure of the hind limbs and pelvic girdle of Aardonyx, the dinosaur normally moved bipedally but could drop to quadrupedal movement similar to Iguanodon. It shares some attributes with giant quadrupedal sauropods like Apatosaurus. Australian paleontologist Adam Yates and his team''s discovery of the genus was published online before print in Proceedings of the Royal Society B in November 2009, and was scheduled to appear in the March 2010 issue.', '[]', 'https://cdn.jacobmaynard.dev/creatures/aardonyx-celestae.webp', 1.5113);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('72b28edbfec10ee1f2b1c', 'Abelisaurus', 'Abelisaurus comahuensis', 'Cretaceous', 'Late Cretaceous', 'Carnivorous', 9.0, NULL, 'uncommon', 'Abelisaurus (; "Abel''s lizard") is a genus of predatory abelisaurid theropod dinosaur which lived during the Late Cretaceous Period (Campanian) of what is now South America. It was a bipedal carnivore that probably reached about 7.4 metres (24 ft 3 in) in length, although this is uncertain as it is known from only one partial skull.', '[]', 'https://cdn.jacobmaynard.dev/creatures/abelisaurus-comahuensis.webp', 1.3636);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('829909b7c46b1bf4a1dea', 'Achelousaurus', 'Achelousaurus horneri', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 6.0, NULL, 'uncommon', 'Achelousaurus ( ) is a genus of centrosaurine ceratopsid dinosaur that lived during the Late Cretaceous Period of what is now North America, about 77 to 74.8 million years ago. The first fossils of Achelousaurus were collected in Montana in 1987, by a team led by Jack Horner, with more finds made in 1989. In 1994, Achelousaurus horneri was described and named by Scott D. Sampson; the generic name means "Achelous lizard", in reference to the Greek deity Achelous, and the specific name refers to Horner. The genus is known from a few specimens consisting mainly of skull material from individuals, ranging from juveniles to adults.
A large centrosaurine, Achelousaurus supposedly was about 6 m (20 ft) long, with a weight of about 3 t (3.3 short tons). As a ceratopsian, it walked on all fours, had a short tail and a large head with a hooked beak. It had a bony neck-frill at the rear of the skull, which sported a pair of long spikes, which curved towards the outside.', '[]', 'https://cdn.jacobmaynard.dev/creatures/achelousaurus-horneri.webp', 1.6304);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('562c2967d043c0cf11aef', 'Achillobator', 'Achillobator giganteus', 'Cretaceous', 'Late Cretaceous', 'Carnivorous', 5.0, NULL, 'common', 'Achillobator is a genus of large dromaeosaurid theropod dinosaur that lived during the Late Cretaceous period about 96 million to 89 million years ago in what is now the Bayan Shireh Formation of Mongolia. The genus is currently monotypic, only including the type species A. giganticus. The first remains were found in 1989 during a Mongolian-Russian field expedition and later described in 1999. Remains at the type locality of Achillobator may represent additional specimens. It represents the first and largest dromaeosaurid known from the Bayan Shireh Formation.
It was a large, heavily-built, ground-dwelling, bipedal carnivore that would have been an active feathered predator hunting with the enlarged sickle claw on each second toe. Measuring around 4.5–5 m (15–16 ft) long and weighing between 250–350 kg (550–770 lb), Achillobator is considered to be one of the largest dromaeosaurs, along with Austroraptor and Utahraptor.', '[]', 'https://cdn.jacobmaynard.dev/creatures/achillobator-giganteus.webp', 3.2609);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('9a5b40c29e042b9bbed27', 'Acrocanthosaurus', 'Acrocanthosaurus atokensis', 'Cretaceous', 'Early Cretaceous', 'Carnivorous', 12.0, NULL, 'uncommon', 'Acrocanthosaurus is a genus of carcharodontosaurid dinosaurs that existed in what is now North America during the Barremian and early Cenomanian stages of the Early Cretaceous and Late Cretaceous, from 125 to 99.6 million years ago. Like most dinosaur genera, Acrocanthosaurus contains only a single species, A. atokensis. It had a continent-wide range, with fossil remains known from the U.S. states of Oklahoma, Texas, and Wyoming in the west and Maryland in the east. However, most of these remains are assigned to the species based on the assumption that Acrocanthosaurus is the only large carcharodontosaurid from North America during this time, and the possibility exists that some referred specimens could represent distinct taxa.
Acrocanthosaurus was a bipedal predator.', '[]', 'https://cdn.jacobmaynard.dev/creatures/acrocanthosaurus-atokensis.webp', 1.8692);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('001df6ee1dae1b59f82f1', 'Aegyptosaurus', 'Aegyptosaurus baharijensis', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 15.0, NULL, 'uncommon', 'Aegyptosaurus (meaning ''Egypt''s lizard'') is a genus of sauropod dinosaur that lived in what is now Africa, around 95 million years ago, during the Late Cretaceous Period (Cenomanian faunal stage).', '[]', 'https://cdn.jacobmaynard.dev/creatures/aegyptosaurus-baharijensis.webp', 1.5306);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('bd67f48628c2c10286359', 'Afrovenator', 'Afrovenator abakensis', 'Cretaceous', 'Early Cretaceous', 'Carnivorous', 9.0, NULL, 'uncommon', 'Afrovenator (; "African hunter") is an extinct genus of megalosaurid theropod dinosaur from the Middle or Late Jurassic Tiourarén Formation and maybe the Irhazer II Formation of the Sahara region of Niger in western Africa. Afrovenator represents the only named definitive Gondwanan megalosaur, with proposed material of the group present in the Tacuarembó Formation of Uruguay and the Tendaguru Formation of Tanzania, both dated to the Late Jurassic.', '[]', 'https://cdn.jacobmaynard.dev/creatures/afrovenator-abakensis.webp', 2.459);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('2ed0a2a127b9daaeae62d', 'Agilisaurus', 'Agilisaurus louderbacki', 'Jurassic', 'Late Jurassic', 'Herbivorous', 1.5, NULL, 'common', 'Agilisaurus (; ''agile lizard'') is a genus of ornithischian dinosaur from the Middle Jurassic Period of what is now eastern Asia. The only named species is A. louderbacki, recovered from the Lower Shaximiao Formation of Sichuan, China. It was about 1.2–1.7 m (3.9–5.6 ft) in length, 60 cm (2.0 ft) in hip height, and 40 kg (88 lb) in weight. It has leaf-shaped teeth that were well-adapted to its abrasive, plant-based diet. Most surprisingly, the wavy enamel of the teeth of this genus (and all other ornithopods), presumed to make them more resistant to wear, was previously thought to be exclusive to hadrosaurs. This is also the case for Changchunsaurus from the Cretaceous Period.', '[]', 'https://cdn.jacobmaynard.dev/creatures/agilisaurus-louderbacki.webp', 1.875);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('7e9d3072faa34a482239a', 'Alamosaurus', 'Alamosaurus sanjuanensis', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 21.0, NULL, 'rare', 'Alamosaurus (; meaning "Ojo Alamo lizard") is a genus of titanosaurian sauropod dinosaurs containing a single known species, Alamosaurus sanjuanensis, from the Maastrichtian age of the Late Cretaceous period in what is now southwestern North America. It is one of the few known titanosaurs to have inhabited North America after the nearly 30-million-year absence of sauropods from the North American fossil record ("sauropod hiatus") and probably represents an immigrant from South America.
Adults would have measured around 26 metres (85 ft) long, 5 metres (16 ft) tall at the shoulder and weighed up to 30–35 tonnes (33–39 short tons), though some specimens indicate a larger body size. Isolated vertebrae and limb bones suggest that it could have reached sizes comparable to Argentinosaurus and Puertasaurus, which would make it the absolute largest dinosaur known from North America.', '[]', 'https://cdn.jacobmaynard.dev/creatures/alamosaurus-sanjuanensis.webp', 1.7751);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('0a6a3ab667567ff9580b1', 'Albertaceratops', 'Albertaceratops nesmoi', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 7.0, NULL, 'uncommon', 'Albertaceratops (meaning "Alberta horned face") is a genus of centrosaurine horned dinosaur from the middle Campanian-age Upper Cretaceous Oldman Formation of Alberta, Canada.', '[]', 'https://cdn.jacobmaynard.dev/creatures/albertaceratops-nesmoi.webp', 1.4184);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('f8daac30f3453084aedef', 'Albertosaurus', 'Albertosaurus libratus', 'Cretaceous', 'Late Cretaceous', 'Carnivorous', 9.0, 1500.0, 'uncommon', 'Gorgosaurus is a genus of tyrannosaurid theropod dinosaur that lived in western North America during the Late Cretaceous Period (Campanian), between about 76.5 and 75 million years ago. Fossil remains have been found in the Canadian province of Alberta and the U.S. state of Montana. Paleontologists recognize only the type species, G. libratus, although other species have been erroneously referred to the genus.
Like most known tyrannosaurids, Gorgosaurus was a large bipedal predator, measuring 8–9 metres (26–30 ft) in length and 2–3 metric tons (2.2–3.3 short tons) in body mass. Dozens of large, sharp teeth lined its jaws, while its two-fingered forelimbs were comparatively small. Gorgosaurus was most closely related to Albertosaurus, and more distantly related to the larger Tyrannosaurus. Gorgosaurus and Albertosaurus are extremely similar, distinguished mainly by subtle differences in the teeth and skull bones. Some experts consider G.', '[]', 'https://cdn.jacobmaynard.dev/creatures/albertosaurus-libratus.webp', 1.5385);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('d1fdec7d6ed67892019dc', 'Alectrosaurus', 'Alectrosaurus olseni', 'Cretaceous', 'Late Cretaceous', 'Carnivorous', 5.0, NULL, 'common', 'Alectrosaurus (; meaning "alone lizard") is a genus of tyrannosauroid theropod dinosaur that lived in Asia during the Late Cretaceous period, about some 96 million years ago in what is now the Iren Dabasu Formation.
It was a medium-sized, moderately-built, ground-dwelling, bipedal carnivore, estimated at 5 to 6 m (16 to 20 ft) with a body shape similar to its much larger advanced relative, Tyrannosaurus. Alectrosaurus was a very fast running tyrannosauroid as indicated by the elongated hindlimbs that likely filled the niche of a pursuit predator, a trait that seems to be lost by the advanced and robust tyrannosaurids, in adulthood.', '[]', 'https://cdn.jacobmaynard.dev/creatures/alectrosaurus-olseni.webp', 1.3953);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('f5a3399ed18a7764cb52b', 'Alioramus', 'Alioramus remotus', 'Cretaceous', 'Late Cretaceous', 'Carnivorous', 6.0, NULL, 'uncommon', 'Alioramus (; meaning ''different branch'') is a genus of tyrannosaurid theropod dinosaurs from the Late Cretaceous period of Asia. It currently contains two species. The type species, A. remotus is known from a partial skull and three foot bones recovered from the Mongolian Nemegt Formation, which was deposited in a humid floodplain. These remains were named and described by Soviet paleontologist Sergei Kurzanov in 1976. A second species, A. altai, known from a much more complete skeleton also from the Nemegt Formation, was named and described by Stephen L. Brusatte and colleagues in 2009. Its relationships to other tyrannosaurid genera were at first unclear, with some evidence supporting a hypothesis that Alioramus was closely related to the contemporary species Tarbosaurus bataar.', '[]', 'https://cdn.jacobmaynard.dev/creatures/alioramus-remotus.webp', 1.7647);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('001ba030720b0583fdadb', 'Allosaurus', 'Allosaurus fragilis', 'Jurassic', 'Late Jurassic', 'Carnivorous', 9.7, 2700.0, 'epic', 'Allosaurus is a genus of theropod dinosaur that lived 155 to 145 million years ago during the Late Jurassic period (Kimmeridgian to late Tithonian ages). The first fossil remains that could definitively be ascribed to this genus were described in 1877 by Othniel C. Marsh. The name "Allosaurus" means "different lizard", alluding to its lightweight vertebrae, which Marsh believed were unique. The genus has a very complicated taxonomy and includes at least three valid species, the best known of which is A. fragilis. The bulk of Allosaurus remains come from North America''s Morrison Formation, with material also known from the Alcobaça, Bombarral, and Lourinhã formations in Portugal. It was known for over half of the 20th century as Antrodemus, but a study of the abundant remains from the Cleveland-Lloyd Dinosaur Quarry returned the name "Allosaurus" to prominence.', '[]', 'https://cdn.jacobmaynard.dev/creatures/allosaurus-fragilis.webp', 1.3333);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('917dfc4fc81d355b67811', 'Alvarezsaurus', 'Alvarezsaurus calvoi', 'Cretaceous', 'Late Cretaceous', 'Carnivorous', 2.0, NULL, 'common', 'Alvarezsaurus (; "Don Gregorio Alvarez''s lizard") is a genus of alvarezsaurid dinosaur from the Late Cretaceous, living in Argentina approximately 86 - 83 million years ago. It was a small dinosaur, measuring 1–1.4 m (3.3–4.6 ft) long and weighing approximately 3 kg (6.6 lb). It was found in the Bajo de la Carpa Formation and was named by paleontologist José Bonaparte in 1991 after the historian Don Gregorio Alvarez. The type species is A. calvoi.', '[]', 'https://cdn.jacobmaynard.dev/creatures/alvarezsaurus-calvoi.webp', 1.4019);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('fe299d477d078487f7def', 'Amargasaurus', 'Amargasaurus cazaui', 'Cretaceous', 'Early Cretaceous', 'Herbivorous', 12.0, 9000.0, 'uncommon', 'Amargasaurus (; "La Amarga lizard") is a genus of sauropod dinosaur from the Early Cretaceous epoch (129.4–122.46 mya) of what is now Argentina. The only known skeleton was discovered in 1984 and is virtually complete, including a fragmentary skull, making Amargasaurus one of the best-known sauropods of its epoch. Amargasaurus was first described in 1991 and contains a single known species, Amargasaurus cazaui. It was a large animal, but small for a sauropod, reaching 9 to 13 meters (30 to 43 feet) in length. Most distinctively, it sported two parallel rows of tall spines down its neck and back, taller than in any other known sauropod. In life, these spines could have stuck out of the body as solitary structures that supported a keratinous sheath. An alternate hypothesis, now more favored, postulates that they could have formed a scaffold supporting a skin sail.', '[]', 'https://cdn.jacobmaynard.dev/creatures/amargasaurus-cazaui.webp', 2.0548);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('670c1415e2542feffa49c', 'Ammosaurus', 'Ammosaurus major', 'Jurassic', 'Early Jurassic', 'Herbivorous', 5.0, NULL, 'common', 'Anchisaurus is a genus of basal sauropodomorph dinosaur. It lived during the Early Jurassic Period, and its fossils have been found in the red sandstone of the Upper Portland Formation, Northeastern United States, which was deposited from the Hettangian age into the Sinemurian age, between about 200 and 192 million years ago. Until recently it was classed as a member of Prosauropoda. The genus name Anchisaurus comes from the Greek αγχι (agkhi) anchi-; "near, close" + Greek σαυρος (sauros); "lizard". Anchisaurus was coined as a replacement name for "Amphisaurus", which was itself a replacement name for Hitchcock''s "Megadactylus", both of which had already been used for other animals.', '[]', 'https://cdn.jacobmaynard.dev/creatures/ammosaurus-major.webp', 3.0612);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('e3fb548a1915de9460173', 'Ampelosaurus', 'Ampelosaurus atacis', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 15.0, NULL, 'uncommon', 'Ampelosaurus is a titanosaurian sauropod dinosaur from the Late Cretaceous Period of what is now France. Its type species is A. atacis, named by Le Loeuff in 1995. Its remains were found in a level dating from 71.5 million years ago representing the early Maastrichtian.
Like most sauropods, it would have had a long neck and tail but it also carried armor in the form of osteoderms. In 2005, over 500 bones have been assigned to Ampelosaurus and additional material has been found since, including a partially articulated skeleton with skull, which makes it one of the best known dinosaurs in France. However, recent studies suggest that the type locality is not a monospecific titanosaur bone bed and that part of the bones attributed to Ampelosaurus probably belong to a second titanosaurian taxon.
Ampelosaurus lived on what was the Ibero-Armorican Island, a landmass including much of present-day France and Iberian Peninsula.', '[]', 'https://cdn.jacobmaynard.dev/creatures/ampelosaurus-atacis.webp', 3.1088);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('b8b2074323f2f5fd7ec65', 'Amygdalodon', 'Amygdalodon patagonicus', 'Jurassic', NULL, 'Herbivorous', 15.0, NULL, 'uncommon', 'Amygdalodon (; "almond tooth" for its almond shaped teeth) is an extinct genus of basal sauropod from the Early Jurassic of Argentina. The type species is Amygdalodon patagonicus. Fossils of Amygdalodon have been found in the Toarcian-aged Cerro Carnerero Formation (about 180-172 million years ago). Very little is known about it, but it is one of the few Jurassic dinosaurs from South America found thus far.', '[]', 'https://cdn.jacobmaynard.dev/creatures/amygdalodon-patagonicus.webp', 1.6997);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('09eb260566bcab398e52a', 'Anchiceratops', 'Anchiceratops ornatus', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 6.0, NULL, 'uncommon', 'Anchiceratops is an extinct genus of chasmosaurine ceratopsid dinosaur that lived approximately 73 to 68 million years ago during the latter part of the Cretaceous Period in what is now Alberta, Canada.
Anchiceratops was a medium-sized, heavily built, ground-dwelling, quadrupedal herbivore that could grow up to an estimated 4.3 metres (14 ft) long. Its skull featured two long brow horns and a short horn on the nose. The skull frill was elongated and rectangular, its edges adorned by coarse triangular projections. About a dozen skulls of the genus have been found.', '[]', 'https://cdn.jacobmaynard.dev/creatures/anchiceratops-ornatus.webp', 1.6086);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('4e5f613758293ec0eed2a', 'Anchisaurus', 'Anchisaurus polyzelous', 'Jurassic', 'Early Jurassic', 'Herbivorous', 2.0, NULL, 'common', 'Anchisaurus is a genus of basal sauropodomorph dinosaur. It lived during the Early Jurassic Period, and its fossils have been found in the red sandstone of the Upper Portland Formation, Northeastern United States, which was deposited from the Hettangian age into the Sinemurian age, between about 200 and 192 million years ago. Until recently it was classed as a member of Prosauropoda. The genus name Anchisaurus comes from the Greek αγχι (agkhi) anchi-; "near, close" + Greek σαυρος (sauros); "lizard". Anchisaurus was coined as a replacement name for "Amphisaurus", which was itself a replacement name for Hitchcock''s "Megadactylus", both of which had already been used for other animals.', '[]', 'https://cdn.jacobmaynard.dev/creatures/anchisaurus-polyzelous.webp', 1.7807);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('b93aab5eb3f01fdd74c6f', 'Ankylosaurus', 'Ankylosaurus magniventris', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 8.0, 8000.0, 'epic', 'Ankylosaurus is a genus of armored dinosaur. Its fossils have been found in geological formations dating to the very end of the Cretaceous Period, about 70-66 million years ago, in western North America, making it among the last of the non-avian dinosaurs. It was named by Barnum Brown in 1908; it is monotypic, containing only A. magniventris. The generic name means "fused" or "bent lizard", and the specific name means "great belly". A handful of specimens have been excavated to date, but a complete skeleton has not been discovered. Though other members of Ankylosauria are represented by more extensive fossil material, Ankylosaurus is often considered the archetypal member of its group, despite having some unusual features.
Possibly the largest known ankylosaurid, Ankylosaurus is estimated to have been between 6 and 8 m (20 and 26 ft) long and to have weighed between 4.8 and 8 t (5.3 and 8.8 short tons). It was quadrupedal, with a broad, robust body.', '[]', 'https://cdn.jacobmaynard.dev/creatures/ankylosaurus-magniventris.webp', 3.2609);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('c69931c5ea1dd8a311ca2', 'Anserimimus', 'Anserimimus planinychus', 'Cretaceous', 'Late Cretaceous', 'Carnivorous', 3.5, NULL, 'common', 'Anserimimus is a genus of ornithomimid theropod dinosaur, from the Late Cretaceous Period of what is now Mongolia. It was a lanky, fast-running animal, possibly an omnivore. From what fossils are known, it probably closely resembled other ornithomimids, except for its more powerful forelimbs.', '[]', 'https://cdn.jacobmaynard.dev/creatures/anserimimus-planinychus.webp', 2.5424);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('6b5bf1a958346c733e407', 'Antarctosaurus', 'Antarctosaurus wichmannianus', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 18.0, NULL, 'rare', 'Antarctosaurus (; meaning "southern lizard") is a genus of titanosaurian sauropod dinosaur from the Late Cretaceous Period of what is now South America. The type species, Antarctosaurus wichmannianus, and a second species, Antarctosaurus giganteus, were described by prolific German paleontologist Friedrich von Huene in 1929. Three additional species of Antarctosaurus have been named since then but later studies have considered them dubious or unlikely to pertain to the genus.
The type species, A. wichmannianus, is controversial because there is uncertainty as to whether all the described remains belong to the same individual or even genus. The second species, A. giganteus, is considered dubious, but the fragmentary remains represent one of the largest dinosaurs known.', '[]', 'https://cdn.jacobmaynard.dev/creatures/antarctosaurus-wichmannianus.webp', 1.5);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('e296fc855c7c5eb18d525', 'Apatosaurus', 'Apatosaurus ajax', 'Jurassic', 'Late Jurassic', 'Herbivorous', 21.0, NULL, 'rare', 'Apatosaurus (; meaning "deceptive lizard") is a genus of herbivorous sauropod dinosaur that lived in North America during the Late Jurassic period. Othniel Charles Marsh described and named the first-known species, Apatosaurus ajax, in 1877, and a second species, Apatosaurus louisae, was discovered and named by William H. Holland in 1916. Apatosaurus lived about 152 to 151 million years ago (mya), during the late Kimmeridgian to early Tithonian age, and are now known from fossils in the Morrison Formation of modern-day Colorado, Oklahoma, New Mexico, Wyoming, and Utah in the United States. Apatosaurus had an average length of 21–23 m (69–75 ft), and an average mass of 16.4–22.4 t (16.1–22.0 long tons; 18.1–24.7 short tons).', '[]', 'https://cdn.jacobmaynard.dev/creatures/apatosaurus-ajax.webp', 3.0);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('202ec56f3a042e785d497', 'Aragosaurus', 'Aragosaurus ischiadicus', 'Cretaceous', 'Early Cretaceous', 'Herbivorous', 18.0, NULL, 'rare', 'Aragosaurus (meaning "Aragon lizard") was a genus of sauropod dinosaur from the Early Cretaceous period of Galve, province of Teruel, in the autonomous territory of Aragón, Spain. It was deposited in the Villar del Arzobispo Formation.

 
Aragosaurus was a large, quadrupedal plant-eating (herbivorous) dinosaur, which lived during the early Berriasian, about 145-140 million years ago. It was about 18 metres (59 ft) in length and about 25 tonnes in weight.
Like other sauropods, it had a long neck, a long powerful tail, a small head and a bulky body. It was broadly similar to Camarasaurus. It is represented by a partial skeleton, which was found in Spain and was named by Sanz, Buscalioni, Casanovi and Santafe in 1987. The type species is A. ischiaticus. Like Camarasaurus, Aragosaurus probably had a short, compact skull and a moderately long neck. The teeth were large and wide, and would have been useful for slicing through the leaves and branches of tall conifer trees.', '[]', 'https://cdn.jacobmaynard.dev/creatures/aragosaurus-ischiadicus.webp', 1.7751);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('4f763998ed0fcdb328b40', 'Aralosaurus', 'Aralosaurus tuberiferus', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 8.0, NULL, 'uncommon', 'Aralosaurus is a genus of hadrosaurid dinosaur that lived during the Late Cretaceous in what is now Kazakhstan. It is known only by a posterior half of a skull (devoid of its mandible) and some post-cranial bones found in the Bostobe Formation in rocks dated from the Upper Santonian - lower Campanian boundary, at about 83.6 Ma (millions of years ago). Only one species is known, Aralosaurus tuberiferus, described by Anatoly Konstantinovich Rozhdestvensky in 1968. The genus name means "Aral Sea lizard", because it was found to the northeast of the Aral Sea. The specific epithet tuberiferus means "bearing a tuber" because the posterior part of the nasal bone rises sharply in front of the orbits like an outgrowth. 
Aralosaurus was originally reconstituted with a nasal arch similar to that of North American Kritosaurus (a comparison based on a specimen now placed in the genus Gryposaurus). For many years, Aralosaurus was thus placed in the clade Hadrosaurinae.', '[]', 'https://cdn.jacobmaynard.dev/creatures/aralosaurus-tuberiferus.webp', 2.3904);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('8c9070083c7e894d01bda', 'Archaeoceratops', 'Archaeoceratops oshimai', 'Cretaceous', 'Early Cretaceous', 'Herbivorous', 1.3, NULL, 'common', 'Archaeoceratops, meaning "ancient horned face", is a genus of basal neoceratopsian dinosaur from the Early Cretaceous (Aptian stage) of north central China. It appears to have been bipedal and quite small, reaching 0.9 m (3.0 ft) in length and 10 kg (22 lb) in body mass. It had a comparatively large head but no horns, possessing only a small bony frill projecting from the back of its head.', '[]', 'https://cdn.jacobmaynard.dev/creatures/archaeoceratops-oshimai.webp', 1.8576);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('fa561fb0dad8632def253', 'Archaeopteryx', 'Archaeopteryx lithographica', 'Jurassic', 'Late Jurassic', 'Carnivorous', 0.5, NULL, 'legendary', 'Archaeopteryx, sometimes referred to by its German name, "Urvogel " is a genus of bird-like dinosaurs. The genus name derives from the Ancient Greek ἀρχαῖος (archaîos), meaning ''ancient'', and πτέρυξ (ptérux), meaning ''feather, wing''. Between the late 19th century and the early 21st century, Archaeopteryx was generally accepted by palaeontologists and popular reference books as the oldest known bird (member of the group Avialae). Older potential avialans have since been identified, including Anchiornis, Xiaotingia, Aurornis, and Baminornis.
Archaeopteryx lived in the Late Jurassic around 150 million years ago, in what is now southern Germany, during a time when Europe was an archipelago of islands in a shallow warm tropical sea, much closer to the equator than it is now.', '[]', 'https://cdn.jacobmaynard.dev/creatures/archaeopteryx-lithographica.webp', 1.4151);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('3cbd8d4466fbedfe377de', 'Archaeornithomimus', 'Archaeornithomimus asiaticus', 'Cretaceous', 'Late Cretaceous', 'Carnivorous', 3.5, NULL, 'common', 'Archaeornithomimus (meaning "ancient bird mimic") is a genus of ornithomimosaurian theropod dinosaur that lived during the Late Cretaceous period (around 96 million years ago) in the Iren Dabasu Formation of Inner Mongolia, China.', '[]', 'https://cdn.jacobmaynard.dev/creatures/archaeornithomimus-asiaticus.webp', 0.6663);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('ecc3c998513d4eb3d3417', 'Argentinosaurus', 'Argentinosaurus huinculensis', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 35.0, 70000.0, 'rare', 'Argentinosaurus (meaning "lizard from Argentina") is a genus of giant sauropod dinosaur that lived during the Late Cretaceous period in what is now Argentina. Although it is only known from fragmentary remains, Argentinosaurus is one of the largest known land animals of all time, perhaps the largest, measuring 30–35 m (98–115 ft) long and weighing 65–80 t (72–88 short tons). It was a member of Titanosauria, the dominant group of sauropods during the Cretaceous.
The first Argentinosaurus bone was discovered in 1987 by a farmer on his farm near the city of Plaza Huincul. A scientific excavation of the site led by the Argentine palaeontologist José Bonaparte was conducted in 1989, yielding several back vertebrae and parts of a sacrum—fused vertebrae between the back and tail vertebrae. Additional specimens include a complete femur (thigh bone) and the shaft of another.', '[]', 'https://cdn.jacobmaynard.dev/creatures/argentinosaurus-huinculensis.webp', 2.4);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('659cc0eab2696a21deceb', 'Arrhinoceratops', 'Arrhinoceratops brachyops', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 6.0, NULL, 'uncommon', 'Arrhinoceratops is a genus of herbivorous ceratopsian dinosaur. The name was coined as its original describer concluded it was special because the nose-horn was not a separate bone, however further analysis revealed this was based on a misunderstanding. It lived during the latest Campanian/earliest Maastrichtian stage of the Late Cretaceous, predating its famous relative Triceratops by a few million years, although it was contemporary with Anchiceratops. Its remains have been found in Canada.', '[]', 'https://cdn.jacobmaynard.dev/creatures/arrhinoceratops-brachyops.webp', 1.432);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('1e2b82fc0ec8e4d785d93', 'Atlascopcosaurus', 'Atlascopcosaurus loadsi', 'Cretaceous', 'Early Cretaceous', 'Herbivorous', 3.0, NULL, 'common', 'Atlascopcosaurus () is a genus of herbivorous basal iguanodont dinosaur from the Early Cretaceous Eumeralla Formation of Australia.', '[]', 'https://cdn.jacobmaynard.dev/creatures/atlascopcosaurus-loadsi.webp', 2.2814);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('ef30fed03d06bace67f27', 'Aucasaurus', 'Aucasaurus garridoi', 'Cretaceous', 'Late Cretaceous', 'Carnivorous', 5.0, NULL, 'common', 'Aucasaurus (meaning ''Auca Mahuevo lizard'') is a genus of medium-sized abelisaurid theropod dinosaur from Argentina that lived during the Late Cretaceous (Santonian to Campanian stage) of the Anacleto Formation. It was smaller than the related Carnotaurus, although more derived in some ways, such as its extremely reduced arms and almost total lack of fingers.
The type skeleton is complete to the thirteenth caudal vertebra, and so is relatively well understood, and was the most complete abelisaurid known when described in 2002. However, the skull is damaged, causing some paleontologists to speculate that it was involved in a fight prior to death.', '[]', 'https://cdn.jacobmaynard.dev/creatures/aucasaurus-garridoi.webp', 2.027);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('2425398d0917495a25309', 'Austrosaurus', 'Austrosaurus mckillopi', 'Cretaceous', 'Early Cretaceous', 'Herbivorous', 15.0, NULL, 'uncommon', 'Austrosaurus was an extinct genus of sauropod dinosaur from the Allaru Formation, dated to the early Cretaceous (112-100 million years ago), of Central-Western Queensland in Australia.', '[]', 'https://cdn.jacobmaynard.dev/creatures/austrosaurus-mckillopi.webp', 1.3699);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('3801c4cf6b03ee7ce7b44', 'Avaceratops', 'Avaceratops lammersi', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 2.3, NULL, 'common', 'Avaceratops is a genus of small herbivorous ceratopsian dinosaurs which lived during the late Campanian in what are now the Northwest United States. Most fossils come from the Judith River Formation.', '[]', 'https://cdn.jacobmaynard.dev/creatures/avaceratops-lammersi.webp', 1.9868);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('7c6671c03c4e1afaeab3d', 'Avimimus', 'Avimimus portentosus', 'Cretaceous', 'Late Cretaceous', 'Omnivorous', 1.5, NULL, 'common', 'Avimimus, meaning "bird mimic" (Latin avis = bird + mimus = mimic), is a genus of oviraptorosaurian theropod dinosaur, named for its bird-like characteristics, that lived in the late Cretaceous in what is now Mongolia, during the Maastrichtian.', '[]', 'https://cdn.jacobmaynard.dev/creatures/avimimus-portentosus.webp', 1.3986);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('425268d55024ef815a9d0', 'Bactrosaurus', 'Bactrosaurus johnsoni', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 6.0, NULL, 'uncommon', 'Bactrosaurus (; meaning "Club lizard," "baktron" = club + sauros = lizard) is a genus of herbivorous hadrosauroid dinosaur that lived in Asia during the Late Cretaceous, from about 96 to 85 million years ago. The position Bactrosaurus occupies in the Cretaceous makes it one of the earliest known hadrosauroids, and although it is not known from a full skeleton, Bactrosaurus is one of the best known of these early hadrosauroids, making its discovery a significant finding.', '[]', 'https://cdn.jacobmaynard.dev/creatures/bactrosaurus-johnsoni.webp', 1.3333);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('8387b3637b85c9d4b2043', 'Bagaceratops', 'Bagaceratops rozhdestvenskyi', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 1.0, NULL, 'common', 'Bagaceratops (meaning "small-horned face") is a genus of small protoceratopsid dinosaurs that lived in Asia during the Late Cretaceous, around 72 to 71 million years ago. Bagaceratops remains have been reported from the Barun Goyot Formation and Bayan Mandahu Formation. One specimen may argue the possible presence of Bagaceratops in the Djadochta Formation.
Bagaceratops was among the smallest ceratopsians, growing up to 1–1.5 m (3.3–4.9 ft) in length, with a weight about 22.7–45 kg (50–99 lb). Although emerging late in the reign of the dinosaurs, Bagaceratops had a fairly primitive anatomy—when compared to the much derived ceratopsids—and kept the small body size that characterized early ceratopsians. Unlike its close relative, Protoceratops, Bagaceratops lacked premaxillary teeth (cylindrical, blunt teeth near the tip of the upper jaw).', '[]', 'https://cdn.jacobmaynard.dev/creatures/bagaceratops-rozhdestvenskyi.webp', 2.069);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('a8faeb2e3933efc9f25c6', 'Bambiraptor', 'Bambiraptor feinbergorum', 'Cretaceous', 'Late Cretaceous', 'Carnivorous', 1.0, NULL, 'common', 'Bambiraptor is a genus of bird-like dromaeosaurid theropod dinosaur that lived during the Late Cretaceous (about 72 million years ago) of Montana. It was described by scientists at the University of Kansas, Yale University, and the University of New Orleans. The holotype fossil is less than 1 m (3.3 ft) long, although this specimen appears to be a juvenile, and it is possible that Bambiraptor is a juvenile Saurornitholestes. It is even suspected that the type specimen is a chimera, based on the fact that "there are elements of three different similarly sized lower legs included in the holotype." Because of its small size, it was named Bambiraptor feinbergi, after the popular Disney movie character (the name literally translates to "Bambi thief") and the surname of the wealthy family who bought and lent the specimen to the new Graves Museum of Natural History in Florida.', '[]', 'https://cdn.jacobmaynard.dev/creatures/bambiraptor-feinbergorum.webp', 1.1538);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('579bfbe2c277a97896446', 'Barapasaurus', 'Barapasaurus tagorei', 'Jurassic', 'Early Jurassic', 'Herbivorous', 14.0, NULL, 'uncommon', 'Barapasaurus is a genus of basal sauropod dinosaur from Jurassic rocks of India. The only species is B. tagorei. Barapasaurus comes from the lower part of the Kota Formation, which is of Early to Middle Jurassic in age. It is therefore one of the earliest known sauropods. Barapasaurus is known from approximately 300 bones from at least six individuals, so that the skeleton is almost completely known except for the anterior cervical vertebrae and the skull. This makes Barapasaurus one of the most completely known sauropods from the Early Jurassic.', '[]', 'https://cdn.jacobmaynard.dev/creatures/barapasaurus-tagorei.webp', 2.0134);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('41ec42efd8b8e4f076322', 'Barosaurus', 'Barosaurus lentus', 'Jurassic', 'Late Jurassic', 'Herbivorous', 24.0, NULL, 'rare', 'Barosaurus is a genus of giant, long-tailed, long-necked, plant-eating sauropod dinosaur closely related to the more familiar Diplodocus. Definitive remains have been found in the Morrison Formation from the Upper Jurassic Period of South Dakota, Utah and Montana, with other possible remains also found in Colorado, eastern Wyoming and Oklahoma. The generic name, Barosaurus, comes from the Greek words barys (βαρυς) meaning "heavy" and sauros (σαυρος) meaning "lizard", and thus meaning "heavy lizard".', '[]', 'https://cdn.jacobmaynard.dev/creatures/barosaurus-lentus.webp', 1.8868);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('76cda07b7b4c034969f09', 'Baryonyx', 'Baryonyx walkeri', 'Cretaceous', 'Early Cretaceous', 'Carnivorous', 10.0, 2000.0, 'uncommon', 'Baryonyx () is a genus of theropod dinosaur which lived in the Barremian stage of the Early Cretaceous period, about 130–125 million years ago. The first skeleton was discovered in 1983 in the Smokejack Clay Pit, of Surrey, England, in sediments of the Weald Clay Formation, and became the holotype specimen of Baryonyx walkeri, named by palaeontologists Alan J. Charig and Angela C. Milner in 1986. The genus name Baryonyx comes from Ancient Greek βαρύς (barús), meaning "heavy" or "strong", and ὄνυξ (ónux), meaning "claw", alluding to the animal''s very large claw on the first finger; the specific name, walkeri, refers to its discoverer, amateur fossil collector William J. Walker. The holotype specimen is one of the most complete theropod skeletons from the UK (and remains the most complete spinosaurid), and its discovery attracted media attention.', '[]', 'https://cdn.jacobmaynard.dev/creatures/baryonyx-walkeri.webp', 3.0);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('9905b33ee85cd037f606d', 'Becklespinax', 'Becklespinax altispinax', 'Cretaceous', 'Early Cretaceous', 'Carnivorous', 5.0, NULL, 'common', 'Altispinax (; "with high spines") is a genus of large predatory theropod dinosaur from the Early Cretaceous period (Valanginian, 140 to 133 million years ago) of what is now the Wadhurst Clay Formation of East Sussex, England.', '[]', 'https://cdn.jacobmaynard.dev/creatures/becklespinax-altispinax.webp', 1.7751);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('c39241b36a0dd63e9baee', 'Beipiaosaurus', 'Beipiaosaurus inexpectus', 'Cretaceous', 'Early Cretaceous', 'Omnivorous', 2.0, NULL, 'common', 'Beipiaosaurus is a genus of therizinosauroid theropod dinosaurs that lived in China during the Early Cretaceous in the Yixian Formation. The first remains were found in 1996 and formally described in 1999. Before the discovery of Yutyrannus, Beipiaosaurus were among the heaviest dinosaurs known from direct evidence to be feathered. Beipiaosaurus is known from three reported specimens. Numerous impressions of feather structures were preserved that allowed researchers to determine the feathering color which turned out to be brownish.
They were relatively small-sized therizinosaurs, measuring 2.2 m (7.2 ft) long and weighing about 27 kg (60 lb) in contrast to the advanced and giant Segnosaurus or Therizinosaurus. The necks of Beipiaosaurus were shorter than in most therizinosaurs, whose are characterized by elongated necks adapted for high-browsing.', '[]', 'https://cdn.jacobmaynard.dev/creatures/beipiaosaurus-inexpectus.webp', 1.8987);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('eaeaed1c2360db0a32113', 'Bellusaurus', 'Bellusaurus sui', 'Jurassic', NULL, 'Herbivorous', 5.0, NULL, 'common', 'Bellusaurus (meaning "Beautiful lizard", from Vulgar Latin bellus ''beautiful'' (masculine form) and Ancient Greek sauros ''lizard'') was a sauropod dinosaur from the Late Jurassic (Oxfordian) known from juvenile specimens that would have measured about 4.8 metres (16 ft) long. Its fossils were found in Shishugou Formation rocks in the northeastern Junggar Basin in China.', '[]', 'https://cdn.jacobmaynard.dev/creatures/bellusaurus-sui.webp', 0.745);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('542c86a0499c94891f5ae', 'Borogovia', 'Borogovia gracilicrus', 'Cretaceous', 'Late Cretaceous', 'Carnivorous', 1.5, NULL, 'common', 'Borogovia is a troodontid theropod dinosaur genus which lived during the Late Cretaceous Period, in what is now Mongolia. It contains one species, Borogovia gracilicrus.', '[]', 'https://cdn.jacobmaynard.dev/creatures/borogovia-gracilicrus.webp', 0.6538);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('2d424bb39b8dbf6c85776', 'Brachiosaurus', 'Brachiosaurus altithorax', 'Jurassic', 'Late Jurassic', 'Herbivorous', 22.0, 46900.0, 'legendary', 'Brachiosaurus () is a genus of sauropod dinosaur that lived in North America during the Late Jurassic, about 155.6 to 145.5 million years ago. It was first described by American paleontologist Elmer S. Riggs in 1903 from fossils found in the Colorado River valley in western Colorado, United States. Riggs named the dinosaur Brachiosaurus altithorax; the generic name is Greek for "arm lizard", in reference to its proportionately long arms, and the specific name means "deep chest". Brachiosaurus is estimated to have been between 18 and 22 meters (59 and 72 ft) long; body mass estimates of the subadult holotype specimen range from 28.3 to 46.9 metric tons (31.2 to 51.7 short tons). It had a disproportionately long neck, small skull, and large overall size, all of which are typical for sauropods.', '[]', 'https://cdn.jacobmaynard.dev/creatures/brachiosaurus-altithorax.webp', 1.9108);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('b15fb63adc44e6ff22e32', 'Brachylophosaurus', 'Brachylophosaurus canadensis', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 7.0, NULL, 'uncommon', 'Brachylophosaurus is a genus of hadrosaurid dinosaur that lived during the Late Cretaceous period of western North America. It was first named in 1953 by Charles Mortram Sternberg for a skull and skeleton he discovered in 1936 in the Oldman Formation of Alberta, Canada, for which he named the new taxon Brachylophosaurus canadensis. While this single specimen was the only known material of Brachylophosaurus for a long time, extensive discoveries in the Judith River Formation of Montana, USA have uncovered not only additional skulls and skeletons with extensive impressions of skin, but also a bonebed of 800 specimens. The earliest of these discoveries in Montana was named Brachylophosaurus goodwini by John R. Horner, but it is now believed that there was only a single species of Brachylophosaurus, with B. goodwini as either a junior synonym of B. canadensis or an indeterminate member of Brachylophosaurini.', '[]', 'https://cdn.jacobmaynard.dev/creatures/brachylophosaurus-canadensis.webp', 1.9802);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('4415897e30739863ad4c8', 'Brachytrachelopan', 'Brachytrachelopan mesai', 'Jurassic', NULL, 'Herbivorous', 10.0, NULL, 'uncommon', 'Brachytrachelopan is a genus of short-necked sauropod dinosaur from the Late Jurassic (Oxfordian to Tithonian) of Argentina. The holotype and only known specimen was collected from an erosional exposure of fluvial sandstone within the Cañadón Calcáreo Formation on a hill approximately 25 kilometres (16 mi) north-northeast of Cerro Cóndor, Chubut Province, in west-central Argentina, South America. Though very incomplete, the skeletal elements recovered were found in articulation and include eight cervical, twelve dorsal, and three sacral vertebrae, as well as proximal portions of the posterior cervical ribs and all the dorsal ribs, the distal end of the left femur, the proximal end of the left tibia, and the right ilium. Much of the specimen was probably lost to erosion many years before its discovery. The type species is Brachytrachelopan mesai.', '[]', 'https://cdn.jacobmaynard.dev/creatures/brachytrachelopan-mesai.webp', 1.7751);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('4f530a5a62299762bbdc3', 'Buitreraptor', 'Buitreraptor gonzalezorum', 'Cretaceous', 'Late Cretaceous', 'Carnivorous', 1.3, NULL, 'common', 'Buitreraptor (meaning "La Buitrera seizer") is a genus of unenlagiine theropod dinosaurs that lived during the Late Cretaceous of Argentina at the Candeleros Formation. Buitreraptor was described in 2005 and the type species is Buitreraptor gonzalezorum. It was rooster-sized and had a very elongated head with many small teeth.', '[]', 'https://cdn.jacobmaynard.dev/creatures/buitreraptor-gonzalezorum.webp', 1.8809);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('08035270476e2dcb8cc21', 'Camarasaurus', 'Camarasaurus supremus', 'Jurassic', 'Late Jurassic', 'Herbivorous', 23.0, 20000.0, 'rare', 'Camarasaurus supremus is a species of sauropod dinosaur that lived during the Jurassic period in what is now the western United States. It is the type species of Camarasaurus, which also includes the species Camarasaurus grandis, Camarasaurus lentus, and Camarasaurus lewisi. C. supremus was discovered by the paleontologist Edward Drinker Cope in 1877, at the outset of the Bone Wars, a period of scientific competition between Cope and his rival Othniel Marsh. C. supremus is the largest and geologically youngest species in its genus, and was contemporary with several other exceptionally large dinosaurs, such as Saurophaganax and Maraapunisaurus. Despite being the first discovered species of Camarasaurus, C. supremus is relatively rare and poorly known.', '[]', 'https://cdn.jacobmaynard.dev/creatures/camarasaurus-supremus.webp', 1.5038);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('39fea59473ce0e75e24d3', 'Camptosaurus', 'Camptosaurus dispar', 'Jurassic', 'Late Jurassic', 'Herbivorous', 5.0, 1000.0, 'common', 'Camptosaurus is a genus of plant-eating, beaked ornithischian dinosaurs of the Late Jurassic period of western North America and possibly also Europe. The name means ''flexible lizard'' (Greek καμπτος (kamptos) meaning ''bent'' and σαυρος (sauros) meaning ''lizard'').', '[]', 'https://cdn.jacobmaynard.dev/creatures/camptosaurus-dispar.webp', 1.3699);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('1b6d19271ac6144bfe342', 'Carcharodontosaurus', 'Carcharodontosaurus saharicus', 'Cretaceous', 'Late Cretaceous', 'Carnivorous', 12.5, NULL, 'uncommon', 'Carcharodontosaurus (; "shark-toothed lizard") is a genus of large theropod dinosaur that lived in Northwest Africa from about 100 to 94 million years ago during the Cenomanian stage of the Cretaceous. The taxon was first described in 1925 by French paleontologists Charles Depéret and Justin Savornin as Megalosaurus saharicus, based on two fossil teeth discovered in Algeria, which are now lost. A partial skeleton was discovered in Egypt as early as 1914 by crews of German paleontologist Ernst Stromer, although he did not report the find until 1931. Based on this specimen, together with the teeth previously described by Depéret and Savornin, Stromer established the genus Carcharodontosaurus and its type species (species a genus in named for) C. saharicus. Although the Egyptian skeleton was destroyed during World War II, it was subsequently redescribed as the holotype (name-bearing) specimen of a distinct carcharodontosaurid genus, Tameryraptor.', '[]', 'https://cdn.jacobmaynard.dev/creatures/carcharodontosaurus-saharicus.webp', 2.7397);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('cd08a4eaabb034d94ecc3', 'Carnotaurus', 'Carnotaurus sastrei', 'Cretaceous', 'Late Cretaceous', 'Carnivorous', 8.0, NULL, 'epic', 'Carnotaurus is a genus of theropod dinosaur that lived in South America during the Late Cretaceous period, between 69 and 66 million years ago. The only species is Carnotaurus sastrei. Known from a single well-preserved skeleton, it is one of the best-understood theropods from the Southern Hemisphere. The skeleton, found in 1984, was uncovered in the Chubut Province of Argentina from rocks of the La Colonia Formation. Carnotaurus is a derived member of the Abelisauridae, a group of large theropods that occupied the large predatorial niche in the southern landmasses of Gondwana during the late Cretaceous. Within the Abelisauridae, the genus is often considered a member of the Brachyrostra, a clade of short-snouted forms restricted to South America.
Carnotaurus was a lightly built, bipedal predator, measuring 7.5 to 8 m (24.6 to 26.2 ft) in length and weighing 1.3–2.1 metric tons (1.4–2.3 short tons; 1.3–2.1 long tons). As a theropod, Carnotaurus was highly specialized and distinctive.', '[]', 'https://cdn.jacobmaynard.dev/creatures/carnotaurus-sastrei.webp', 1.1299);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('00073e9b476aa6d3df313', 'Caudipteryx', 'Caudipteryx zoui', 'Cretaceous', 'Early Cretaceous', 'Omnivorous', 1.0, 2.0, 'common', 'Caudipteryx (meaning "tail feather") is a genus of small oviraptorosaurian dinosaurs that lived in China during the Early Cretaceous, around 124.6 million years ago. They were feathered and extremely bird-like in their overall appearance, to the point that some paleontologists suggested it was a bird. Two species have been described: C. zoui (the type species), in 1998, and C. dongi, in 2000. Caudipteryx had a stout trunk, long legs, and was probably a swift runner. Its discovery has led to many intensive studies and debate over the relationship between birds and dinosaurs.', '[]', 'https://cdn.jacobmaynard.dev/creatures/caudipteryx-zoui.webp', 1.0345);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('6a8630fcc3421fa788aa1', 'Cedarpelta', 'Cedarpelta bilbeyhallorum', 'Cretaceous', 'Early Cretaceous', 'Herbivorous', 10.0, NULL, 'uncommon', 'Cedarpelta is an extinct genus of basal ankylosaurid dinosaur from Utah that lived during the Late Cretaceous period (Cenomanian to lower Turonian stage, 98.2 to 93 Ma) in what is now the Mussentuchit Member of the Cedar Mountain Formation. The type and only species, Cedarpelta bilbeyhallorum, is known from multiple specimens including partial skulls and postcranial material. It was named in 2001 by Kenneth Carpenter, James Kirkland, Don Burge, and John Bird. Cedarpelta has an estimated length of 7 metres (23 feet) and weight of 5 tonnes (11,023 lbs). The skull of Cedarpelta lacks extensive cranial ornamentation and is one of the only known ankylosaurs with individual skull bones that are not completely fused together.', '[]', 'https://cdn.jacobmaynard.dev/creatures/cedarpelta-bilbeyhallorum.webp', 1.1583);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('435fedc4f1b36fe9fa9c7', 'Centrosaurus', 'Centrosaurus', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 6.0, 1000.0, 'uncommon', 'Centrosaurus is a genus of centrosaurine ceratopsid dinosaur from the Campanian age of the Late Cretaceous of Canada. Its remains have been found in the Dinosaur Park Formation, dating from 76.5 to 75.5 million years ago. The type and only species seen as valid today is Centrosaurus apertus.', '[]', 'https://cdn.jacobmaynard.dev/creatures/centrosaurus.webp', 1.3857);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('3fb2db7e3dfe11d219f3c', 'Ceratosaurus', 'Ceratosaurus nasicornis', 'Jurassic', 'Late Jurassic', 'Carnivorous', 7.0, 980.0, 'uncommon', 'Ceratosaurus is a genus of carnivorous theropod dinosaur that lived during the Late Jurassic period in North America and Europe. The genus was first described in 1884 by American paleontologist Othniel Charles Marsh based on a nearly complete skeleton discovered in Garden Park, Colorado, in rocks belonging to the Morrison Formation. The type species is Ceratosaurus nasicornis.
The Garden Park specimen remains the most complete skeleton known from the genus and only a handful of additional specimens have been described since. Two additional species, Ceratosaurus dentisulcatus and Ceratosaurus magnicornis, were described in 2000 from two fragmentary skeletons from the Cleveland-Lloyd Quarry of Utah and from the vicinity of Fruita, Colorado. These species are no longer accepted by most paleontologists, and all three skeletons possibly represent different growth stages of the same species.', '[]', 'https://cdn.jacobmaynard.dev/creatures/ceratosaurus-nasicornis.webp', 2.8037);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('9ef1db6d18b6878fdfd41', 'Cetiosauriscus', 'Cetiosauriscus stewarti', 'Jurassic', NULL, 'Herbivorous', 15.0, NULL, 'uncommon', 'Cetiosauriscus is a genus of sauropod dinosaur that lived between 166 and 164 million years ago during the Callovian (Middle Jurassic Period) in what is now England. A herbivore, Cetiosauriscus had – by sauropod standards – a moderately long tail, and longer forelimbs, making them as long as its hindlimbs. It has been estimated as about 15 m (49 ft) long and between 4 and 10 t (3.9 and 9.8 long tons; 4.4 and 11.0 short tons) in weight.
The only known fossil includes most of the rear half of a skeleton as well as a forelimb (NHMUK PV R3078). Found in Cambridgeshire in the 1890s, it was described by Arthur Smith Woodward in 1905 as a new specimen of the species Cetiosaurus leedsi. This was changed in 1927, when Friedrich von Huene found NHMUK PV R3078 and the C. leedsi type specimen to be too different from Cetiosaurus, warranting its own genus, which he named Cetiosauriscus, meaning "Cetiosaurus-like".', '[]', 'https://cdn.jacobmaynard.dev/creatures/cetiosauriscus-stewarti.webp', 1.6997);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('d0ac565c362cd5e1e8028', 'Cetiosaurus', 'Cetiosaurus oxoniensis', 'Jurassic', NULL, 'Herbivorous', 18.0, NULL, 'rare', 'Cetiosaurus and sauros/σαυρος meaning ''lizard''), is a genus of herbivorous sauropod dinosaur from the Middle Jurassic Period, living about 171 to 165 million years ago during the Bajocian and Bathonian ages in what is now Britain and probably France.
Cetiosaurus was named in 1842, making it the first sauropod from which bones were described and is the most complete sauropod found in England. It was so named because its describer, Sir Richard Owen, supposed it was a marine creature, initially an extremely large crocodile, and did not recognise it for a land-dwelling dinosaur. Because of the early description many species would be named in the genus, eventually eighteen of them. Most of these have now been placed in other genera or are understood to be dubious names, based on poor fossil material. The last is true also of the original type species, Cetiosaurus medius, and so C.', '[]', 'https://cdn.jacobmaynard.dev/creatures/cetiosaurus-oxoniensis.webp', 2.0761);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('18f1620933125db9efb41', 'Chaoyangsaurus', 'Chaoyangsaurus youngi', 'Jurassic', 'Late Jurassic', 'Herbivorous', 1.1, NULL, 'common', 'Chaoyangsaurus ("Chaoyang lizard") is a genus of marginocephalian dinosaur from the Late Jurassic (about between 150.8 and 145.5 million years ago) of China. Chaoyangsaurus belonged to the Ceratopsia (Greek for "horned faces"). Chaoyangsaurus, like all ceratopsians, was primarily a herbivore.', '[]', 'https://cdn.jacobmaynard.dev/creatures/chaoyangsaurus-youngi.webp', 0.7362);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('8e3f77b6893a246aa7787', 'Chasmosaurus', 'Chasmosaurus', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 5.0, 2500.0, 'common', 'Chasmosaurus is a genus of ceratopsid dinosaur from the Late Cretaceous Period in North America. Its given name means ''opening lizard'', referring to the large openings (fenestrae) in its frill (Greek chasma, meaning ''opening'', ''hollow'', or ''gulf''; and sauros, meaning ''lizard''). With a length of 4.3–4.8 metres (14.1–15.7 ft) and a weight of 1.5–2 tonnes (1.7–2.2 short tons)—or anywhere from 2,200 to nearly 5,000 lbs—Chasmosaurus was of a slightly smaller to "average" size, especially when compared to larger ceratopsids (such as Triceratops, which were about the size of an African bush elephant).
It was initially to be called Protorosaurus, but this name had been previously published for another animal. All of the excavated specimens of Chasmosaurus were collected at the Dinosaur Park Formation, Dinosaur Provincial Park, Alberta, Canada. Referred specimens of C. russelli come from the lower beds of the formation, while C. belli comes from the middle and upper beds.', '[]', 'https://cdn.jacobmaynard.dev/creatures/chasmosaurus.webp', 1.5152);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('121d0927c82138f257272', 'Chindesaurus', 'Chindesaurus bryansmalli', 'Triassic', 'Late Triassic', 'Carnivorous', 4.0, NULL, 'common', 'Chindesaurus is an extinct genus of basal saurischian dinosaur from the Late Triassic (213-210 million years ago) of the southwestern United States. It is known from a single species, C. bryansmalli, based on a partial skeleton recovered from Petrified Forest National Park in Arizona. The original specimen was nicknamed "Gertie", and generated much publicity for the park upon its discovery in 1984 and airlift out of the park in 1985. Other fragmentary referred specimens have been found in Late Triassic sediments throughout Arizona, New Mexico, and Texas, but these may not belong to the genus. Chindesaurus was a bipedal carnivore, approximately as large as a wolf.
Chindesaurus''s classification is debated, and various papers have had different conclusions on its affinities.', '[]', 'https://cdn.jacobmaynard.dev/creatures/chindesaurus-bryansmalli.webp', 2.0966);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('bd83c7792c2d1b4c3d447', 'Chinshakiangosaurus', 'Chinshakiangosaurus zhongheensis', 'Jurassic', 'Late Jurassic', 'Herbivorous', 11.0, NULL, 'uncommon', 'Chinshakiangosaurus is a genus of basal sauropod dinosaur. The only species, Chinshakiangosaurus chunghoensis, is known from a fragmentary skeleton found in Early Jurassic rocks in China. It is one of the few basal sauropods with preserved skull bones and therefore important for the understanding of the early evolution of this group, and also shows that early sauropods may have possessed fleshy cheeks.', '[]', NULL, NULL);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('406d3407adccca436a2a7', 'Chirostenotes', 'Chirostenotes pergracilis', 'Jurassic', 'Late Jurassic', 'Omnivorous', 1.7, NULL, 'common', 'Chirostenotes is a genus of oviraptorosaurian dinosaur from the late Cretaceous (about 76.5–75 million years ago) of Alberta, Canada. The type species is Chirostenotes pergracilis.', '[]', 'https://cdn.jacobmaynard.dev/creatures/chirostenotes-pergracilis.webp', 0.75);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('8c18c70109215fa2a321d', 'Chubutisaurus', 'Chubutisaurus insignis', 'Cretaceous', 'Early Cretaceous', 'Herbivorous', 23.0, NULL, 'rare', 'Chubutisaurus (meaning "Chubut lizard") is a genus of somphospondylan sauropod dinosaur from the Late Cretaceous (Cenomanian) Cerro Barcino Formation of Argentina. The type species, Chubutisaurus insignis, was described by del Corro in 1975. Chubutisaurus had a more robust radius than Venenosaurus. In 2010 Gregory S. Paul gave a length of 18 metres (59 ft) and a weight of 12 tonnes (13 short tons). Thomas Holtz estimated its length at 23 metres (75 ft) in 2012.', '[]', 'https://cdn.jacobmaynard.dev/creatures/chubutisaurus-insignis.webp', 1.9417);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('aa0359e6b8303913e2990', 'Chungkingosaurus', 'Chungkingosaurus jiangbeiensis', 'Jurassic', 'Late Jurassic', 'Herbivorous', 4.0, NULL, 'common', 'Chungkingosaurus (meaning "Chongqing Lizard") is a genus of stegosaurian dinosaur from the Late Jurassic Upper Shaximiao Formation in what is now China. The type species is Chungkingosaurus jiangbeiensis.', '[]', 'https://cdn.jacobmaynard.dev/creatures/chungkingosaurus-jiangbeiensis.webp', 2.439);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('02405db8d9629ea20c3aa', 'Citipati', 'Citipati osmolskae', 'Cretaceous', 'Late Cretaceous', 'Omnivorous', 2.1, NULL, 'common', 'Citipati ([t͡ɕit̪ipɜt̪i]; meaning "funeral pyre lord") is a genus of oviraptorid dinosaur that lived in Asia during the Late Cretaceous period, about 75 million to 71 million years ago. It is mainly known from the Ukhaa Tolgod locality at the Djadochta Formation, where the first remains were collected during the 1990s. The genus and type species Citipati osmolskae were named and described in 2001. A second species from the adjacent Zamyn Khondt locality may also exist. Citipati is one of the best-known oviraptorids thanks to a number of well-preserved specimens, including individuals found in brooding positions atop nests of eggs, though most of them were initially referred to the related Oviraptor. These nesting specimens have helped to solidify the link between non-avian dinosaurs and birds.
Citipati was among the largest oviraptorids; it is estimated to have been around 2.5–2.9 m (8.2–9.5 ft) in length and to have weighed 75–110 kg (165–243 lb).', '[]', 'https://cdn.jacobmaynard.dev/creatures/citipati-osmolskae.webp', 0.9231);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('703b861c59fb61eb3b942', 'Coelophysis', 'Coelophysis', 'Triassic', 'Late Triassic', 'Carnivorous', 2.0, 27.0, 'common', 'Coelophysis (from Ancient Greek κοῖλος (koilos), "hollow", and φύσεις (fysis), "form") is an extinct genus of coelophysid theropod dinosaurs that lived approximately 215 to 201.4 million years ago during the late Triassic period from the middle Norian to Rhaetian age in what is now the southwestern United States. Megapnosaurus was once considered to be a species within this genus, but this interpretation has been challenged and the genus Megapnosaurus is now considered valid.
Coelophysis was a small, slenderly built, ground-dwelling, bipedal carnivore that could grow up to 3 m (9.8 ft) long. It is one of the earliest known dinosaur genera. Scattered material representing similar animals has been found worldwide in some Late Triassic and Early Jurassic formations.
The type species C. bauri, originally placed in the genus Coelurus by Edward Drinker Cope in 1887, was described by the latter in 1889. The names Longosaurus and Rioarribasaurus are synonymous with Coelophysis.', '[]', 'https://cdn.jacobmaynard.dev/creatures/coelophysis.webp', 2.5);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('2cefc00c07b5ed1c64e55', 'Coelurus', 'Coelurus fragilis', 'Jurassic', 'Late Jurassic', 'Carnivorous', 1.8, NULL, 'common', 'Coelurus is a genus of coelurosaurian dinosaur from the Late Jurassic period (mid-late Kimmeridgian faunal stage, 155–152 million years ago). The name means "hollow tail", referring to its hollow tail vertebrae (Greek κοῖλος, koilos = hollow + οὐρά, oura = tail). Although its name is linked to one of the main divisions of theropods (Coelurosauria), it has historically been poorly understood, and sometimes confused with its better-known contemporary Ornitholestes. Like many dinosaurs studied in the early years of paleontology, it has had a confusing taxonomic history, with several species being named and later transferred to other genera or abandoned. Only one species is currently recognized as valid: the type species, C. fragilis, described by Othniel Charles Marsh in 1879. It is known from one partial skeleton found in the Morrison Formation of Wyoming, United States. It was a small bipedal carnivore with elongate legs.', '[]', 'https://cdn.jacobmaynard.dev/creatures/coelurus-fragilis.webp', 2.3077);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('260d84d9bdb201a9d7281', 'Coloradisaurus', 'Coloradisaurus brevis', 'Triassic', 'Late Triassic', 'Omnivorous', 4.0, NULL, 'common', 'Coloradisaurus (meaning "Los Colorados lizard") is a genus of massospondylid sauropodomorph dinosaur. It lived during the Late Triassic period (Norian stage) in what is now La Rioja Province, Argentina. It is known from two specimens collected from the Los Colorados Formation of the Ischigualasto-Villa Unión Basin.', '[]', 'https://cdn.jacobmaynard.dev/creatures/coloradisaurus-brevis.webp', 1.9934);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('e3b12550114f2ac47e5a8', 'Compsognathus', 'Compsognathus longipes', 'Jurassic', 'Late Jurassic', 'Carnivorous', 0.7, 3.0, 'rare', 'Compsognathus is a genus of small, bipedal, carnivorous theropod dinosaur. Members of its single species Compsognathus longipes could grow to around the size of a chicken. They lived about 150 million years ago, during the Tithonian age of the late Jurassic period, in what is now Europe. Paleontologists have found two well-preserved fossils, one in Germany in the 1850s and the second in France more than a century later. Today, C. longipes is the only recognized species, although the French specimen was once thought to belong to a separate species named C. corallestris.
Many presentations still describe Compsognathus as "chicken-sized" dinosaurs because of the size of the German specimen, which is now believed to be a juvenile.', '[]', 'https://cdn.jacobmaynard.dev/creatures/compsognathus-longipes.webp', 2.2727);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('46a7ad26444dd0fa67f4f', 'Conchoraptor', 'Conchoraptor gracilis', 'Cretaceous', 'Late Cretaceous', 'Carnivorous', 1.5, NULL, 'common', 'Conchoraptor (meaning "conch plunderer") is a genus of oviraptorid dinosaurs that lived in Asia during the Late Cretaceous epoch, about 70 million years ago. It is known from the Barun Goyot and possibly the Nemegt formation of Mongolia.', '[]', 'https://cdn.jacobmaynard.dev/creatures/conchoraptor-gracilis.webp', 1.6667);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('76e8b2b4ed1deb8cb97ac', 'Confuciusornis', 'Confuciusornis sanctus', 'Cretaceous', 'Early Cretaceous', 'Carnivorous', 0.3, NULL, 'common', 'Confuciusornis is a genus of basal crow-sized avialan confuciusornithid theropod dinosaur from the Early Cretaceous Period of the Yixian and Jiufotang Formations of China, dating from 125 to 120 million years ago. Like modern birds, Confuciusornis had a toothless beak, but closer and later relatives of modern birds such as Hesperornis and Ichthyornis were toothed, indicating that the loss of teeth occurred convergently in Confuciusornis and living birds. It was thought to be the oldest known bird to have a beak, though this title now belongs to an earlier relative Eoconfuciusornis. It was named after the Chinese moral philosopher Confucius (551–479 BC). Confuciusornis is one of the most abundant vertebrates found in the Yixian Formation, and several hundred complete specimens have been found.', '[]', 'https://cdn.jacobmaynard.dev/creatures/confuciusornis-sanctus.webp', 1.4963);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('20d1df9c1e53aeab3c462', 'Corythosaurus', 'Corythosaurus casuarius', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 10.0, NULL, 'uncommon', 'Corythosaurus is a genus of hadrosaurid "duck-billed" dinosaur from the Late Cretaceous period, about 77–75.7 million years ago, in what is now western North America. Its name is derived from the Greek word κόρυς, meaning "helmet", named and described in 1914 by Barnum Brown. Corythosaurus is now thought to be a lambeosaurine, thus related to Lambeosaurus, Nipponosaurus, Velafrons, Hypacrosaurus, and Olorotitan. Corythosaurus has an estimated length of 7.7–9 metres (25–30 ft) and has a skull, including the crest, that is 70.8 centimetres (27.9 in; 2.32 ft) tall.
Corythosaurus is known from many complete specimens, including the nearly complete holotype found by Brown in 1911. The holotype skeleton is only missing the last section of the tail and part of the front legs, but was preserved with impressions of polygonal scales. Corythosaurus is known from many skulls with tall crests that resemble those of the cassowary and a Corinthian helmet.', '[]', 'https://cdn.jacobmaynard.dev/creatures/corythosaurus-casuarius.webp', 2.8037);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('1fa97d480ca101f9ef135', 'Cryolophosaurus', 'Cryolophosaurus elliotti', 'Jurassic', 'Early Jurassic', 'Carnivorous', 8.0, 500.0, 'uncommon', 'Cryolophosaurus is a genus of large theropod dinosaur known from only a single species, Cryolophosaurus ellioti, from the Early Jurassic of Antarctica. It was one of the largest theropods of the Early Jurassic, with the subadult, being estimated to have reached 6–7 metres (20–23 ft) long and weighed 350–465 kilograms (772–1,025 lb).
Cryolophosaurus was first excavated from Antarctica''s Early Jurassic, Pliensbachian aged Hanson Formation, formerly the upper Falla Formation, by paleontologist Dr. William Hammer in 1991. It was the first carnivorous dinosaur to be discovered in Antarctica, and the first non-avian dinosaur from the continent to be officially named. The sediments in which its fossils were found have been dated to about 196 to 188 million years ago, representing the Early Jurassic Period.
Cryolophosaurus is known from a skull, a femur and other material, all of which have caused its classification to vary greatly.', '[]', 'https://cdn.jacobmaynard.dev/creatures/cryolophosaurus-elliotti.webp', 2.1505);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('07ea45db3fa1c379e1661', 'Dacentrurus', 'Dacentrurus armatus', 'Jurassic', 'Late Jurassic', 'Herbivorous', 6.0, NULL, 'uncommon', 'Dacentrurus (meaning "tail full of points") is an extinct genus of stegosaurian dinosaur from the Late Jurassic and perhaps Early Cretaceous (154–140 million years ago) of Europe. Its type species, D. armatus, was named in 1875 as Omosaurus armatus, based on a skeleton found in a clay pit in the Kimmeridge Clay in Swindon, England. In 1902 the genus was renamed Dacentrurus because the name Omosaurus had already been used for a phytosaur in 1856. After 1875, half a dozen other species would be named but perhaps only Dacentrurus armatus is valid.
Dacentrurus is among the largest known stegosaurs, measuring around 8–9 metres (26–30 ft) long and weighing up to 5–7.4 metric tons (5.5–8.2 short tons). Finds of this animal have been limited, so much of its appearance is uncertain and its relationship with other members of the Dacentrurinae are contentious. Some researchers suggest that Miragaia longicollum represents a junior synonym of this taxon.', '[]', 'https://cdn.jacobmaynard.dev/creatures/dacentrurus-armatus.webp', 2.0134);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('a10116b1412731485e6b6', 'Daspletosaurus', 'Daspletosaurus torosus', 'Cretaceous', 'Late Cretaceous', 'Carnivorous', 9.0, NULL, 'uncommon', 'Daspletosaurus is a genus of tyrannosaurid dinosaur that lived in Laramidia between about 77 and 74.4 million years ago, during the Late Cretaceous Period. The genus Daspletosaurus contains three named species. Fossils of the earlier type species, D. torosus, have been found in Alberta, while fossils of a later species, D. horneri, have been found in Montana and Alberta. D. wilsoni has been suggested as an intermediate species between D. torosus and D. horneri that evolved through anagenesis, though further research may be required to definitively support the theory.
There are also multiple specimens which may represent new species of Daspletosaurus from Alberta and Montana, but these have not been formally described. The taxon Thanatotheristes has been suggested to represent a species of Daspletosaurus, D. degrootorum, but this has not been widely supported.', '[]', 'https://cdn.jacobmaynard.dev/creatures/daspletosaurus-torosus.webp', 1.0949);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('b39edc146b73e48f5285b', 'Datousaurus', 'Datousaurus bashanensis', 'Jurassic', NULL, 'Herbivorous', 15.0, NULL, 'uncommon', 'Datousaurus (meaning "chieftain lizard" or "big-head lizard"; originally named using the Malay datu, after its Chinese nickname qiulong - literally "chieftain dragon" - but also a pun on its big head; da tou means "big head" in Chinese) is a sauropod dinosaur from the Middle Jurassic Lower Shaximiao Formation in Sichuan province, China. It shared the local Middle Jurassic landscape with other sauropods such as Shunosaurus, Omeisaurus, and Protognathosaurus, the neornithischian Xiaosaurus, and the early stegosaur Huayangosaurus as well as the carnivorous Gasosaurus.', '[]', 'https://cdn.jacobmaynard.dev/creatures/datousaurus-bashanensis.webp', 0.75);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('6751cd6b66eba3a068068', 'Deinocheirus', 'Deinocheirus mirificus', 'Cretaceous', 'Late Cretaceous', 'Omnivorous', 10.0, NULL, 'uncommon', 'Deinocheirus is a genus of large ornithomimosaur that lived during the Late Cretaceous around 70 million years ago. In 1965, a pair of large arms, shoulder girdles, and a few other bones of a new dinosaur were first discovered in the Nemegt Formation of Mongolia. In 1970, this specimen became the holotype of the only species within the genus, Deinocheirus mirificus; the genus name is Greek for "horrible hand". No further remains were discovered for almost fifty years, and its nature remained a mystery. Two more complete specimens were described in 2014, which shed light on many aspects of the animal. Parts of these new specimens had been looted from Mongolia some years before, but were repatriated in 2014.
Deinocheirus was an unusual ornithomimosaur, the largest of the clade at 11 m (36 ft) long, and weighing 6.5 t (7.2 short tons). Though it was a bulky animal, it had many hollow bones which saved weight.', '[]', 'https://cdn.jacobmaynard.dev/creatures/deinocheirus-mirificus.webp', 2.2901);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('73c2101cb11150082a6ac', 'Deinonychus', 'Deinonychus antirrhopus', 'Cretaceous', 'Early Cretaceous', 'Carnivorous', 3.4, 100.0, 'epic', 'Deinonychus ''terrible'' and ὄνυξ (ónux), genitive ὄνυχος (ónukhos) ''claw'') is a genus of dromaeosaurid theropod dinosaur with one described species, Deinonychus antirrhopus. This species, which could grow up to 3.4 meters (11 ft) long, lived during the Early and Late Cretaceous Period, about 115–93.9 million years ago (from the mid-Aptian to Cenomanian stages). Fossils have been recovered from the U.S. states of Montana, Utah, Wyoming, and Oklahoma, in rocks of the Cloverly Formation and Antlers Formation, though teeth that may belong to Deinonychus have been found much farther east in Maryland.
Paleontologist John Ostrom''s study of Deinonychus in the late 1960s revolutionized the way scientists thought about dinosaurs, leading to the "dinosaur renaissance" and igniting the debate on whether dinosaurs were warm-blooded or cold-blooded. Before this, the popular conception of dinosaurs had been one of plodding, reptilian giants.', '[]', 'https://cdn.jacobmaynard.dev/creatures/deinonychus-antirrhopus.webp', 1.3825);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('7b3577bbf1eeaaa9561e0', 'Deltadromeus', 'Deltadromeus agilis', 'Cretaceous', 'Late Cretaceous', 'Carnivorous', 8.1, NULL, 'uncommon', 'Deltadromeus (meaning "delta runner") is an extinct genus of controversial theropod dinosaur that lived in present-day Morocco during the mid-Cretaceous period. It was described by American paleontologist Paul Sereno and colleagues in 1996. The genus contains a single species, D. agilis, named based on an incomplete postcranial skeleton, the holotype (name-bearing) specimen. However, some fossils from the Bahariya Formation of Egypt that were formerly referred to the theropod Bahariasaurus have been suggested to belong to Deltadromeus. The holotype specimen of Deltadromeus was unearthed by a joint expedition by the University of Chicago and the Service Géologique du Maroc in Errachidia Province, eastern Morocco in rock layers coming from the Gara Sbaa Formation of the Kem Kem Group. This indicates that these fossils date to the Cenomanian stage of the Cretaceous period, 100-95 million years ago.', '[]', 'https://cdn.jacobmaynard.dev/creatures/deltadromeus-agilis.webp', 1.5152);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('647376305d1c9f4534f3a', 'Dicraeosaurus', 'Dicraeosaurus hansemanni', 'Jurassic', 'Late Jurassic', 'Herbivorous', 20.0, NULL, 'rare', 'Dicraeosaurus (Gr. δικραιος, dikraios "bifurcated, double-headed" + Gr. σαυρος, sauros "lizard") is a genus of diplodocoid sauropod dinosaur that lived in what is now Lindi Region, Tanzania during the late Jurassic period. The genus was named for the neural spines on the back of its neck. The first fossil was described by paleontologist Werner Janensch in 1914.', '[]', 'https://cdn.jacobmaynard.dev/creatures/dicraeosaurus-hansemanni.webp', 2.0619);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('b8565efa4c39eb000819c', 'Dilophosaurus', 'Dilophosaurus', 'Jurassic', 'Early Jurassic', 'Carnivorous', 7.0, 400.0, 'rare', 'Dilophosaurus is a genus of theropod dinosaurs that lived in what is now North America during the Early Jurassic, about 186 million years ago. Three skeletons were discovered in northern Arizona in 1940, and the two best preserved were collected in 1942. The most complete specimen became the holotype of a new species in the genus Megalosaurus, named M. wetherilli by Samuel P. Welles in 1954. Welles found a larger skeleton belonging to the same species in 1964. Realizing it bore crests on its skull, he assigned the species to the new genus Dilophosaurus in 1970, as Dilophosaurus wetherilli. The genus name means "two-crested lizard", and the species name honors John Wetherill, an explorer and amateur archeologist. Further specimens have since been found, including an infant. Fossil footprints have also been attributed to the animal, including resting traces.', '[]', 'https://cdn.jacobmaynard.dev/creatures/dilophosaurus.webp', 0.7782);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('2eaa4cbac5a71f5adb46c', 'Diplodocus', 'Diplodocus longus', 'Jurassic', 'Late Jurassic', 'Herbivorous', 26.0, 15000.0, 'epic', 'Diplodocus (, , or ) is an extinct genus of diplodocid sauropod dinosaurs known from the Late Jurassic of North America. The first fossils of Diplodocus were discovered in 1877 by S. W. Williston. The generic name, coined by Othniel Charles Marsh in 1878, is a Neo-Latin term derived from Greek διπλός (diplos) "double" and δοκός (dokos) "beam", in reference to the double-beamed chevron bones located in the underside of the tail, which were then considered unique.
The genus lived in what is now mid-western North America, at the end of the Jurassic period. It is one of the more common dinosaur fossils found in the middle to upper Morrison Formation, with most specimens being found in rocks dated between about 151.88 and 149.1 million years ago, during the latest Kimmeridgian Age, although it may have made it into the Tithonian, with at least one specimen (AMNH FR 223) being potentially from among the youngest deposits of the formation.', '[]', 'https://cdn.jacobmaynard.dev/creatures/diplodocus-longus.webp', 2.214);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('ef14859df8ea4f922cc6f', 'Dromaeosaurus', 'Dromaeosaurus albertensis', 'Cretaceous', 'Late Cretaceous', 'Carnivorous', 1.8, 15.0, 'common', 'Dromaeosaurus is a genus of dromaeosaurid theropod dinosaur that lived during the Late Cretaceous period (middle to late Campanian and Maastrichtian), sometime between 80 and 69 million years ago, in the Canadian province of Alberta and the western United States. The type species is Dromaeosaurus albertensis, which was described by William Diller Matthew and Barnum Brown in 1922. Its fossils were unearthed in the Hell Creek Formation, Horseshoe Canyon Formation and Dinosaur Park Formation. Teeth attributed to this genus have been found in the Prince Creek Formation. Dromaeosaurus is the type genus of both Dromaeosauridae and Dromaeosaurinae, which include many genera with similar characteristics to Dromaeosaurus such as possibly its closest relative Dakotaraptor. Dromaeosaurus was heavily built, more so than other dromaeosaurids that are similar in size, like Velociraptor.', '[]', 'https://cdn.jacobmaynard.dev/creatures/dromaeosaurus-albertensis.webp', 1.9231);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('e0df9f9179635bc37c1c9', 'Dromiceiomimus', 'Dromiceiomimus brevitertius', 'Cretaceous', 'Late Cretaceous', 'Omnivorous', 3.5, 100.0, 'common', 'Dromiceiomimus is a genus of ornithomimid theropod from the Late Cretaceous (early Maastrichtian) of Alberta, Canada. The type species, D. brevitertius, is considered a synonym of Ornithomimus edmontonicus by some authors, while others consider it a distinct and valid taxon. It was a small ornithomimid that weighed about 135 kilograms (298 lb).', '[]', 'https://cdn.jacobmaynard.dev/creatures/dromiceiomimus-brevitertius.webp', 1.222);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('521000328436dbeaf3a78', 'Dryosaurus', 'Dryosaurus altus', 'Jurassic', 'Late Jurassic', 'Herbivorous', 4.0, NULL, 'common', 'Dryosaurus meaning ''tree, oak'' and σαυρος (sauros) meaning ''lizard'' (the name reflects the forested habitat, not a vague oak-leaf shape of its cheek teeth as is sometimes assumed)) is a genus of ornithopod dinosaur that lived in the Late Jurassic period. It was an iguanodont (formerly classified as a hypsilophodont). Fossils have been found in the western United States and were first discovered in the late 19th century. Valdosaurus canaliculatus and Dysalotosaurus lettowvorbecki were both formerly considered to represent species of Dryosaurus.', '[]', 'https://cdn.jacobmaynard.dev/creatures/dryosaurus-altus.webp', 1.3333);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('60314c0e5b0d9fdd9389b', 'Dryptosaurus', 'Dryptosaurus aquilunguis', 'Cretaceous', 'Late Cretaceous', 'Carnivorous', 6.4, NULL, 'uncommon', 'Dryptosaurus is a genus of eutyrannosaurian theropod dinosaur that lived on the island continent of Appalachia approximately 67-66 million years ago during the end of the Maastrichtian age of the Late Cretaceous period. Dryptosaurus was a large, bipedal, ground-dwelling carnivore that could grow up to 7.5 metres (25 ft) long and weigh up to 756–1,500 kilograms (1,667–3,307 lb). 
Although it is now largely unknown outside of academic circles, the 1897 painting of the genus by Charles R. Knight made Dryptosaurus one of the more widely known dinosaurs of its time, despite its poor fossil record. First described by Edward Drinker Cope in 1866 and later renamed by Othniel Charles Marsh in 1877, Dryptosaurus is among the first theropod dinosaurs ever known to science.', '[]', 'https://cdn.jacobmaynard.dev/creatures/dryptosaurus-aquilunguis.webp', 1.9481);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('ee68ed342d11b6f8ab6e2', 'Dubreuillosaurus', 'Dubreuillosaurus valesdunensis', 'Jurassic', 'Late Jurassic', 'Carnivorous', NULL, NULL, 'common', 'Dubreuillosaurus is a genus of carnivorous megalosaurid theropod dinosaur from the middle Jurassic Period. Its fossils were found in France. The only named species, Dubreuillosaurus valesdunensis, was originally described as a species of Poekilopleuron, Poekilopleuron? valesdunensis, which is still formally the type species of the genus. It was later renamed Dubreuillosaurus valesdunensis when, in 2005, Allain came to the conclusion that it was not part of the genus Poekilopleuron. Its type specimen, MNHN 1998-13, is only rivalled in the number of preserved elements in this group by that of Eustreptospondylus. Dubreuillosaurus is considered to be a sister taxon of Magnosaurus. It did not show signs of insular dwarfism even though it was uncovered on an island.', '[]', 'https://cdn.jacobmaynard.dev/creatures/dubreuillosaurus-valesdunensis.webp', 2.2222);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('c50d810d87561a9075e38', 'Edmontonia', 'Edmontonia longiceps', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 4.0, NULL, 'common', 'Edmontonia is a genus of panoplosaurin nodosaurid dinosaur from the Late Cretaceous Period of what is now western North America. It is named after the Edmonton Formation (now the Horseshoe Canyon Formation in Canada), the unit of rocks where it was first found.', '[]', 'https://cdn.jacobmaynard.dev/creatures/edmontonia-longiceps.webp', 1.7595);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('cd550a9e51b47127978c8', 'Edmontosaurus', 'Edmontosaurus regalis', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 13.0, 3400.0, 'uncommon', 'Edmontosaurus regalis is a species of comb-crested hadrosaurid dinosaur. Fossils of E. regalis have been found in rocks of western North America that date from the late Campanian age of the Cretaceous Period 73 million years ago, but it may have possibly lived into the early Maastrichtian.
E. regalis was one of the largest hadrosaurids, measuring up to 12 metres (39 ft) long and weighing around 4.0 metric tons (4.4 short tons). It is classified as a genus of saurolophine (or hadrosaurine) hadrosaurid, a member of the group of hadrosaurids that lacked large, hollow crests, and instead had smaller, solid crests or fleshy combs. The distribution of E. regalis fossils suggests that it preferred coasts and coastal plains. It was a herbivore that could move on both two legs and four. Because it is known from several bone beds, E. regalis is thought to have lived in large groups.', '[]', 'https://cdn.jacobmaynard.dev/creatures/edmontosaurus-regalis.webp', 1.4354);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('c2df65e04d19663fdd541', 'Einiosaurus', 'Einiosaurus procurvicornis', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 6.0, NULL, 'uncommon', 'Einiosaurus is a genus of herbivorous centrosaurine ceratopsian dinosaur from the Upper Cretaceous (Campanian stage) of northwestern Montana. The name means ''bison lizard'', in a combination of Blackfeet Indian eini and Latinized Ancient Greek sauros; the specific name (procurvicornis) means ''with a forward-curving horn'' in Latin. Einiosaurus is medium-sized with an estimated body length at 4.5 metres (15 ft).', '[]', 'https://cdn.jacobmaynard.dev/creatures/einiosaurus-procurvicornis.webp', 1.4423);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('ec69722a9c619bc4928fa', 'Elaphrosaurus', 'Elaphrosaurus bambergi', 'Jurassic', 'Late Jurassic', 'Carnivorous', 6.2, NULL, 'uncommon', 'Elaphrosaurus is a genus of ceratosaurian theropod dinosaur that lived approximately 155 to 145 million years ago during the Late Jurassic Period in what is now Tanzania in Africa. Elaphrosaurus was a medium-sized but lightly built member of the group that could grow up to 6.2 m (20 ft) long. Morphologically, this dinosaur is significant in two ways. Firstly, it has a relatively long body but is very shallow-chested for a theropod of its size. Secondly, it has very short hindlimbs in comparison with its body. Phylogenetic analyses indicate that this genus is likely a ceratosaur. Earlier suggestions that it is a late surviving coelophysoid have been examined but generally dismissed. Elaphrosaurus is currently believed to be a very close relative of Limusaurus, an unusual beaked ceratosaurian which may have been either herbivorous or omnivorous.', '[]', 'https://cdn.jacobmaynard.dev/creatures/elaphrosaurus-bambergi.webp', 2.6549);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('b9524c0dea31732bae8c0', 'Emausaurus', 'Emausaurus ernsti', 'Jurassic', NULL, 'Herbivorous', 2.0, NULL, 'common', 'Emausaurus is a genus of thyreophoran or armored dinosaur from the Early Jurassic (Early Toarcian). Its fossils have been found in the Lehmhagen Member, in Mecklenburg-Vorpommern, northern Germany. Emausaurus is the only known Toarcian thyreophoran, as well as the only dinosaur from the zone of the same age with a formal name.', '[]', 'https://cdn.jacobmaynard.dev/creatures/emausaurus-ernsti.webp', 2.1583);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('e9d8ae03bfa4a87ca64df', 'Eolambia', 'Eolambia caroljonesa', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', NULL, NULL, 'common', 'Eolambia (meaning "dawn lambeosaurine") is a genus of herbivorous hadrosauroid dinosaur from the early Late Cretaceous of the United States. It contains a single species, E. caroljonesa, named by paleontologist James Kirkland in 1998. The type specimen of Eolambia was discovered by Carole and Ramal Jones in 1993; the species name honors Carole. Since then, hundreds of bones have been discovered from both adults and juveniles, representing nearly every element of the skeleton. All of the specimens have thus far been found in Emery County, Utah, in a layer of rock known as the Mussentuchit Member of the Cedar Mountain Formation.
Measuring up to 6 meters (20 ft) long, Eolambia is a large member of its group. While it closely approaches the Asian hadrosauroids Equijubus, Probactrosaurus, and Choyrodon, in traits of the skull, vertebrae, and limbs, it may actually be more closely related to the North American Protohadros.', '[]', 'https://cdn.jacobmaynard.dev/creatures/eolambia-caroljonesa.webp', 1.0067);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('3fa0c6e22a4237c1107d3', 'Eoraptor', 'Eoraptor lunensis', 'Triassic', 'Late Triassic', 'Carnivorous', 1.7, 10.0, 'common', 'Eoraptor () is a genus of small, lightly built, basal sauropodomorph dinosaur. One of the earliest-known dinosaurs and one of the earliest sauropodomorphs, it lived approximately 231 to 228 million years ago, during the Late Triassic in Western Gondwana, in the region that is now northwestern Argentina. The type and only species, Eoraptor lunensis, was first described in 1993, and is known from an almost complete and well-preserved skeleton and several fragmentary ones. Eoraptor had multiple tooth shapes, which suggests that it was omnivorous.', '[]', 'https://cdn.jacobmaynard.dev/creatures/eoraptor-lunensis.webp', 1.4286);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('ac81303fe2b9197e69d71', 'Eotyrannus', 'Eotyrannus lengi', 'Cretaceous', 'Early Cretaceous', 'Carnivorous', 5.0, NULL, 'common', 'Eotyrannus (meaning "dawn tyrant") is a genus of tyrannosauroid theropod dinosaur hailing from the Early Cretaceous Wessex Formation beds, included in Wealden Group, located in the southwest coast of the Isle of Wight, United Kingdom. The remains (MIWG1997.550), consisting of assorted skull, axial skeleton and appendicular skeleton elements, from a juvenile or subadult, found in a plant debris clay bed, were described by Stephen Hutt and colleagues in early 2001. The etymology of the generic name refers to the animal''s classification as an early tyrannosaur or "tyrant lizard", while the specific name honors the discoverer of the fossil.', '[]', 'https://cdn.jacobmaynard.dev/creatures/eotyrannus-lengi.webp', 1.5038);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('c2f7b504b97b9d5374fd3', 'Equijubus', 'Equijubus normani', 'Cretaceous', 'Early Cretaceous', 'Herbivorous', NULL, NULL, 'common', 'Equijubus (Chinese: 马鬃龙; pinyin: Mǎzōng lóng; Mǎzōng meaning "horse mane" after the area Mǎzōng Mountain 马鬃山 in which it was found), is a genus of herbivorous hadrosauroid dinosaur from the Early Cretaceous (Albian stage) of northwestern China.', '[]', 'https://cdn.jacobmaynard.dev/creatures/equijubus-normani.webp', 2.5974);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('3c28fb09a7ba1b55b5f75', 'Erketu', 'Erketu ellisoni', 'Cretaceous', 'Early Cretaceous', 'Herbivorous', 15.0, NULL, 'uncommon', 'Erketu (meaning "Erketü tengri") is a genus of somphospondylan dinosaur that lived in Asia during the Late Cretaceous, roughly between 96 million and 89 million years ago. It is known from the Bayanshiree Formation of Mongolia, and its fossils were found between 2002 and 2003 during field expeditions. Erketu was first described in 2006 and later on in 2010 due to some cervicals that were left behind in the expedition. This genus represents the first sauropod described from the Bayanshiree Formation. The elongated cervical vertebrae indicate that it probably had the longest neck relative to its body size of any sauropod.', '[]', 'https://cdn.jacobmaynard.dev/creatures/erketu-ellisoni.webp', 1.8127);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('db17e0dfb57a2adf9c63a', 'Erlikosaurus', 'Erlikosaurus andrewsi', 'Cretaceous', 'Late Cretaceous', 'Omnivorous', 3.4, NULL, 'common', 'Erlikosaurus (meaning "Erlik''s lizard") is a genus of therizinosaurid that lived in Asia during the Late Cretaceous period. The fossils, a skull and some post-cranial fragments, were found in the Bayan Shireh Formation of Mongolia in 1972, dating to around 96 and 89 million years ago. These remains were later described by Altangerel Perle and Rinchen Barsbold in 1980, naming the new genus and species Erlikosaurus andrewsi. It represents the second therizinosaur taxon from this formation (after Segnosaurus), with the most complete skull among members of this peculiar family of dinosaurs.
In contrast to most therizinosaurids, Erlikosaurus was a small member reaching nearly 3.4 m (11 ft) in length and 150 to 250 kg (330 to 550 lb) in mass. It had a well-developed beak at the snout tip and toothed jaws that were used for its herbivorous diet. The feet ended in four toes with the first one articulated to the ankle—in contrast to the vestigial first toe of most theropods.', '[]', 'https://cdn.jacobmaynard.dev/creatures/erlikosaurus-andrewsi.webp', 1.2);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('38a89eff13aaa2cc3441a', 'Euhelopus', 'Euhelopus zdanskyi', 'Jurassic', 'Late Jurassic', 'Herbivorous', 10.0, NULL, 'uncommon', 'Euhelopus is a genus of sauropod dinosaur that lived between 143 and 133 million years ago during the Berriasian and Valanginian ages of the Early Cretaceous in what is now Shandong Province in China. It was a large quadrupedal herbivore. Like sauropods such as brachiosaurids and titanosaurs, Euhelopus had longer forelimbs than hindlimbs. This discovery was paleontologically significant because it represented the first dinosaur scientifically investigated from China: seen in 1913, rediscovered in 1922, excavated in 1923, and studied by T''an during the same year. Unlike most sauropod specimens, it has a relatively complete skull. Euhelopus was a long-necked sauropod similar to Mamenchisaurus, but its affinities are controversial. Most studies favor a close relationship between Euhelopus and titanosaurs, rather than mamenchisaurids.', '[]', 'https://cdn.jacobmaynard.dev/creatures/euhelopus-zdanskyi.webp', 1.7544);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('40a9232c8eba9d209008d', 'Euoplocephalus', 'Euoplocephalus', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 7.0, 2000.0, 'uncommon', 'Euoplocephalus is a genus of large herbivorous ankylosaurid dinosaurs, living during the Late Cretaceous of Canada. It has only one named species, Euoplocephalus tutus.
The first fossil of Euoplocephalus was found in 1897 in Alberta. In 1902, it was named Stereocephalus, but that name had already been given to an insect, so it was changed in 1910. Later, many more ankylosaurid remains were found from the Campanian of North America and often made separate genera. In 1971, Walter Coombs concluded that they all belonged to Euoplocephalus, which then make it one of the best-known dinosaurs. Recently, however, experts have come to the opposite conclusion, limiting the authentic finds of Euoplocephalus to about a dozen specimens. These include a number of almost complete skeletons, so nevertheless much is known about the build of the animal.
Euoplocephalus reached 5.3 metres (17 ft) in length and 2 metric tons (2.2 short tons) in body mass.', '[]', 'https://cdn.jacobmaynard.dev/creatures/euoplocephalus.webp', 1.3605);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('33f3fc8ac63b3b607dbd2', 'Europasaurus', 'Europasaurus holgeri', 'Jurassic', 'Late Jurassic', 'Herbivorous', 6.2, NULL, 'uncommon', 'Europasaurus (meaning ''Europe lizard'') is a basal macronarian sauropod, a form of quadrupedal herbivorous dinosaur. It lived during the Late Jurassic (middle Kimmeridgian, from about 154 to 151 million years ago) of northern Germany, and has been identified as an example of insular dwarfism resulting from the isolation of a sauropod population on an island within the Lower Saxony basin.', '[]', 'https://cdn.jacobmaynard.dev/creatures/europasaurus-holgeri.webp', 1.5707);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('cd14f13e18b5c6fd23a49', 'Eustreptospondylus', 'Eustreptospondylus oxoniensis', 'Jurassic', NULL, 'Carnivorous', 7.0, NULL, 'uncommon', 'Eustreptospondylus, from (Ancient Greek εὖ (eû), meaning "well", στρεπτός (streptós), meaning "twisted", and σπόνδυλος (spóndulos), meaning "vertebra"), is an extinct genus of megalosaurid theropod dinosaur, from the Callovian and Oxfordian stages of the Jurassic period (some time between 166 and 154 million years ago) in southern England, at a time when Europe was a series of scattered islands (due to tectonic movement at the time which raised the sea-bed and flooded the lowland).', '[]', 'https://cdn.jacobmaynard.dev/creatures/eustreptospondylus-oxoniensis.webp', 1.7751);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('c2734561e7c2191165dac', 'Fukuiraptor', 'Fukuiraptor kitadaniensis', 'Cretaceous', 'Early Cretaceous', 'Carnivorous', 4.2, NULL, 'common', 'Fukuiraptor ("thief of Fukui") is a genus of medium-sized megaraptoran theropod dinosaur of the Early Cretaceous epoch (either Barremian or Aptian) that lived in what is now Japan. Fukuiraptor is known from the Kitadani Formation and possibly also the Sebayashi Formation. Fukuiraptor may have been one of the basalmost members of Megaraptora, or a sister taxon to Australovenator.', '[]', 'https://cdn.jacobmaynard.dev/creatures/fukuiraptor-kitadaniensis.webp', 1.3333);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('40a36f7e7020ff6a8ed74', 'Fukuisaurus', 'Fukuisaurus tetoriensius', 'Cretaceous', 'Early Cretaceous', 'Herbivorous', 4.7, NULL, 'common', 'Fukuisaurus (meaning "Fukui (Fortunate) lizard") is a genus of herbivorous ornithopod dinosaur that lived during the Early Cretaceous in what is now Japan. The type species is F. tetoriensis, which was named and described in 2003.', '[]', 'https://cdn.jacobmaynard.dev/creatures/fukuisaurus-tetoriensius.webp', 1.0);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('20cf216b60edfb3664191', 'Gallimimus', 'Gallimimus bullatus', 'Cretaceous', 'Late Cretaceous', 'Omnivorous', 6.0, 490.0, 'rare', 'Gallimimus is a genus of theropod dinosaur that lived in what is now Mongolia during the Late Cretaceous period. Several fossils in various stages of growth were discovered by Polish-Mongolian expeditions in the Gobi Desert of Mongolia during the 1960s; a large skeleton discovered in this region was made the holotype specimen of the new genus and species Gallimimus bullatus in 1972. The generic name means "chicken mimic", referring to the similarities between its neck vertebrae and those of the Galliformes. The specific name is derived from bulla, a golden capsule worn by Roman youth, in reference to a bulbous structure at the base of the skull of Gallimimus.', '[]', 'https://cdn.jacobmaynard.dev/creatures/gallimimus-bullatus.webp', 1.5075);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('d4428d3fbb8787664dfb6', 'Gargoyleosaurus', 'Gargoyleosaurus parkpinorum', 'Jurassic', 'Late Jurassic', 'Herbivorous', 4.0, NULL, 'common', 'Gargoyleosaurus (meaning "gargoyle lizard") is one of the earliest ankylosaurs known from reasonably complete fossil remains. The holotype was discovered in 1995 at the Bone Cabin Quarry West locality, in Albany County, Wyoming in exposures of the Upper Jurassic (Kimmeridgian to Tithonian stages) Morrison Formation.
The type species, G. parkpinorum (originally G. parkpini) was described by Ken Carpenter et al. in 1998. A mounted skeletal reconstruction of Gargoyleosaurus parkpinorum can be seen at the Denver Museum of Nature and Science and, alongside a couple skeletons of baby Stegosaurus, has been on display there since around 2002. Gargoyleosaurus was present in stratigraphic zone 2 of the Morrison Formation.', '[]', 'https://cdn.jacobmaynard.dev/creatures/gargoyleosaurus-parkpinorum.webp', 0.9231);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('31b7f8e166d948debeac1', 'Garudimimus', 'Garudimimus brevipes', 'Cretaceous', 'Late Cretaceous', 'Omnivorous', 4.7, NULL, 'common', 'Garudimimus (meaning "Garuda mimic") is a genus of ornithomimosaur that lived in Asia during the Late Cretaceous. The genus is known from a single specimen found in 1981 by a Soviet-Mongolian paleontological expedition in the Bayanshiree Formation and formally described in the same year by Rinchen Barsbold; the only species is Garudimimus brevipes. Several interpretations about the anatomical traits of Garudimimus were made in posterior examinations of the specimen, but most of them were criticized during its comprehensive redescription in 2005. Extensive undescribed ornithomimosaur remains at the type locality of Garudimimus may represent additional specimens of the genus.
The only known specimen of Garudimimus was a medium-sized animal measuring nearly 3.5 m (11.5 ft) in length and weighing about 77.3–98 kg (170–216 lb).', '[]', 'https://cdn.jacobmaynard.dev/creatures/garudimimus-brevipes.webp', 1.7751);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('3f32e021c16459430cb6b', 'Gasosaurus', 'Gasosaurus constructus', 'Jurassic', NULL, 'Carnivorous', 4.0, NULL, 'common', 'Gasosaurus () is a genus of tetanuran theropod that lived approximately 171.6 to 161.2 million years ago during the middle of the Jurassic Period. The name "Gasosaurus" is derived from the English "gasoline" and the Greek σαῦρος (sauros). Only one species is currently recognised, G. constructus, from which the specific name honours the gasoline company that found the Dashanpu fossil quarry in Sichuan Province, China, now named as the Lower Shaximiao Formation.', '[]', 'https://cdn.jacobmaynard.dev/creatures/gasosaurus-constructus.webp', 1.5748);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('1eff9864c0039486abc37', 'Gasparinisaura', 'Gasparinisaura cincosaltensis', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 0.8, NULL, 'common', 'Gasparinisaura (meaning "Gasparini''s lizard") is a genus of herbivorous ornithopod dinosaur from the Late Cretaceous. The first fossils of Gasparinisaura were found in 1992 near Cinco Saltos in Río Negro Province, Argentina. The type species, Gasparinisaura cincosaltensis, was named and described in 1996 by Rodolfo Coria and Leonardo Salgado. The generic name honors Argentine palaeontologist Zulma Brandoni de Gasparini. The specific name refers to Cinco Saltos.', '[]', 'https://cdn.jacobmaynard.dev/creatures/gasparinisaura-cincosaltensis.webp', 1.3667);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('0ec4cc3587d772b120467', 'Gastonia', 'Gastonia burgei', 'Cretaceous', 'Early Cretaceous', 'Herbivorous', 4.6, NULL, 'common', 'Gastonia is a genus of herbivorous ankylosaurian dinosaur from the Early Cretaceous of North America, around 139 to 125.77 million years ago. It is often considered a nodosaurid closely related to Polacanthus. Gastonia has a sacral shield and large shoulder spikes.', '[]', 'https://cdn.jacobmaynard.dev/creatures/gastonia-burgei.webp', 1.4019);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('eab44f2797e7a99fb16af', 'Giganotosaurus', 'Giganotosaurus carolinii', 'Cretaceous', 'Early Cretaceous', 'Carnivorous', 13.0, 13800.0, 'epic', 'Giganotosaurus is a genus of large theropod dinosaur that lived in what is now Argentina, during the early Cenomanian age of the Late Cretaceous period, approximately 99.6 to 95 million years ago. The holotype specimen was discovered in the Candeleros Formation of Patagonia in 1993 and is almost 70% complete. The animal was named Giganotosaurus carolinii in 1995; the genus name translates to "giant southern lizard", and the specific name honors the discoverer, Ruben Carolini. A dentary bone, a tooth, and some tracks, discovered before the holotype, were later assigned to this animal. The genus attracted much interest and became part of a scientific debate about the maximum sizes of theropod dinosaurs.
Giganotosaurus was one of the largest known terrestrial carnivores, but the exact size has been hard to determine due to the incompleteness of the remains found so far.', '[]', 'https://cdn.jacobmaynard.dev/creatures/giganotosaurus-carolinii.webp', 1.3333);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('8cdae3fe6add690fc3f9b', 'Gilmoreosaurus', 'Gilmoreosaurus mongoliensis', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 6.0, NULL, 'uncommon', 'Gilmoreosaurus (meaning "Charles Whitney Gilmore''s lizard") is a genus of hadrosauromorphan dinosaur from the Late Cretaceous of Asia. The type species is Gilmoreosaurus mongoliensis, known from the Iren Dabasu Formation of Inner Mongolia, dating to 96 million years ago. Additional specimens have been described as distinct species, including G. atavus from the Khodzhakul Formation of Uzbekistan, and G. arkhangelskyi from the Bissekty Formation, also of Uzbekistan. However, these are based on very fragmentary remains, and their classification is dubious. An additional species, G. kysylkumense, also from the Bissekty Formation, is sometimes included, though it has also been referred to the related genus Bactrosaurus.', '[]', 'https://cdn.jacobmaynard.dev/creatures/gilmoreosaurus-mongoliensis.webp', 1.5038);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('fdb4ebaf621d4bebc3dd0', 'Giraffatitan', 'Giraffatitan brancai', 'Jurassic', 'Late Jurassic', 'Herbivorous', 23.0, NULL, 'rare', 'Giraffatitan (name meaning "titanic giraffe") is a genus of sauropod dinosaur that lived during the late Jurassic Period (Kimmeridgian–Tithonian stages) in what is now Lindi Region, Tanzania. Only one species is known, G. brancai, named in honor of German paleontologist Wilhelm von Branca, who was a driving force behind the expedition that discovered it in the Tendaguru Formation. Giraffatitan brancai was originally described by German paleontologist Werner Janensch as a species of the North American sauropod Brachiosaurus from the Morrison Formation, as Brachiosaurus brancai. Recent research shows that the differences between the type species of Brachiosaurus and the Tendaguru material are so large that the African material should be placed in a separate genus. 
Giraffatitan was for many decades known as the largest dinosaur but recent discoveries of several larger dinosaurs prove otherwise; giant titanosaurians appear to have surpassed Giraffatitan in terms of sheer mass.', '[]', 'https://cdn.jacobmaynard.dev/creatures/giraffatitan-brancai.webp', 2.1978);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('b292efe1f7078436a31fc', 'Gobisaurus', 'Gobisaurus domoculus', 'Cretaceous', 'Early Cretaceous', 'Herbivorous', 5.0, NULL, 'common', 'Gobisaurus is an extinct genus of herbivorous basal ankylosaurid ankylosaur from the Lower Cretaceous of China (Nei Mongol Zizhiqu). The genus is monotypic, containing only the species Gobisaurus domoculus.', '[]', 'https://cdn.jacobmaynard.dev/creatures/gobisaurus-domoculus.webp', 2.6549);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('42cce0988f8dea7cf7766', 'Gorgosaurus', 'Gorgosaurus libratus', 'Cretaceous', 'Late Cretaceous', 'Carnivorous', 8.6, NULL, 'uncommon', 'Gorgosaurus is a genus of tyrannosaurid theropod dinosaur that lived in western North America during the Late Cretaceous Period (Campanian), between about 76.5 and 75 million years ago. Fossil remains have been found in the Canadian province of Alberta and the U.S. state of Montana. Paleontologists recognize only the type species, G. libratus, although other species have been erroneously referred to the genus.
Like most known tyrannosaurids, Gorgosaurus was a large bipedal predator, measuring 8–9 metres (26–30 ft) in length and 2–3 metric tons (2.2–3.3 short tons) in body mass. Dozens of large, sharp teeth lined its jaws, while its two-fingered forelimbs were comparatively small. Gorgosaurus was most closely related to Albertosaurus, and more distantly related to the larger Tyrannosaurus. Gorgosaurus and Albertosaurus are extremely similar, distinguished mainly by subtle differences in the teeth and skull bones. Some experts consider G.', '[]', 'https://cdn.jacobmaynard.dev/creatures/gorgosaurus-libratus.webp', 2.2901);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('e15a8783a0624ddfbc26b', 'Goyocephale', 'Goyocephale lattimorei', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 2.0, NULL, 'common', 'Goyocephale is an extinct genus of pachycephalosaurian ornithischian that lived in Mongolia during the Late Cretaceous about 76 million years ago. It was first described in 1982 by Altangerel Perle, Teresa Maryańska and Halszka Osmólska for a disarticulated skeleton with most of a skull, part of the forelimb and hindlimb, some of the pelvic girdle, and some vertebrae. Perle et al. named the remains Goyocephale lattimorei, from the Mongolian гоё (goyo), meaning "decorated", and the Ancient Greek κεφαλή (kephale), for head. The species name honours Owen Lattimore.', '[]', 'https://cdn.jacobmaynard.dev/creatures/goyocephale-lattimorei.webp', 1.4218);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('0d4e9b9bcc57d566170dc', 'Graciliceratops', 'Graciliceratops mongoliensis', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', NULL, NULL, 'common', 'Graciliceratops (meaning "slender horned face") is a genus of neoceratopsian dinosaurs that lived in Asia during the Late Cretaceous period.', '[]', 'https://cdn.jacobmaynard.dev/creatures/graciliceratops-mongoliensis.webp', 1.5957);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('6f2970322b1da138a430a', 'Gryposaurus', 'Gryposaurus notabilis', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 10.0, NULL, 'uncommon', 'Gryposaurus (meaning "hooked-nosed (Greek grypos) lizard"; sometimes incorrectly translated as "griffin (Latin gryphus) lizard") was a genus of duckbilled dinosaur that lived about 80 to 75 million years ago, in the Late Cretaceous (late Santonian to late Campanian stages) of North America. Named species of Gryposaurus are known from the Dinosaur Park Formation in Alberta, Canada, and two formations in the United States: the Lower Two Medicine Formation in Montana and the Kaiparowits Formation of Utah. A possible additional species from the Javelina Formation in Texas may extend the temporal range of the genus to 66 million years ago.
Gryposaurus is similar to Kritosaurus, and for many years the two were thought to be synonyms. It is known from numerous skulls, some skeletons, and even some skin impressions that show it to have had pyramidal scales projecting along the midline of the back.', '[]', 'https://cdn.jacobmaynard.dev/creatures/gryposaurus-notabilis.webp', 2.0837);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('d3a755d814c227df11f79', 'Guaibasaurus', 'Guaibasaurus candelariensis', 'Triassic', 'Late Triassic', 'Herbivorous', 1.8, NULL, 'common', 'Guaibasaurus is an extinct genus of basal saurischian dinosaur known from the Late Triassic Caturrita Formation of Rio Grande do Sul, southern Brazil. Most analyses recover it as a sauropodomorph, although there are some suggestions that it was a theropod instead. In 2016 Gregory S. Paul estimated it at around 2 meters long (6.6 ft) and 10 kg (22 lbs), whereas in 2020 Molina-Pérez and Larramendi listed it at 3 meters (10 ft) and 35 kg (77 lbs).', '[]', 'https://cdn.jacobmaynard.dev/creatures/guaibasaurus-candelariensis.webp', 1.7751);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('5c19757a840f0c403b6ab', 'Guanlong', 'Guanlong wucaii', 'Jurassic', 'Late Jurassic', 'Carnivorous', 3.0, NULL, 'common', 'Guanlong is an extinct genus of proceratosaurid tyrannosauroid dinosaur from the Late Jurassic (Oxfordian) Shishugou Formation of China. It was first described in 2006 by Xu Xing and colleagues, who found it to represent a new taxon related to Tyrannosaurus. Two individuals are currently known, consisting of a partially complete adult and a nearly complete juvenile.', '[]', 'https://cdn.jacobmaynard.dev/creatures/guanlong-wucaii.webp', 1.9169);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('b659b5ae71054da4bc249', 'Hadrosaurus', 'Hadrosaurus foulkii', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 9.0, NULL, 'uncommon', 'Hadrosaurus is a genus of hadrosaurid ornithopod dinosaurs that lived in North America during the Late Cretaceous Period in what is now the Woodbury Formation in New Jersey about 83.6 to 77.9 million years ago. The holotype specimen was found in fluvial marine sedimentation, meaning that the corpse of the animal was transported by a river and washed out to sea. Some fossils are found in the Tar Heel/Coachman Formation.
They were large animals ranging from 7 to 8 m (23 to 26 ft) in length and 2 to 4 t (2.2 to 4.4 short tons) in weight. Most of the preserved elements are very robust, unusual traits in hadrosaurs. Hadrosaurus were ponderously built animals equipped with keratinous beaks for cropping foliage and a specialized and complex dentition for food processing. Hadrosaurus foulkii, the only species in this genus, is known from a single specimen consisting of much of the skeleton and parts of the skull.', '[]', 'https://cdn.jacobmaynard.dev/creatures/hadrosaurus-foulkii.webp', 2.4291);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('eba12040045edb705aefe', 'Hagryphus', 'Hagryphus giganteus', 'Unknown', NULL, 'Omnivorous', 3.0, NULL, 'common', 'Hagryphus (meaning "Ha''s griffin") is a monospecific genus of caenagnathid dinosaur from southern Utah that lived during the Late Cretaceous (upper Campanian stage, 75.95 Ma) in what is now the Kaiparowits Formation of the Grand Staircase–Escalante National Monument. The type and only species, Hagryphus giganteus, is known only from an incomplete but articulated left manus and the distal portion of the left radius. It was named in 2005 by Lindsay E. Zanno and Scott D. Sampson. Hagryphus has an estimated length of 2.4–3 metres (8–10 feet) and weight of 50 kilograms (110 lbs).', '[]', 'https://cdn.jacobmaynard.dev/creatures/hagryphus-giganteus.webp', 0.5012);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('52c42293f47630f468e27', 'Haplocanthosaurus', 'Haplocanthosaurus priscus', 'Jurassic', 'Late Jurassic', 'Herbivorous', 21.5, NULL, 'rare', 'Haplocanthosaurus (meaning "simple spined lizard") is a genus of diplodocoid sauropod dinosaur. Two species, H. delfsi and H. priscus, are known from incomplete fossil skeletons. They lived during the Late Jurassic (Kimmeridgian stage), 155 to 152 million years ago in North America. The type species is H. priscus, named in 1903 John Bell Hatcher , and the referred species H. delfsi was discovered by a young college student named Edwin Delfs in Colorado, United States and described by Jack McIntosh and Michael Williams in 1988. Haplocanthosaurus specimens have been found in the lowermost layer of the Morrison Formation, along with Hesperosaurus mjosi, Brontosaurus yahnahpin, and Allosaurus jimmadseni.', '[]', 'https://cdn.jacobmaynard.dev/creatures/haplocanthosaurus-priscus.webp', 0.9934);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('a58939b1307c8f4811ae1', 'Harpymimus', 'Harpymimus okladnikovi', 'Cretaceous', 'Early Cretaceous', 'Omnivorous', 2.0, NULL, 'common', 'Harpymimus is a genus of basal ornithomimosaurian theropod dinosaur from the Early Cretaceous Period of what is now Mongolia. Unlike later, more derived ornithomimosaurs, Harpymimus still possessed teeth, although they appear to have been restricted to the dentary of the lower jaw.', '[]', 'https://cdn.jacobmaynard.dev/creatures/harpymimus-okladnikovi.webp', 0.6925);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('1ad5c66381f1e8d07f920', 'Herrerasaurus', 'Herrerasaurus ischigualastensis', 'Triassic', 'Late Triassic', 'Carnivorous', 3.0, NULL, 'common', 'Herrerasaurus is likely a genus of saurischian dinosaur from the Late Triassic period. Measuring 6 m (20 ft) long and weighing around 350 kg (770 lb), this genus was one of the earliest dinosaurs from the fossil record. Its name means "Herrera''s lizard", after the rancher who discovered the first specimen in 1958 in South America. All known fossils of this carnivore have been discovered in the Ischigualasto Formation of Carnian age (late Triassic according to the ICS, dated to 231.4 million years ago) in northwestern Argentina. The type species, Herrerasaurus ischigualastensis, was described by Osvaldo Reig in 1963 and is the only species assigned to the genus. Ischisaurus and Frenguellisaurus are synonyms.
For many years, the classification of Herrerasaurus was unclear because it was known from very fragmentary remains. It was hypothesized to be a basal theropod, a basal sauropodomorph, a basal saurischian, or not a dinosaur at all but another type of archosaur.', '[]', 'https://cdn.jacobmaynard.dev/creatures/herrerasaurus-ischigualastensis.webp', 1.7544);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('b183211d49a28ce4d5848', 'Hesperosaurus', 'Hesperosaurus mjosi', 'Jurassic', 'Late Jurassic', 'Herbivorous', 6.0, NULL, 'uncommon', 'Hesperosaurus (from Ancient Greek ἕσπερος (hésperos), meaning "western", and σαῦρος (saûros), meaning "lizard") is a herbivorous stegosaurian dinosaur from the Kimmeridgian age of the Jurassic period, approximately 156 million years ago.
Fossils of Hesperosaurus have been found in the state of Wyoming and Montana in the United States of America since 1985. The type species Hesperosaurus mjosi was named in 2001. It is from an older part of the Morrison Formation, and so a little older than other Morrison stegosaurs. Several relatively complete skeletons of Hesperosaurus are known. One specimen preserves the first known impression of the horn sheath of a stegosaurian back plate.
Hesperosaurus was a member of the Stegosauridae, quadrupedal plant-eaters protected by vertical bony plates and spikes. It was closely related to Stegosaurus and was similar to it in having two rows of, possibly alternating, plates on its back and four spikes on its tail end.', '[]', 'https://cdn.jacobmaynard.dev/creatures/hesperosaurus-mjosi.webp', 1.5504);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('81f4059f5900d0057f01b', 'Heterodontosaurus', 'Heterodontosaurus tucki', 'Jurassic', 'Early Jurassic', 'Herbivorous', 1.2, NULL, 'common', 'Heterodontosaurus is a genus of heterodontosaurid dinosaur that lived during the Early Jurassic, 200–190 million years ago. Its only known member species, Heterodontosaurus tucki, was named in 1962 based on a skull discovered in South Africa. The genus name means "different toothed lizard", in reference to its unusual, heterodont dentition; the specific name honours G. C. Tuck, who supported the discoverers. Further specimens have since been found, including an almost complete skeleton in 1966.
Though it was a small dinosaur, Heterodontosaurus was one of the largest members of its family, reaching between 1.18 m (3 ft 10 in) and possibly 1.75 m (5 ft 9 in) in length, and weighing between 2 and 10 kg (4.4 and 22.0 lb). The skull was elongated, narrow, and triangular when viewed from the side. The front of the jaws were covered in a horny beak. It had three types of teeth; in the upper jaw, small, incisor-like teeth were followed by long, canine-like tusks.', '[]', 'https://cdn.jacobmaynard.dev/creatures/heterodontosaurus-tucki.webp', 2.8037);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('9d147bb2a1fd4404a5d83', 'Heyuannia', 'Heyuannia yanshini', 'Cretaceous', 'Late Cretaceous', 'Omnivorous', 2.0, NULL, 'common', 'Heyuannia ("from Heyuan") is a genus of oviraptorid dinosaur that lived in Asia during the Late Cretaceous epoch, in what is now China and Mongolia. It was the first oviraptorid found in China; most others were found in neighbouring Mongolia. Two species are known: H. huangi, named by Lü Junchang in 2002 from the Dalangshan Formation; and H. yanshini, originally named as a separate genus Ingenia from the Barun Goyot Formation by Rinchen Barsbold in 1981, and later renamed to Ajancingenia in 2013 due to the preoccupation of Ingenia. The latter name was eventually discarded due to various ethical issues surrounding the author.', '[]', 'https://cdn.jacobmaynard.dev/creatures/heyuannia-yanshini.webp', 1.8293);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('825664e833d2ccd8dcf2f', 'Homalocephale', 'Homalocephale calathocercos', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 1.5, NULL, 'common', 'Homalocephale (from Greek ὁμαλός, homalos, "even", and κεφαλή, kephalē, "head") is a genus of pachycephalosaurid dinosaur that lived during the Late Cretaceous period of what is now the Nemegt Formation, Mongolia. The genus was described in 1974 by Halszka Osmólska and Teresa Maryańska, and consists of a single species, H. calathocercos. Though Homalocephale has been regarded as a synonym (and juvenile form) of Prenocephale, juvenile specimens of the latter indicate that they were distinct. Homalocephale was 1.8 m (5.9 ft) long and possibly an omnivore.', '[]', 'https://cdn.jacobmaynard.dev/creatures/homalocephale-calathocercos.webp', 2.5532);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('03a67ff9f9d134b253ade', 'Huayangosaurus', 'Huayangosaurus taibaii', 'Jurassic', NULL, 'Herbivorous', 4.5, NULL, 'common', 'Huayangosaurus is a genus of stegosaurian dinosaur from the Middle Jurassic of China. The name derives from "Huayang" (華陽), an alternate name for Sichuan (the province where it was discovered), and "saurus", meaning "lizard". It lived during the Bathonian to Callovian stages, around 165 million years ago, some 20 million years before its famous relative, Stegosaurus appeared in North America. At only approximately 4 metres (13 ft) long, it was also much smaller than its famous cousin. Found in the Lower Shaximiao Formation, Huayangosaurus shared the local Middle Jurassic landscape with the sauropods Shunosaurus, Datousaurus, Omeisaurus and Protognathosaurus, the ornithopod Xiaosaurus and the carnivorous Gasosaurus.', '[]', 'https://cdn.jacobmaynard.dev/creatures/huayangosaurus-taibaii.webp', 2.2814);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('dbf772917391d9acd165c', 'Hylaeosaurus', 'Hylaeosaurus armatus', 'Cretaceous', 'Early Cretaceous', 'Herbivorous', 5.0, NULL, 'common', 'Hylaeosaurus is a herbivorous ankylosaurian dinosaur that lived about 136 million years ago, in the late Valanginian stage of the early Cretaceous period of England. It was found in the Grinstead Clay.
Hylaeosaurus was one of the first dinosaurs to be discovered, in 1832 by Gideon Mantell. In 1842 it was one of the three dinosaurs Richard Owen based the Dinosauria on, the others being Iguanodon and Megalosaurus. Four species were named in the genus, but only the type species Hylaeosaurus armatus is today considered valid. Only limited remains have been found of Hylaeosaurus and much of its anatomy is unknown. It might have been a basal nodosaurid, although a recent cladistic analysis recovers it as a basal ankylosaurid.
Hylaeosaurus was about five metres long. It was an armoured dinosaur that carried at least three long spines on its shoulder.', '[]', 'https://cdn.jacobmaynard.dev/creatures/hylaeosaurus-armatus.webp', 3.681);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('49cdd6275fd5f00f6275b', 'Hypacrosaurus', 'Hypacrosaurus altispinus', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 9.0, NULL, 'uncommon', 'Hypacrosaurus (meaning "near the highest lizard" [from Ancient Greek ὑπο- hypo- "less" and ἄκρος akros "high"], because it was almost but not quite as large as Tyrannosaurus) is an extinct genus of duckbill dinosaur similar in appearance to Corythosaurus. Like Corythosaurus, it had a tall, hollow rounded crest, although not as large and straight. It is known from the remains of two species that spanned 75.0 to 69.5 million years ago, in the Late Cretaceous of Alberta, Canada, and Montana, United States, and is the latest hollow-crested duckbill known from good remains in North America. It was an obscure genus until the discovery in the 1990s of nests, eggs, and hatchlings belonging to H. stebingeri.', '[]', 'https://cdn.jacobmaynard.dev/creatures/hypacrosaurus-altispinus.webp', 1.1009);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('5decafa1fbf456197e1e2', 'Hypsilophodon', 'Hypsilophodon foxii', 'Cretaceous', 'Early Cretaceous', 'Herbivorous', 2.0, 20.0, 'common', 'Hypsilophodon (; meaning "high-crested tooth") is a neornithischian dinosaur genus from the Early Cretaceous period of England. It has traditionally been considered an early member of the group Ornithopoda, but recent research has put this into question.
The first remains of Hypsilophodon were found in 1849; the type species, Hypsilophodon foxii, was named in 1869. Abundant fossil discoveries were made on the Isle of Wight, giving a good impression of the build of the species. It was a small, agile bipedal herbivore, measuring 1.5–2 m (4.9–6.6 ft) long and weighing 20 kg (44 lb). It had a pointed head equipped with a sharp beak used to bite off plant material, much like modern-day parrots.
Some outdated studies have given rise to a number of misconceptions about Hypsilophodon, including that it was an armoured, arboreal animal, and that it could be found in areas outside of the Isle of Wight. However, research from the following years has shown these ideas to be incorrect.', '[]', 'https://cdn.jacobmaynard.dev/creatures/hypsilophodon-foxii.webp', 2.3715);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('ff5c151ba5f7d38c1bac0', 'Iguanodon', 'Iguanodon bernissartensis', 'Cretaceous', 'Early Cretaceous', 'Herbivorous', 10.0, 4000.0, 'rare', 'Iguanodon, named in 1825, is a genus of iguanodontian dinosaur. While many species found worldwide have been classified in the genus Iguanodon, dating from the Late Jurassic to Early Cretaceous, taxonomic revision in the early 21st century has defined Iguanodon to be based on at least one well-substantiated species: Iguanodon bernissartensis, which lived during the Barremian to early Aptian ages of the Early Cretaceous in Belgium, Germany, England, and Spain, between about 126 and 122 million years ago. Iguanodon was a large, bulky herbivore, measuring up to 9–11 metres (30–36 ft) in length and 4.5 metric tons (5.0 short tons) in body mass.', '[]', 'https://cdn.jacobmaynard.dev/creatures/iguanodon-bernissartensis.webp', 3.1915);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('c256e8a3bad39112c8469', 'Indosuchus', 'Indosuchus raptorius', 'Cretaceous', 'Late Cretaceous', 'Carnivorous', 7.0, NULL, 'uncommon', 'Indosuchus is a genus of abelisaurid dinosaur from the Late Cretaceous Period (Maastrichtian, 70 to 66 million years ago) of what is now India. Like most theropods, Indosuchus was a bipedal carnivore. It was about 7 metres (23 ft) long, weighed about 1.2 tonnes (1.3 short tons), and had a crested skull, flattened on the top.', '[]', 'https://cdn.jacobmaynard.dev/creatures/indosuchus-raptorius.webp', 2.7523);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('1df77d88614e1bfef9a28', 'Irritator', 'Irritator challengeri', 'Cretaceous', 'Early Cretaceous', 'Carnivorous', 6.5, NULL, 'uncommon', 'Irritator is a genus of spinosaurid dinosaur that lived in what is now Brazil during the Albian stage of the Early Cretaceous Period, about 113 to 110 million years ago. It is known from a nearly complete skull found in the Romualdo Formation of the Araripe Basin. Fossil dealers had acquired this skull and sold it to the State Museum of Natural History Stuttgart. In 1996, the specimen became the holotype of the type species Irritator challengeri. The genus name comes from the word "irritation", reflecting the feelings of paleontologists who found the skull had been heavily damaged and altered by the collectors. The species name is a homage to the fictional character Professor Challenger from Arthur Conan Doyle''s novels.
Some paleontologists regard Angaturama limai—known from a snout tip that was described a few weeks later also in 1996—as a potential junior synonym of Irritator. Both animals hail from the same stratigraphic units of the Araripe Basin.', '[]', 'https://cdn.jacobmaynard.dev/creatures/irritator-challengeri.webp', 1.7751);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('c653c9e86cc996627720c', 'Isisaurus', 'Isisaurus colberti', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', NULL, NULL, 'common', 'Isisaurus (named after the Indian Statistical Institute) is a genus of titanosaurian dinosaur from the Late Cretaceous Lameta Formation of India and Pab Formation of Pakistan. The genus contains a single species, Isisaurus colberti.', '[]', 'https://cdn.jacobmaynard.dev/creatures/isisaurus-colberti.webp', 1.4019);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('3e26c228268ee1418e4ba', 'Janenschia', 'Janenschia robusta', 'Jurassic', 'Late Jurassic', 'Herbivorous', 20.0, NULL, 'rare', 'Janenschia (named after Werner Janensch) is a genus of large herbivorous sauropod dinosaur from the Late Jurassic (around 155 to 145 million years ago) Tendaguru Formation of Lindi Region, Tanzania.', '[]', 'https://cdn.jacobmaynard.dev/creatures/janenschia-robusta.webp', 2.4194);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('cbdd273fda766933ea862', 'Jaxartosaurus', 'Jaxartosaurus aralensis', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 9.0, NULL, 'uncommon', 'Jaxartosaurus (meaning "Jaxartes lizard" after the early name of the Syr Darya) is a genus of hadrosaurid dinosaur similar to Corythosaurus which lived during the Late Cretaceous. Its fossils were found in Kazakhstan.', '[]', 'https://cdn.jacobmaynard.dev/creatures/jaxartosaurus-aralensis.webp', 2.0906);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('a86b90fbae052bf01f2bf', 'Jingshanosaurus', 'Jingshanosaurus xinwaensis', 'Jurassic', 'Early Jurassic', 'Herbivorous', 5.0, NULL, 'common', 'Jingshanosaurus (meaning "Jingshan lizard") is a genus of sauropodomorph dinosaurs from the early Jurassic period (201.4 to 196.5 million years ago, Hettangian age) of China. The type and only species is Jingshanosaurus xinwaensis. Its maximum weight was around 4.3 t (4.7 short tons) with an adult femur length of 845 mm (33.3 in). The genus grew up to 5 m (16 ft) long.', '[]', 'https://cdn.jacobmaynard.dev/creatures/jingshanosaurus-xinwaensis.webp', 3.0612);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('c5c38887bad3c1529b75a', 'Jinzhousaurus', 'Jinzhousaurus yangi', 'Cretaceous', 'Early Cretaceous', 'Herbivorous', NULL, NULL, 'common', 'Jinzhousaurus is a genus of hadrosauroid dinosaur of the Early Cretaceous of China. The type species is Jinzhousaurus yangi. The generic name refers to the town Jinzhou. The specific name honours Yang Zhongjian is the founder of Chinese paleontology. It was first described by Wang Xiao-lin and Xu Xing in 2001.', '[]', 'https://cdn.jacobmaynard.dev/creatures/jinzhousaurus-yangi.webp', 1.5464);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('cd437b090215692f1134d', 'Jobaria', 'Jobaria tiguidensis', 'Cretaceous', 'Early Cretaceous', 'Herbivorous', 21.0, NULL, 'rare', 'Jobaria is a genus of sauropod dinosaur that lived in what is now Niger during the middle Jurassic Period, between 164 and 161 million years ago. Jobaria is currently the only known valid sauropod from the Tiouraren, where it was discovered in 1997.', '[]', 'https://cdn.jacobmaynard.dev/creatures/jobaria-tiguidensis.webp', 1.4118);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('6f1e71201ae062bf9b0f1', 'Juravenator', 'Juravenator starki', 'Jurassic', 'Late Jurassic', 'Carnivorous', 0.8, NULL, 'common', 'Juravenator is a genus of tetanuran theropod dinosaur which lived about 152 or 151 million years ago in modern day Franconian Jura of Germany (Torleite Formation) during the Late Jurassic. It is known from a single, juvenile specimen measuring about 75 cm (2.46 ft) in length.', '[]', 'https://cdn.jacobmaynard.dev/creatures/juravenator-starki.webp', 1.3333);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('88fabf0c764b82844bfad', 'Kentrosaurus', 'Kentrosaurus aethiopicus', 'Jurassic', 'Late Jurassic', 'Herbivorous', 5.0, NULL, 'common', 'Kentrosaurus is a genus of stegosaurid dinosaur from the Late Jurassic in Lindi Region of Tanzania. The type species is K. aethiopicus, named and described by German palaeontologist Edwin Hennig in 1915. Often thought to be a "primitive" member of the Stegosauria, several recent cladistic analyses find it as more derived than many other stegosaurs, and a close relative of Stegosaurus from the North American Morrison Formation within the Stegosauridae.
Fossils of K. aethiopicus have been found only in the Tendaguru Formation, dated to the late Kimmeridgian and early Tithonian ages, about 152 million years ago. Hundreds of bones were unearthed by German expeditions to German East Africa between 1909 and 1912. Although no complete skeletons are known, the remains provided a nearly complete picture of the build of the animal.', '[]', 'https://cdn.jacobmaynard.dev/creatures/kentrosaurus-aethiopicus.webp', 2.0833);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('1938dc84a51961177da09', 'Khaan', 'Khaan mckennai', 'Cretaceous', 'Late Cretaceous', 'Omnivorous', 1.8, NULL, 'common', 'Khaan is an extinct genus of oviraptorid dinosaur known from remains found in the Djadochta Formation of Mongolia, dating to the Late Cretaceous (Campanian, 75-71 million years ago).', '[]', 'https://cdn.jacobmaynard.dev/creatures/khaan-mckennai.webp', 1.3333);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('c07c32917188e8ef57131', 'Kotasaurus', 'Kotasaurus yamanpalliensis', 'Jurassic', 'Early Jurassic', 'Herbivorous', 9.0, NULL, 'uncommon', 'Kotasaurus is a genus of sauropod dinosaur from the Early Jurassic period (Sinemurian–Pliensbachian). The only known species is Kotasaurus yamanpalliensis. It was discovered in the Kota Formation of Telangana, India and shared its habitat with the related Barapasaurus. So far the remains of at least 12 individuals are known. The greater part of the skeleton is known, but the skull is missing, with the exception of two teeth. Like some sauropods, it had a tail club that would have been used for intraspecific combat or interspecific defense.', '[]', 'https://cdn.jacobmaynard.dev/creatures/kotasaurus-yamanpalliensis.webp', 1.3333);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('254671da075785eeb11b1', 'Kritosaurus', 'Kritosaurus navajovius', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 8.0, NULL, 'uncommon', 'Kritosaurus is an incompletely known genus of hadrosaurid (duck-billed) dinosaur. It lived about 74.5-66 million years ago, in the Late Cretaceous of North America. The name means "separated lizard" (referring to the arrangement of the cheek bones in an incomplete type skull), but is often mistranslated as "noble lizard" in reference to the presumed "Roman nose" (in the original specimen, the nasal region was fragmented and disarticulated, and was originally restored flat).', '[]', 'https://cdn.jacobmaynard.dev/creatures/kritosaurus-navajovius.webp', 2.0202);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('083d915680bcfdd77d437', 'Lambeosaurus', 'Lambeosaurus lambei', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 9.0, NULL, 'uncommon', 'Lambeosaurus is a genus of hadrosaurid dinosaur that lived during the Late Cretaceous period of western North America. The first skull of Lambeosaurus found was used by palaeontologist Lawrence M. Lambe to justify the creation of the new genus Stephanosaurus, although it was not part of the latter''s original material. Its incomplete nature led William A. Parks to name Lambeosaurus lambei for this skull in 1923 to honour Lambe. Multiple species of Lambeosaurus have been named since, including L. clavinitialis and L. magnicristatus in 1935, and L. laticaudus in 1981 which was later moved to its own genus Magnapaulia. It has also been identified that some species earlier identified as belonging to Tetragonosaurus and Corythosaurus are now considered juveniles of Lambeosaurus. It is the eponymous member of the subfamily Lambeosaurinae and tribe Lambeosaurini.', '[]', 'https://cdn.jacobmaynard.dev/creatures/lambeosaurus-lambei.webp', 0.7362);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('29201c7e5894c4890975b', 'Lapparentosaurus', 'Lapparentosaurus madagascariensis', 'Jurassic', NULL, 'Herbivorous', NULL, NULL, 'common', 'Lapparentosaurus is a genus of sauropod dinosaur from the Middle Jurassic. Its fossils were found in Madagascar (Isalo III Formation). It contains one species, Lapparentosaurus madagascariensis. The genus and species were named by José Bonaparte in 1986. The classification of Lapparentosaurus is controversial, as it exhibits a combination of characteristics of basal sauropods and titanosauriforms.', '[]', 'https://cdn.jacobmaynard.dev/creatures/lapparentosaurus-madagascariensis.webp', 1.9802);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('0aa23e6691795aa77ba34', 'Leaellynasaura', 'Leaellynasaura amicagraphica', 'Cretaceous', 'Early Cretaceous', 'Herbivorous', 2.0, NULL, 'common', 'Leaellynasaura (meaning "Leaellyn''s lizard") is a genus of small herbivorous ornithischian dinosaurs from the late Aptian to early Albian stage of the Early Cretaceous, around 118-110 million years ago. It was first discovered in Dinosaur Cove, Australia. The only known species is Leaellynasaura amicagraphica. It was described in 1989, and named after Leaellyn Rich, the daughter of the Australian palaeontologist couple Tom Rich and Patricia Vickers-Rich who discovered it. The specific name, amicagraphica, translates to "friend writing" and honours both the Friends of the Museum of Victoria and the National Geographic Society for their support of Australian paleontology.', '[]', 'https://cdn.jacobmaynard.dev/creatures/leaellynasaura-amicagraphica.webp', 1.7751);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('aa43e9c0971e5f3cb39c5', 'Leptoceratops', 'Leptoceratops gracilis', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 3.0, NULL, 'common', 'Leptoceratops (meaning ''small horn face'') is a genus of ceratopsian dinosaur from the Late Cretaceous of North America. First found in Alberta in 1910, the type species Leptoceratops gracilis was named in 1914 by Barnum Brown for a partial skull and skeleton of two individuals found in the Scollard Formation of Alberta. Additional specimens found in the Scollard include one complete and two mostly complete skeletons together, uncovered in 1947 by Charles M. Sternberg. Specimens from Montana that were among the earliest referred to Leptoceratops have since been moved to their own genera Montanoceratops and Cerasinops, while new specimens of L. gracilis include bonebed remains from the Hell Creek Formation of Montana and a partial skeleton from the Lance Formation of Wyoming. Together with related taxa, Leptoceratops is the eponymous genus of the family Leptoceratopsidae.', '[]', 'https://cdn.jacobmaynard.dev/creatures/leptoceratops-gracilis.webp', 1.9672);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('193b4338132ce462485b4', 'Lesothosaurus', 'Lesothosaurus diagnosticus', 'Jurassic', 'Early Jurassic', 'Herbivorous', 1.0, 10.0, 'common', 'Lesothosaurus is a monospecific genus of ornithischian dinosaur that lived during the Early Jurassic in what is now South Africa and Lesotho. It was named by paleontologist Peter Galton in 1978, the name meaning "lizard from Lesotho". The genus has only one valid species, Lesothosaurus diagnosticus. Lesothosaurus is one of the most completely-known early ornithischians, based on numerous skull and postcranial fossils from the Upper Elliot Formation. It had a simpler tooth and jaw anatomy than later ornithischians, and may have been omnivorous in some parts of the year.', '[]', 'https://cdn.jacobmaynard.dev/creatures/lesothosaurus-diagnosticus.webp', 2.0833);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('5dfc1022985389db56be6', 'Liaoceratops', 'Liaoceratops yanzigouensis', 'Cretaceous', 'Early Cretaceous', 'Herbivorous', NULL, NULL, 'common', 'Liaoceratops, meaning "Liaoning horned face", is a ceratopsian dinosaur believed to be an early relative of the horned ceratopsids. It lived in the Early Cretaceous, 126 million years ago. It was discovered in China by a team of American and Chinese scientists. Liaoceratops was much smaller than its later relatives, but offers a glimpse into the early evolution of this group of dinosaurs.', '[]', 'https://cdn.jacobmaynard.dev/creatures/liaoceratops-yanzigouensis.webp', 2.9557);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('53580a4ea076b4ab813db', 'Ligabuesaurus', 'Ligabuesaurus leanzai', 'Cretaceous', 'Early Cretaceous', 'Herbivorous', 24.0, NULL, 'rare', 'Ligabuesaurus is a genus of somphospondylan sauropod from the Early Cretaceous Lohan Cura Formation of what is now Argentina. The type species, Ligabuesaurus leanzai, was described in 2006, based on a partial skeleton with a skull. The generic name, Ligabuesaurus, honors Giancarlo Ligabue, while the specific name, leanzai, honors the geologist Dr. Héctor A. Leanza, who discovered the skeleton in the Lohan Cura Formation.', '[]', 'https://cdn.jacobmaynard.dev/creatures/ligabuesaurus-leanzai.webp', 1.7241);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('75d52cdfe7147fea65c88', 'Liliensternus', 'Liliensternus liliensterni', 'Triassic', 'Late Triassic', 'Carnivorous', 5.0, NULL, 'common', 'Liliensternus is an extinct genus of basal neotheropod dinosaur that lived approximately 210 million years ago during the latter part of the Triassic Period in what is now Germany. Liliensternus was a bipedal, ground-dwelling carnivore, that could grow up to 5.15 m (16.9 ft) long; however, this size estimate is based on specimens now believed to be subadults, and possible fragmentary remains indicate an adult length of 7 to 9 meters. It is the best represented Triassic theropod from Europe and one of the largest known.', '[]', 'https://cdn.jacobmaynard.dev/creatures/liliensternus-liliensterni.webp', 2.1352);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('da69e4b3cb5be34245676', 'Lophorhothon', 'Lophorhothon atopus', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 4.5, NULL, 'common', 'Lophorhothon is a genus of hadrosauroid dinosaur from the Late Cretaceous of Alabama, and possibly Georgia and North Carolina. It was the first dinosaur genus discovered in Alabama, in the United States.', '[]', 'https://cdn.jacobmaynard.dev/creatures/lophorhothon-atopus.webp', 0.71);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('377c0d89c3cbf1950c2e2', 'Lophostropheus', 'Lophostropheus airelensis', 'Jurassic', 'Early Jurassic', 'Carnivorous', 6.2, NULL, 'uncommon', 'Lophostropheus is an extinct genus of coelophysoid theropod dinosaur that lived approximately 205.6 to 196.5 million years ago during the boundary between the Late Triassic Period and the Early Jurassic Period, in what is now Normandy, France. Lophostropheus is one of the few dinosaurs that may have survived the Triassic–Jurassic extinction event.
Lophostropheus was a small to medium-sized, moderately-built, ground-dwelling, bipedal carnivore, that could grow up to 3 m (9.8 ft) long. Over the years it had been incorrectly classified as Halticosaurus and Liliensternus, but was later recognized as a new genus and was reassigned to Lophostropheus in 2007.', '[]', NULL, NULL);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('b86d66d36a559c7f05c6e', 'Lufengosaurus', 'Lufengosaurus huenei', 'Jurassic', 'Early Jurassic', 'Herbivorous', 6.0, NULL, 'uncommon', 'Lufengosaurus (Chinese: 祿豐龍 or 禄丰龙, meaning "Lufeng lizard") is a genus of massospondylid dinosaur which lived during the Early Jurassic period in what is now southwestern China.', '[]', 'https://cdn.jacobmaynard.dev/creatures/lufengosaurus-huenei.webp', 1.9934);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('56228f4b5a59ce033c2f9', 'Lurdusaurus', 'Lurdusaurus arenatus', 'Cretaceous', 'Early Cretaceous', 'Herbivorous', 9.0, NULL, 'uncommon', 'Lurdusaurus ("heavy lizard") is a genus of massive and unusually shaped iguanodont dinosaur from the Elrhaz Formation in Niger. It contains one species, L. arenatus. The formation dates to the Early Cretaceous, roughly 112 million years ago.
Lurdusaurus has a highly atypical body plan for an iguanodont, with a small skull, long neck, rotund torso, and powerful forelimbs and claws (the thumb-pike is remarkably enormous), somewhat reminiscent of a ground sloth. Lurdusaurus is estimated to have been 7–9 m (23–30 ft) long and 2 m (6 ft 7 in) high when on all-fours, but its stomach would have been only 70 cm (2 ft 4 in) off the ground. It may have weighed 2.5–5.5 t (2.8–6.1 short tons), conspicuously heavy for an iguanodontid this size. Correspondingly, Lurdusaurus may be the first ornithischian identified with graviportal anatomy, designed for moving slowly whilst supporting a heavy body mass.
Paleontologist Thomas R. Holtz Jr. speculated Lurdusaurus may have behaved much like a hippo.', '[]', 'https://cdn.jacobmaynard.dev/creatures/lurdusaurus-arenatus.webp', 1.519);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('94c57138aa460cbbe163c', 'Lycorhinus', 'Lycorhinus angustidens', 'Triassic', 'Late Triassic', 'Herbivorous', 1.2, NULL, 'common', 'Lycorhinus is a genus of heterodontosaurid ornithischian dinosaur from the Early Jurassic (Hettangian to Sinemurian ages) strata of the Elliot Formation located in the Cape Province, South Africa.', '[]', 'https://cdn.jacobmaynard.dev/creatures/lycorhinus-angustidens.webp', 1.0);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('1fbd0fcaa49175c6d9c5c', 'Magyarosaurus', 'Magyarosaurus dacus', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 5.0, NULL, 'common', 'Magyarosaurus ("Hungarian lizard") is a genus of dwarf sauropod dinosaur from late Cretaceous Period (early to late Maastrichtian) in Romania. It is one of the smallest-known adult sauropods, measuring less than 3 m (9.8 ft) long and weighing less than 1,000 kg (2,200 lb). The type and only species is Magyarosaurus dacus. It has been found to be a close relative of Rapetosaurus in the family Saltasauridae in the sauropod clade Titanosauria in a 2005 study.', '[]', 'https://cdn.jacobmaynard.dev/creatures/magyarosaurus-dacus.webp', 1.676);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('c60f619101bf1c709a58d', 'Maiasaura', 'Maiasaura peeblesorum', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 9.0, 2500.0, 'uncommon', 'Maiasaura is a large herbivorous saurolophine hadrosaurid ("duck-billed") dinosaur genus that lived in the area currently covered by the state of Montana and the Canadian province of Alberta, in the Upper Cretaceous (mid to late Campanian), from 86.3 to 70.6 million years ago. Maiasaura is the state fossil of Montana. 
The first remains of Maiasaura were discovered in the Two Medicine Formation near Choteau, Montana in 1978 by Bynum, Montana resident Laurie Trexler. This holotype specimen was later described by Horner and Makela in 1979 as the new genus and species Maiasaura peeblesorum. The given genus name refers to the finding of eggs, embryos, and juveniles in a nest-like structure by Marion Brandvold in 1978 relatively close to the holotype specimen.', '[]', 'https://cdn.jacobmaynard.dev/creatures/maiasaura-peeblesorum.webp', 1.7751);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('69fad982e562adcb9ea24', 'Majungasaurus', 'Majungasaurus atopus', 'Cretaceous', 'Late Cretaceous', 'Carnivorous', 6.0, NULL, 'uncommon', 'Majungasaurus is a genus of abelisaurid theropod dinosaur that lived in Madagascar from 70 to 66 million years ago, at the end of the Cretaceous Period, making it one of the last-known non-avian dinosaurs that went extinct during the Cretaceous–Paleogene extinction event. The genus contains a single species, Majungasaurus crenatissimus. This dinosaur is also called Majungatholus, a name which is considered a junior synonym of Majungasaurus.
Like other abelisaurids, Majungasaurus was a bipedal predator with a short snout. Although the forelimbs are not completely known, they were very short, while the hind limbs were longer and very stocky.', '[]', 'https://cdn.jacobmaynard.dev/creatures/majungasaurus-atopus.webp', 1.4778);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('08c01e647b875412aed91', 'Malawisaurus', 'Malawisaurus dixeyi', 'Cretaceous', 'Early Cretaceous', 'Herbivorous', 9.0, NULL, 'uncommon', 'Malawisaurus (meaning "Malawi lizard") is an extinct genus of titanosaurian sauropod dinosaur. It is known from the Dinosaur Beds of northern Malawi, which probably date to the Aptian stage of the Early Cretaceous. The type species is M. dixeyi and the specific name honours Frederick Augustus Dixey.', '[]', 'https://cdn.jacobmaynard.dev/creatures/malawisaurus-dixeyi.webp', 0.715);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('5c962c8cbc035e46263bc', 'Mamenchisaurus', 'Mamenchisaurus constructus', 'Jurassic', 'Late Jurassic', 'Herbivorous', 22.0, NULL, 'rare', 'Mamenchisaurus is an extinct genus of sauropod dinosaurs known for their remarkably long necks, which made up nearly half the total body length. Numerous species have been assigned to the genus; however, the validity of these assignments has been questioned. Fossils have been found in the Sichuan Basin and Yunnan Province in China. Several species from the Upper Shaximiao Formation, whose geologic age is uncertain, have been described. However, evidence suggests this formation to be no earlier than the Oxfordian stage of the Late Jurassic. M. sinocanadorum dates to the Oxfordian stage (161.2 to 158.7 mya), and M. anyuensis to the Aptian stage of the Early Cretaceous (around 114.4 mya). Most species were medium-large to large sauropods, measuring roughly 15 to 26 meters (49 to 85 ft) in length—possibly up to 35 meters (115 ft), based on two undescribed vertebrae.', '[]', 'https://cdn.jacobmaynard.dev/creatures/mamenchisaurus-constructus.webp', 1.3333);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('9faec0f96a4a346429098', 'Mapusaurus', 'Mapusaurus roseae', 'Cretaceous', 'Late Cretaceous', 'Carnivorous', 13.0, NULL, 'uncommon', 'Mapusaurus is a genus of giant carcharodontosaurid carnosaurian dinosaur that lived in Argentina during the Cenomanian–Turonian ages of the Late Cretaceous. It is known from a bonebed of between seven and nine specimens, excavated from the strata of the Huincul Formation between 1997 and 2001 as part of the Argentinian-Canadian Dinosaur Project. In 2006, Rodolfo Coria and Philip J. Currie scientifically described Mapusaurus. Only one species of Mapusaurus, M. roseae, has been described, named after the rose-colored rocks in which it was discovered and sponsor Rose Letwin.
Mapusaurus was one of the largest carcharodontosaurids. Based on the biggest specimen known from the bonebed, represented by a left femur, it was originally estimated to have reached a maximum body length of 10.2 m (33 ft) and a mass of 3 t (6,600 lb). Subsequent works have given maximum size estimates of 10.2–12.6 metres (33–41 ft) and 3–6 t (6,600–13,200 lb) respectively.', '[]', 'https://cdn.jacobmaynard.dev/creatures/mapusaurus-roseae.webp', 2.0067);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('544751c9452aac7822e18', 'Marshosaurus', 'Marshosaurus bicentesimus', 'Jurassic', 'Late Jurassic', 'Carnivorous', 6.0, NULL, 'uncommon', 'Marshosaurus is a genus of carnivorous theropod dinosaur, belonging to the family Piatnitzkysauridae, from the Late Jurassic Morrison Formation of Utah and possibly Colorado.', '[]', 'https://cdn.jacobmaynard.dev/creatures/marshosaurus-bicentesimus.webp', 2.2989);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('4589256e51be77c679930', 'Masiakasaurus', 'Masiakasaurus knopfleri', 'Cretaceous', 'Late Cretaceous', 'Carnivorous', 2.0, NULL, 'common', 'Masiakasaurus is a genus of small predatory theropod dinosaurs from the Late Cretaceous of Madagascar. In Malagasy, masiaka means "vicious"; thus, the genus name means "vicious lizard". The type species, Masiakasaurus knopfleri, was named after the musician Mark Knopfler, whose music inspired the expedition crew. It was named in 2001 by Scott D. Sampson, Matthew Carrano, and Catherine A. Forster. Unlike most theropods, the front teeth of Masiakasaurus projected forwards instead of straight down. This unique dentition suggests that they had a specialized diet, perhaps including fish and other small prey. Other bones of the skeleton indicate that Masiakasaurus were bipedal, with much shorter forelimbs than hindlimbs. It was a small theropod, reaching 1.8–2.1 m (5.9–6.9 ft) long and weighing 20 kg (44 lb). Masiakasaurus lived from 72.1 to 66 million years ago, along with animals such as Majungasaurus, Rapetosaurus, and Rahonavis.', '[]', 'https://cdn.jacobmaynard.dev/creatures/masiakasaurus-knopfleri.webp', 1.4252);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('d99e59894d82399c3260b', 'Massospondylus', 'Massospondylus carinatus', 'Jurassic', 'Early Jurassic', 'Omnivorous', 4.0, 70.0, 'common', 'Massospondylus is a genus of sauropodomorph dinosaur from the Early Jurassic of southern Africa. It was described by Richard Owen in 1854 from remains discovered in South Africa, and is thus one of the first dinosaurs to have been named. The name Massospondylus means ''longer vertebra'', alluding to what Owen identified as tail vertebrae; these vertebrae are now known to be from the neck. Although the original fossils were destroyed in London during a bombing raid in World War II, a plethora of specimens have since been assigned to the genus, making it one of the best-known sauropodomorphs from the Early Jurassic. The genus lived during the Hettangian, Sinemurian, and Pliensbachian ages, which lasted from ca. 201 to 184 million years ago. Most fossils come from the upper Elliot and Clarens formations of South Africa and Lesotho, but the genus is also found in the Forest Sandstone and the Mpandi Formation of Zimbabwe.', '[]', 'https://cdn.jacobmaynard.dev/creatures/massospondylus-carinatus.webp', 3.0928);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('f84d14ccfbeb891fe6d8d', 'Maxakalisaurus', 'Maxakalisaurus topai', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 13.0, NULL, 'uncommon', 'Maxakalisaurus is a genus of titanosaur dinosaur, found in the Adamantina Formation of Brazil, in the state of Minas Gerais in 1998. The genus name is derived from the tribe of the Maxakali; Topa is one of their divinities.', '[]', 'https://cdn.jacobmaynard.dev/creatures/maxakalisaurus-topai.webp', 1.3333);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('c0a35a15db939e3630720', 'Megalosaurus', 'Megalosaurus bucklandii', 'Jurassic', NULL, 'Carnivorous', 6.0, NULL, 'uncommon', 'Megalosaurus (meaning "great lizard", from Greek μέγας, megas, meaning ''big'', ''tall'' or ''great'' and σαῦρος, sauros, meaning ''lizard'') is an extinct genus of large carnivorous theropod dinosaurs of the Middle Jurassic Epoch (Bathonian stage, 166 million years ago) of southern England. Although fossils from other areas have been assigned to the genus, the only certain remains of Megalosaurus come from Oxfordshire and date to the late Middle Jurassic.
The earliest remains of Megalosaurus were described in the 17th century, and were initially interpreted as the remains of elephants or giants. Megalosaurus was named in 1824 by William Buckland, becoming the first genus of dinosaur to be validly named (other than birds, not then recognized as dinosaurs). The type species is M. bucklandii, named in 1827 by Gideon Mantell, after Buckland. In 1842, Megalosaurus was one of three genera on which Richard Owen based his Dinosauria, along with Iguanodon and Hylaeosaurus.', '[]', 'https://cdn.jacobmaynard.dev/creatures/megalosaurus-bucklandii.webp', 1.2793);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('07e0c4d7944e8ac1c77c9', 'Melanorosaurus', 'Melanorosaurus readi', 'Triassic', 'Late Triassic', 'Omnivorous', 12.0, NULL, 'uncommon', 'Melanorosaurus is a genus of basal sauropodomorph dinosaur that lived during the Late Triassic period. An omnivore from South Africa, it had a large body and sturdy limbs, suggesting it moved quadrupedally. Its limb bones were massive and heavy like the limb bones of true sauropods.', '[]', 'https://cdn.jacobmaynard.dev/creatures/melanorosaurus-readi.webp', 1.9737);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('f7557ea01e447259cbe1a', 'Metriacanthosaurus', 'Metriacanthosaurus parkeri', 'Jurassic', 'Late Jurassic', 'Carnivorous', 8.2, NULL, 'uncommon', 'Metriacanthosaurus (meaning "moderately-spined lizard") is a genus of metriacanthosaurid dinosaur from the Oxford Clay Formation of England, dating to the Late Jurassic period, about 160 million years ago (lower Oxfordian). It is the only metriacanthosaurid currently named from outside of Asia.', '[]', 'https://cdn.jacobmaynard.dev/creatures/metriacanthosaurus-parkeri.webp', 1.3825);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('8f6eea9678604a9d38fd9', 'Microceratus', 'Microceratus gobiensis', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 0.5, NULL, 'common', 'Microceratus (meaning "small-horned") is a genus of small ceratopsian dinosaur that lived in the Cretaceous period of Mongolia. It walked on two legs, had short front arms, a characteristic ceratopsian frill and beak-like mouth, and was around 60 cm (2.0 ft) long. It was one of the most primitive ceratopsians, or horned dinosaurs, along with Psittacosaurus, which was also discovered in Mongolia.', '[]', 'https://cdn.jacobmaynard.dev/creatures/microceratus-gobiensis.webp', 1.5957);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('13f15c952ada8d7b795f0', 'Micropachycephalosaurus', 'Micropachycephalosaurus hongtuyanensis', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 0.6, NULL, 'epic', 'Micropachycephalosaurus (meaning "small thick-headed lizard") is an extinct genus of basal marginocephalian dinosaur, containing only the type species, Micropachycephalosaurus hongtuyanensis. It lived in China during the Late Cretaceous (Campanian) and was found in the Jiangjunding Formation. It has the longest name of any dinosaur, with 23 letters in the genus name alone, while the full binomial contains 37 letters.', '[]', 'https://cdn.jacobmaynard.dev/creatures/micropachycephalosaurus-hongtuyanensis.webp', 2.3715);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('5170dae80cf5b17a81ac0', 'Microraptor', 'Microraptor zhaoianus', 'Cretaceous', 'Early Cretaceous', 'Carnivorous', 0.8, 1.0, 'rare', 'Microraptor (Greek, μικρός, mīkros: "small"; Latin, raptor: "one who seizes") is a genus of small, four-winged dromaeosaurid dinosaurs. Numerous well-preserved fossil specimens have been recovered from Liaoning, China. They date from the early Cretaceous Jiufotang Formation (Aptian stage), 125 to 120 million years ago. Three species have been named (M. zhaoianus, M. gui, and M. hanqingi), though further study has suggested that all of them represent variation in a single species, which is properly called M. zhaoianus. Cryptovolans, initially described as another four-winged dinosaur, is usually considered to be a synonym of Microraptor.
Like Archaeopteryx, well-preserved fossils of Microraptor provide important evidence about the evolutionary relationship between birds and earlier dinosaurs. Microraptor had long pennaceous feathers that formed aerodynamic surfaces on the arms and tail but also on the legs.', '[]', 'https://cdn.jacobmaynard.dev/creatures/microraptor-zhaoianus.webp', 1.6173);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('f6102c133c945e9d78ab6', 'Minmi', 'Minmi paravertebra', 'Cretaceous', 'Early Cretaceous', 'Herbivorous', 3.0, NULL, 'common', 'Minmi is a genus of small herbivorous ankylosaurian dinosaur that lived during the early Cretaceous Period of Australia, about 120 to 112 million years ago.', '[]', 'https://cdn.jacobmaynard.dev/creatures/minmi-paravertebra.webp', 1.5385);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('bf56102d7de6774a6d9f5', 'Monolophosaurus', 'Monolophosaurus jiangi', 'Jurassic', NULL, 'Carnivorous', 5.7, NULL, 'uncommon', 'Monolophosaurus is an extinct genus of tetanuran theropod dinosaur from the Middle Jurassic Shishugou Formation in what is now Xinjiang, China. It was named for the single crest on top of its skull. Monolophosaurus was a mid-sized theropod at about 5–5.5 metres (16–18 ft) long and weighed 475 kilograms (1,047 lb).', '[]', 'https://cdn.jacobmaynard.dev/creatures/monolophosaurus-jiangi.webp', 1.3304);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('0a1758e22c4f7f001a5d1', 'Mononykus', 'Mononykus olecranus', 'Cretaceous', 'Late Cretaceous', 'Unknown', 1.0, NULL, 'common', 'Mononykus is a genus of alvarezsaurid dinosaur that lived during the Late Cretaceous in what is now Mongolia, specifically the Nemegt Formation, about 70 million years ago. Mononykus was a very small theropod, estimated around 1 to 1.2 metres (3.3 to 3.9 ft) in length with a weight of 3.5 kilograms (7.7 lb). As in Shuvuuia, Mononykus likely developed a shaggy feathering. It was lightly built with long, thin legs and highly reduced and specialized forelimbs that were likely used for foraging termite mounds or other insect colonies.', '[]', 'https://cdn.jacobmaynard.dev/creatures/mononykus-olecranus.webp', 1.5);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('342fe8bbff268e8b65853', 'Mussaurus', 'Mussaurus patagonicus', 'Triassic', 'Late Triassic', 'Herbivorous', 3.0, NULL, 'common', 'Mussaurus (meaning "mouse lizard") is a genus of herbivorous sauropodomorph dinosaur that lived in southern Argentina during the Sinemurian stage of the Early Jurassic. It receives its name from the small size of the skeletons of juvenile and infant individuals, which were once the only known specimens of the genus. However, since Mussaurus is now known from adult specimens, the name is something of a misnomer. 
In its early stages of life, Mussaurus was a small quadrupedal herbivore, walking on all four legs. As it grew up, the changes in body proportions may have led its centre of mass to move backwards towards its pelvis. Adults would have been medium-sized bipedal herbivores, measuring up to 8 metres (26 ft) long and weighing up to 1.2–1.6 metric tons (1.3–1.8 short tons).
Numerous specimens of varying age found in a single locality suggest that Mussaurus is one of the earliest dinosaurs to have lived in a gregarious lifestyle.', '[]', 'https://cdn.jacobmaynard.dev/creatures/mussaurus-patagonicus.webp', 1.7857);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('48a1eabcb80d2a792f187', 'Muttaburrasaurus', 'Muttaburrasaurus langdoni', 'Cretaceous', 'Early Cretaceous', 'Herbivorous', 7.0, NULL, 'uncommon', 'Muttaburrasaurus was a genus of herbivorous iguanodontian ornithopod dinosaur that lived in what is now north-eastern Australia sometime between 112 and 103 million years ago during the early Cretaceous period. It has been recovered in some analyses as a member of the iguanodontian clade Rhabdodontomorpha, or alternately as a member of Elasmaria. After Kunbarrasaurus, it is Australia''s most completely known dinosaur from skeletal remains. It was named after Muttaburra, the site in Queensland, Australia, where it was found. The dinosaur was selected from twelve candidates to become the official fossil emblem of the State of Queensland.', '[]', 'https://cdn.jacobmaynard.dev/creatures/muttaburrasaurus-langdoni.webp', 1.7699);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('4fb5e4cea23e0f4c446e6', 'Nanshiungosaurus', 'Nanshiungosaurus brevispinus', 'Cretaceous', 'Late Cretaceous', 'Omnivorous', 4.4, NULL, 'common', 'Nanshiungosaurus (meaning "Nanxiong''s lizard") is a genus of therizinosaurid that lived in what is now Asia during the Late Cretaceous of South China. The type species, Nanshiungosaurus brevispinus, was first discovered in 1974 and described in 1979 by Dong Zhiming. It is represented by a single specimen preserving most of the cervical and dorsal vertebrae with the pelvis. A supposed and unlikely second species, "Nanshiungosaurus" bohlini, was found in 1992 and described in 1997. It is also represented by vertebrae but this species however, differs in geological age and lacks authentic characteristics compared to the type, making its affinity to the genus unsupported.
It was a large-sized therizinosaurid that is estimated to have cover nearly 5 m (16 ft) in length and to have weighed about 600–907 kg (1,323–2,000 lb).', '[]', 'https://cdn.jacobmaynard.dev/creatures/nanshiungosaurus-brevispinus.webp', 1.7045);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('71a2fd47ec84fe81821fa', 'Nedoceratops', 'Nedoceratops hatcheri', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 7.0, NULL, 'uncommon', 'Nedoceratops (meaning "insufficient horned face") is a controversial genus of ceratopsid dinosaur from the Late Cretaceous period Lance Formation of North America. It is known only from a single skull discovered in Wyoming. Its status is the subject of ongoing debate among paleontologists: some authors consider Nedoceratops a valid, distinct taxon, while others consider it to be an unusual specimen of Triceratops.', '[]', 'https://cdn.jacobmaynard.dev/creatures/nedoceratops-hatcheri.webp', 1.1257);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('9465fa8e3b59c100ced46', 'Nemegtosaurus', 'Nemegtosaurus mongoliensis', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 13.0, NULL, 'uncommon', 'Nemegtosaurus (meaning "reptile from the Nemegt") was a sauropod dinosaur from the Late Cretaceous Period of what is now Mongolia. Measuring an estimated 12–13 m (39–43 ft) long and weighing 20 t (44,000 lb), it was named after the Nemegt Basin in the Gobi Desert, where the remains — a single skull — were found. The skull resembles diplodocoids in being long and low, with pencil-shaped teeth. However, recent work has shown that Nemegtosaurus is in fact a titanosaur, closely related to animals such as Saltasaurus, Alamosaurus, and Rapetosaurus.', '[]', 'https://cdn.jacobmaynard.dev/creatures/nemegtosaurus-mongoliensis.webp', 1.7964);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('22e7bad77f0bcb46a5833', 'Neovenator', 'Neovenator salerii', 'Cretaceous', 'Early Cretaceous', 'Carnivorous', 7.4, NULL, 'uncommon', 'Neovenator is an extinct genus of carcharodontosaurian theropod dinosaur. It is known primarily from several skeletons found in the Early Cretaceous (Hauterivian–Barremian) Wessex Formation on the south coast of the Isle of Wight, southern England. The first remains of Neovenator were discovered in 1978 alongside those of the ornithopod Brighstoneus, after the collapse of part of Grange Chine. In 1996, Steve Hutt, David Martill and Michael Barker named the genus Neovenator. One species is known: the type species, N. salerii, after the Salero family who owned the site on which its remains were discovered.
Between the type specimen and multiple referred specimens, roughly seventy per cent of Neovenator''s skeleton is known. While incompletely known, it was likely around 7 metres (23 ft) in length, and probably weighed 1 metric ton (1.1 short tons), though a specimen possibly referrable to the genus indicates a larger body size of 10 metres (33 ft).', '[]', 'https://cdn.jacobmaynard.dev/creatures/neovenator-salerii.webp', 1.6667);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('5299cb8e5da92f448a816', 'Neuquenosaurus', 'Neuquenosaurus australis', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 15.0, NULL, 'uncommon', 'Neuquensaurus was a relatively small sauropod. It had hardened, bone-like, raised scales on its back, which would have acted as protective armour.', '[]', NULL, NULL);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('1a925229e7c49a9f3c36d', 'Nigersaurus', 'Nigersaurus taqueti', 'Cretaceous', 'Early Cretaceous', 'Herbivorous', 15.0, NULL, 'uncommon', 'Nigersaurus () is a genus of rebbachisaurid sauropod dinosaur that lived during the middle Cretaceous period, about 115 to 105 million years ago. It was discovered in the Elrhaz Formation in an area called Gadoufaoua, in Niger. Fossils of this dinosaur were first described in 1976, but it was only named Nigersaurus taqueti in 1999 after further and more complete remains were found and described. The genus name means "Niger reptile", and the specific name honours the palaeontologist Philippe Taquet, who discovered the first remains.
Small for a sauropod, Nigersaurus was about 9–14.1 m (30–46 ft) long, and had a short neck. It weighed around 1.9–4 t (2.1–4.4 short tons), comparable to a modern elephant. Its skull was very specialised for feeding, with large fenestrae and thin bones. It had a wide muzzle filled with more than 500 teeth, which were replaced at a rapid rate: around every 14 days. The jaws may have borne a keratinous sheath.', '[]', 'https://cdn.jacobmaynard.dev/creatures/nigersaurus-taqueti.webp', 0.9119);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('aa57dfffc00ce1f5520ec', 'Nipponosaurus', 'Nipponosaurus sachalinensis', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', NULL, NULL, 'common', 'Nipponosaurus (meaning "Japanese lizard") is a lambeosaurine hadrosaur from sediments of the Yezo Group, in Sinegorsk on the island of Sakhalin, which was part of Japan at the time of the species'' classification. The type and only species is N. sachalinensis, known only from a single juvenile specimen discovered in 1934 and named in 1936, by Takumi Nagao, with further material of the same individual found in 1937. Since then, the taxon has been largely ignored, and its validity has been doubted, with synonymy with other Asian hadrosaurs or status as a nomen dubium being suggested. Redescriptions from 2004 and 2017, however, have supported recognition as a distinct species. Dating the only specimen has been difficult, but based on associated mollusc taxa, the species likely lived sometime in the upper Santonian or lower Campanian, around 80 million years ago.', '[]', 'https://cdn.jacobmaynard.dev/creatures/nipponosaurus-sachalinensis.webp', 0.9077);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('58674fdc3cb42f03e0f23', 'Noasaurus', 'Noasaurus leali', 'Cretaceous', 'Late Cretaceous', 'Carnivorous', 1.0, NULL, 'common', 'Noasaurus ("Northwestern Argentina lizard") is a genus of ceratosaurian theropod dinosaur from the Maastrichtian (Late Cretaceous) of Argentina. The type and only species is N. leali. The fragmentary holotype specimen of Noasaurus, PVL 4061, consisting of a few cranial and postcranial bones, was discovered from strata from the Lecho Formation of Southern Salta in 1975 by a team led by José Fernando Bonaparte. When described by Bonaparte and in PhD student Jaime Powell in 1980, it was believed to be a coelurosaur theropod and assigned to a family of its own; this family, Noasauridae, still exists, though has been reassigned to Ceratosauria.
Noasaurus was a fairly small theropod, with PVL 4061 measuring somewhere between 1.6–2 m (5.2–6.6 ft) in length. Initially, it was believed that two strongly curved unguals (claws) found alongside the holotype were evidence of raptorial foot claws, like those of dromaeosaurids.', '[]', 'https://cdn.jacobmaynard.dev/creatures/noasaurus-leali.webp', 1.3216);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('f0647b2ca8d58f7bb4fc3', 'Nodosaurus', 'Nodosaurus textilis', 'Cretaceous', 'Early Cretaceous', 'Herbivorous', 5.0, NULL, 'common', 'Nodosaurus (meaning ''knobbed lizard'') is a genus of herbivorous nodosaurid ankylosaurian dinosaur from the Late Cretaceous, the fossils of which are found exclusively in the Frontier Formation in Wyoming.', '[]', 'https://cdn.jacobmaynard.dev/creatures/nodosaurus-textilis.webp', 2.9126);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('554d22a8b4e5824325878', 'Nomingia', 'Nomingia gobiensis', 'Cretaceous', 'Late Cretaceous', 'Omnivorous', 1.6, NULL, 'common', 'Nomingia is a genus of oviraptorosaurian theropod dinosaur known from the Late Cretaceous Bugin Tsav Beds of Mongolia.', '[]', 'https://cdn.jacobmaynard.dev/creatures/nomingia-gobiensis.webp', 1.432);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('74f6c28adc56897c68b68', 'Nothronychus', 'Nothronychus mckinleyi', 'Cretaceous', 'Late Cretaceous', 'Omnivorous', 5.3, NULL, 'uncommon', 'Nothronychus (meaning "slothful claw") is a genus of therizinosaurid theropod dinosaurs that lived in North America during the Late Cretaceous period. The type species, Nothronychus mckinleyi, was described by James Kirkland and Douglas G. Wolfe in 2001. It was recovered near New Mexico''s border with Arizona, in an area known as the Zuni Basin, from rocks assigned to the Moreno Hill Formation, dating to the Turonian stage of the Late Cretaceous. A second specimen, described in 2009 as a second species, Nothronychus graffami, was found in the Tropic Shale of Utah, dating between one and a half million years older than N. mckinleyi.
Like other therizinosaurids, Nothronychus was likely a bulky herbivore with wide, sloth-like hips (resembling those of the unrelated ornithischians), feet with forward-facing four toes, elongated necks, and prominent arms with sharp claws. Both species were similar in dimensions, but N. graffami was slightly more robust than N. mckinleyi.', '[]', 'https://cdn.jacobmaynard.dev/creatures/nothronychus-mckinleyi.webp', 0.5988);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('2b4d7fc1b45e572c7af19', 'Nqwebasaurus', 'Nqwebasaurus thwazi', 'Jurassic', NULL, 'Carnivorous', 1.0, NULL, 'common', 'Nqwebasaurus is a probable ornithomimosaurian theropod from the Early Cretaceous of South Africa. The genus contains a single species, Nqwebasaurus thwazi, representing the oldest known coelurosaur in Africa and the evidence for basal coelurosaurian dinosaurs inhabiting Gondwana since the earliest Cretaceous period.', '[]', 'https://cdn.jacobmaynard.dev/creatures/nqwebasaurus-thwazi.webp', 1.9934);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('0a02a8a756e0cf76123ed', 'Omeisaurus', 'Omeisaurus junghsiensis', 'Jurassic', NULL, 'Herbivorous', 20.0, NULL, 'rare', 'Omeisaurus (meaning "Omei lizard") is a genus of sauropod dinosaur from the Middle to Late Jurassic Period (Bathonian-Oxfordian stage) of what is now China. Its name comes from Mount Emei, where it was discovered in the lower Shaximiao Formation of Sichuan Province.
Like most sauropods, Omeisaurus was herbivorous and large. The largest species, O. tianfuensis, measured 18–20.2 metres (59–66 ft) long, and weighed 8.5–9.8 metric tons (9.4–10.8 short tons). Other species were much smaller, as the type species O. junghsiensis reached a size of 14 metres (46 ft) in length and 4 metric tons (4.4 short tons) in body mass, and O. maoianus reached a size of 15 metres (49 ft) and 5 metric tons (5.5 short tons).', '[]', 'https://cdn.jacobmaynard.dev/creatures/omeisaurus-junghsiensis.webp', 1.7751);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('ee1551fd759d81e919b12', 'Opisthocoelicaudia', 'Opisthocoelicaudia skarzynskii', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 12.0, NULL, 'uncommon', 'Opisthocoelicaudia is a genus of sauropod dinosaur of the Late Cretaceous Period discovered in the Gobi Desert of Mongolia. The type species is Opisthocoelicaudia skarzynskii. A well-preserved skeleton lacking only the head and neck was unearthed in 1965 by Polish and Mongolian scientists, making Opisthocoelicaudia one of the best known sauropods from the Late Cretaceous. Tooth marks on this skeleton indicate that large carnivorous dinosaurs had fed on the carcass and possibly had carried away the now-missing parts. To date, only two additional, much less complete specimens are known, including part of a shoulder and a fragmentary tail. A relatively small sauropod, Opisthocoelicaudia measured about 11.4–13 m (37–43 ft) in length. Like other sauropods, it would have been characterised by a small head sitting on a very long neck and a barrel shaped trunk carried by four column-like legs.', '[]', 'https://cdn.jacobmaynard.dev/creatures/opisthocoelicaudia-skarzynskii.webp', 2.8169);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('4712b43e90017d52c2d90', 'Ornitholestes', 'Ornitholestes hermanni', 'Jurassic', 'Late Jurassic', 'Carnivorous', 2.0, NULL, 'common', 'Ornitholestes (from Ancient Greek ὄρνις (órnis), meaning "bird", and λῃστής (lēistḗs), meaning "robber", and thus, "bird robber") is a small theropod dinosaur of the late Jurassic (Brushy Basin Member of the Morrison Formation, middle Kimmeridgian age, about 154 million years ago) of Western Laurasia (the area that was to become North America).
To date, Ornitholestes is known only from a single partial skeleton with a badly crushed skull found at the Bone Cabin Quarry near Medicine Bow, Wyoming, in 1900. It was described by Henry Fairfield Osborn in 1903. An incomplete hand was later attributed to Ornitholestes, although it now appears to belong to Tanycolagreus. The type (and only known) species is O. hermanni. The specific name honors the American Museum of Natural History preparator Adam Hermann.', '[]', 'https://cdn.jacobmaynard.dev/creatures/ornitholestes-hermanni.webp', 1.7751);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('cf0c1bc42503a6f2e69e0', 'Ornithomimus', 'Ornithomimus velox', 'Cretaceous', 'Late Cretaceous', 'Omnivorous', 4.0, NULL, 'common', 'Ornithomimus (; "bird mimic") is a genus of ornithomimid theropod dinosaurs from the Campanian and Maastrichtian ages of the Late Cretaceous in western North America. Ornithomimus was a swift, bipedal dinosaur which was covered in feathers and equipped with a small toothless beak that may indicate an omnivorous diet. It is usually classified into two species: the type species, Ornithomimus velox, and a referred species, Ornithomimus edmontonicus.
O. velox was named in 1890 by Othniel Charles Marsh on the basis of a foot and partial hand from the Denver Formation of Colorado. Other seventeen species have been named since then, though almost all of them have been subsequently assigned to new genera or shown not to be directly related to O. velox. The best material of species still considered part of the genus has been found in Alberta, representing the species O. edmontonicus, known from several skeletons from the Horseshoe Canyon Formation.', '[]', 'https://cdn.jacobmaynard.dev/creatures/ornithomimus-velox.webp', 1.9737);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('efd76793787dfe3bbffc8', 'Orodromeus', 'Orodromeus makelai', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 2.0, 50.0, 'common', 'Orodromeus (meaning "Mountain Runner") is a genus of herbivorous orodromine thescelosaurid dinosaur from the Late Cretaceous of North America. Only one species is known, the type species Orodromeus makelai.', '[]', 'https://cdn.jacobmaynard.dev/creatures/orodromeus-makelai.webp', 2.6201);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('e45eac02a9a7f0438ce22', 'Oryctodromeus', 'Oryctodromeus cubicularis', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 2.1, NULL, 'common', 'Oryctodromeus (from Ancient Greek ὀρυκτήρ (oruktḗs), meaning "digger", and δρομαῖος (dromaîos), meaning "runner") is an extinct genus of small orodromine thescelosaurid dinosaur. Fossils are known from the Late Cretaceous Blackleaf Formation of southwestern Montana and the Wayan Formation of southeastern Idaho, USA, both of the Cenomanian stage, roughly 105-96 million years ago. A member of the small, presumably fast-running herbivorous family Thescelosauridae, Oryctodromeus is the first non-avian dinosaur published that shows evidence of burrowing behavior.', '[]', 'https://cdn.jacobmaynard.dev/creatures/oryctodromeus-cubicularis.webp', 1.6901);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('1c7a0781f798a9d9e1438', 'Othnielia', 'Othnielia rex', 'Jurassic', 'Late Jurassic', 'Herbivorous', 1.4, NULL, 'common', 'Nanosaurus ("small or dwarf lizard") is an extinct genus of neornithischian dinosaur that lived about 155 to 148 million years ago, during the Late Jurassic in North America. Its fossils are known from the Morrison Formation of the south-western United States. The type and only species, Nanosaurus agilis, was described and named by Othniel Charles Marsh in 1877. The taxon has a complicated taxonomic history, largely the work of Marsh and Peter M. Galton, involving the genera Laosaurus, Hallopus, Drinker, Othnielia, and Othnielosaurus, the latter three now being considered to be synonyms of Nanosaurus. It had historically been classified as a hypsilophodont or fabrosaur, types of generalized small bipedal herbivore, but more recent research has abandoned these groupings as paraphyletic and Nanosaurus is today considered a basal member of Neornithischia.', '[]', 'https://cdn.jacobmaynard.dev/creatures/othnielia-rex.webp', 1.5504);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('0f8853cd529862aee76d6', 'Ouranosaurus', 'Ouranosaurus nigeriensis', 'Cretaceous', 'Early Cretaceous', 'Herbivorous', 7.0, NULL, 'uncommon', 'Ouranosaurus is a genus of herbivorous basal hadrosauriform dinosaur that lived during the Aptian stage of the Early Cretaceous of modern-day Niger and Cameroon. Ouranosaurus measured about 7–8.3 metres (23–27 ft) long and weighed 2.2 metric tons (2.4 short tons). Two rather complete fossils were found in the Elrhaz Formation, Gadoufaoua deposits, Agadez, Niger, in 1965 and 1970, with a third indeterminate specimen known from the Koum Formation of Cameroon. The animal was named in 1976 by French paleontologist Philippe Taquet, the type species being Ouranosaurus nigeriensis. The generic name is a combination of ourane, a word with multiple meanings, and sauros, the Greek word for lizard. The specific epithet nigeriensis alludes to Niger, its country of discovery (in Latin, the adjectival suffix -iensis means "originating from"). As such, Ouranosaurus nigeriensis could be interpreted as "brave lizard originating from Niger".', '[]', 'https://cdn.jacobmaynard.dev/creatures/ouranosaurus-nigeriensis.webp', 1.6349);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('9ae3bce648d80de4a9dc4', 'Oviraptor', 'Oviraptor philoceratops', 'Cretaceous', 'Late Cretaceous', 'Omnivorous', 2.0, 20.0, 'rare', 'Oviraptor is a genus of oviraptorid dinosaur that lived in Asia during the Late Cretaceous period. The first remains were collected from the Djadokhta Formation of Mongolia in 1923 during a paleontological expedition led by Roy Chapman Andrews, and in the following year the genus and type species Oviraptor philoceratops were named by Henry Fairfield Osborn. The genus name refers to the initial thought of egg-stealing habits, and the specific name was intended to reinforce this view indicating a preference over ceratopsian eggs. Despite the fact that numerous specimens have been referred to the genus, Oviraptor is only known from a single partial skeleton regarded as the holotype, as well as a nest of about fifteen eggs and several small fragments from a juvenile.
Oviraptor was a rather small feathered oviraptorid, estimated at 1.6–2 m (5.2–6.6 ft) long with a weight between 33–40 kg (73–88 lb). It had a wide lower jaw with a skull that likely had a crest.', '[]', 'https://cdn.jacobmaynard.dev/creatures/oviraptor-philoceratops.webp', 1.4528);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('2093ebcc64f403e09b6dd', 'Pachycephalosaurus', 'Pachycephalosaurus wyomingensis', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 3.0, 450.0, 'epic', 'Pachycephalosaurus is a genus of pachycephalosaurid ornithischian dinosaur. The type species, P. wyomingensis, is the only known definitive species. The possibly synonymous taxon, Stygimoloch, might represent a distinct genus or a second species, P. spinifer. It lived during the Maastrichtian age of the Late Cretaceous period in what is now western North America. Remains have been excavated in Montana, South Dakota, Wyoming, and Alberta. Mainly known from a single skull and a few extremely thick skull roofs (at 22 cm (8.7 in) thick), Pachycephalosaurus is estimated to have reached 4.5 m (15 ft) long and weighed 370–450 kg (820–990 lb). More complete fossils would come to be found in the following years. 
Like other pachycephalosaurids, Pachycephalosaurus was a bipedal herbivore, possessing long, strong legs and somewhat small arms with five-fingered hands.', '[]', 'https://cdn.jacobmaynard.dev/creatures/pachycephalosaurus-wyomingensis.webp', 1.6667);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('8f17f37c09011b66fe8cb', 'Pachyrhinosaurus', 'Pachyrhinosaurus canadensis', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 8.0, 4000.0, 'uncommon', 'Pachyrhinosaurus (from Ancient Greek Παχυ (pachy), thick; ρινό (rinó), nose; and σαυρος (sauros), lizard) is a genus of centrosaurine ceratopsid dinosaur from the Late Cretaceous period of North America. The first examples were discovered by Charles M. Sternberg in Alberta, Canada, in 1946, and named in 1950. Over a dozen partial skulls and a large assortment of other fossils from various species have been found in Alberta and Alaska. A great number were not available for study until the 1980s, resulting in a relatively recent increase of interest in Pachyrhinosaurus.
Three species have been identified. P. lakustai, from the Wapiti Formation, the bonebed horizon of which is roughly equivalent in age to the upper Bearpaw and lower Horseshoe Canyon Formations, is known to have existed from about 73.5–72.5 million years ago. P. canadensis is younger, known from the lower Horseshoe Canyon Formation, about 73–71 Ma ago and the St. Mary River Formation.', '[]', 'https://cdn.jacobmaynard.dev/creatures/pachyrhinosaurus-canadensis.webp', 2.1661);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('2cb36a8f8207ebf48d445', 'Panoplosaurus', 'Panoplosaurus mirus', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 7.0, NULL, 'uncommon', 'Panoplosaurus is a genus of armoured dinosaur from the Late Cretaceous of Alberta, Canada. Few specimens of the genus are known, all from the middle Campanian of the Dinosaur Park Formation, roughly 76 to 75 million years ago. It was first discovered in 1917, and named in 1919 by Lawrence Lambe, named for its extensive armour, meaning "well-armoured lizard". Panoplosaurus has at times been considered the proper name for material otherwise referred to as Edmontonia, complicating its phylogenetic and ecological interpretations, at one point being considered to have existed across Alberta, New Mexico and Texas, with specimens in institutions from Canada and the United States. The skull and skeleton of Panoplosaurus are similar to its relatives, but have a few significant differences, such as the lumpy form of the skull osteoderms, a completely fused shoulder blade, and regularly shaped plates on its neck and body lacking prominent spines.', '[]', 'https://cdn.jacobmaynard.dev/creatures/panoplosaurus-mirus.webp', 3.4091);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('758870911b32cb4e85186', 'Pantydraco', 'Pantydraco caducus', 'Jurassic', 'Early Jurassic', 'Herbivorous', 3.0, NULL, 'common', 'Pantydraco is a genus of basal sauropodomorph dinosaur from the Late Triassic of the United Kingdom (Wales). It is based on a partial juvenile skeleton once thought to belong to Thecodontosaurus. Only one valid species of Pantydraco is recognised: P. caducus.', '[]', 'https://cdn.jacobmaynard.dev/creatures/pantydraco-caducus.webp', 2.1978);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('367f8cb91af8b2e2fe3c6', 'Paralititan', 'Paralititan stromeri', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 28.0, NULL, 'rare', 'Paralititan (meaning "tidal giant") is a genus of sauropod dinosaur that lived in present-day Egypt during the Late Cretaceous period. It was described by American paleontologist Joshua B. Smith and colleagues in 2001. The genus contains a single species, Paralititan stromeri, named based on a fragmentary skeleton including vertebrae and limb bones. These fossils were unearthed by an American expedition to the Bahariya Oasis in western Egypt in rock layers of the Bahariya Formation. This formation dates to the Cenomanian stage of the Late Cretaceous, which lasted 101 to 94 million years ago. An incomplete dorsal (back) vertebra that had been described by German paleontologist Ernst Stromer in 1932 was also assigned to Paralititan. However, this vertebra had been destroyed during the Bombing of Munich in World War II.
Like other sauropods, Paralititan was a four-legged herbivore with a long neck ending in a small head. It was at one point considered one of the largest dinosaurs known.', '[]', 'https://cdn.jacobmaynard.dev/creatures/paralititan-stromeri.webp', 1.8809);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('9f1da2a89c1bf3afafabb', 'Parasaurolophus', 'Parasaurolophus walkeri', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 9.0, 5000.0, 'epic', 'Parasaurolophus (; meaning "beside crested lizard" in reference to Saurolophus) is a genus of hadrosaurid "duck-billed" dinosaur that lived in what is now western North America and possibly Asia during the Late Cretaceous period, about 76.5–73 million years ago. It was a large herbivore that could reach over 9 metres (30 ft) long and weigh over 5 metric tons (5.5 short tons), and were able to move as a biped and a quadruped. Three species are universally recognized: P. walkeri (the type species), P. tubicen, and the short-crested P. cyrtocristatus. Additionally, a fourth species, P. jiayinensis, has been proposed, although it is more commonly placed in the separate genus Charonosaurus. Remains are known from Alberta, New Mexico, and Utah, as well as possibly Heilongjiang if Charonosaurus is in fact part of the genus.', '[]', 'https://cdn.jacobmaynard.dev/creatures/parasaurolophus-walkeri.webp', 2.8708);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('61356431a7a7e17fe826d', 'Parksosaurus', 'Parksosaurus warrenae', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 3.0, NULL, 'common', 'Parksosaurus (meaning "William Parks''s lizard") is a genus of neornithischian dinosaur from the early Maastrichtian-aged (Upper Cretaceous) Horseshoe Canyon Formation of Alberta, Canada. It is based on most of a partially articulated skeleton and partial skull, showing it to have been a small, bipedal, herbivorous dinosaur. It is one of the few described non-hadrosaurid ornithopods from the end of the Cretaceous in North America, existing around 70 million years ago.', '[]', 'https://cdn.jacobmaynard.dev/creatures/parksosaurus-warrenae.webp', 2.9557);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('0cde94592ec4337258bfc', 'Patagosaurus', 'Patagosaurus fariasi', 'Jurassic', NULL, 'Herbivorous', 18.0, NULL, 'rare', 'Patagosaurus (meaning "Patagonia lizard") is an extinct genus of eusauropod dinosaur from the middle Toarcian of Patagonia, Argentina. It was first found in deposits of the Cañadón Asfalto Formation, which date to around 178 million years ago. Although originally twelve specimens were assigned to the taxon, at least one of them may belong to a different genus. Patagosaurus probably lived alongside genera such as Piatnitzkysaurus, Condorraptor, and Volkheimeria.
Since Patagosaurus is known from many specimens, including at least one juvenile, its anatomy and growth are fairly well understood. Both ages exhibit the typical features of a sauropod: a long neck, small head, a long tail, and quadrupedal stance. The juvenile exhibits features different from the adult in regions like the mandible, pectoral girdle, pelvis, and hindlimb, although overall their anatomy is quite similar. The many known specimens help fill in gaps in the anatomy of the genus, such as the forelimb and skull.', '[]', 'https://cdn.jacobmaynard.dev/creatures/patagosaurus-fariasi.webp', 0.75);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('e30e68c708857098cb921', 'Pelicanimimus', 'Pelicanimimus polyodon', 'Cretaceous', 'Early Cretaceous', 'Carnivorous', 2.5, NULL, 'common', 'Pelecanimimus (meaning "pelican mimic") is an extinct genus of basal ("primitive") ornithomimosaurian dinosaur from the Early Cretaceous of Spain. It is notable for possessing more teeth than any other member of the Ornithomimosauria (or any other theropod), most of which were toothless.', '[]', 'https://cdn.jacobmaynard.dev/creatures/pelicanimimus-polyodon.webp', 1.3216);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('312bf2823774aae24fe4f', 'Pelorosaurus', 'Pelorosaurus conybearei', 'Cretaceous', 'Early Cretaceous', 'Herbivorous', 25.0, NULL, 'rare', 'Pelorosaurus is a genus of titanosauriform sauropod dinosaur. Remains referred to Pelorosaurus date from the Early Cretaceous period, about 140–125 million years ago, and have been found in England. Thomas Holtz estimated its length at 24 m (79 ft). The name Pelorosaurus was one of the first to be given to any sauropod. Many species have been assigned to the genus historically, but most are currently considered to belong to other genera. Problematically, the first named species of Pelorosaurus, P. conybeari, is a junior synonym of Cetiosaurus brevis (now Pelorosaurus brevis).', '[]', 'https://cdn.jacobmaynard.dev/creatures/pelorosaurus-conybearei.webp', 1.2409);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('21ef47caf403ff01dd804', 'Pentaceratops', 'Pentaceratops sternbergi', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 6.8, NULL, 'uncommon', 'Pentaceratops ("five-horned face") is a genus of herbivorous ceratopsid dinosaur from the late Cretaceous Period of what is now North America. Fossils of this animal were first discovered in 1921, but the genus was named in 1923 when its type species, Pentaceratops sternbergii, was described. Pentaceratops lived around 76–73 million years ago, its remains having been mostly found in the Kirtland Formation in the San Juan Basin in New Mexico. Another species, P. aquilonius, was named by Nick W. Longrich in 2014, but it is debated if it belongs to that genus or a separate taxon. About a dozen skulls and skeletons have been uncovered, so anatomical understanding of Pentaceratops is fairly complete.', '[]', 'https://cdn.jacobmaynard.dev/creatures/pentaceratops-sternbergi.webp', 1.5707);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('5bbb7d33c8f4f63e5782e', 'Piatnitzkysaurus', 'Piatnitzkysaurus floresi', 'Jurassic', 'Late Jurassic', 'Carnivorous', 4.2, NULL, 'common', 'Piatnitzkysaurus is a genus of tetanuran theropod dinosaur that lived approximately 179 to 177 million years ago during the lower part of the Jurassic Period in what is now Argentina. Piatnitzkysaurus was a moderately large, lightly built, bipedal, ground-dwelling carnivore that could grow over 4 m (13.1 ft) long.', '[]', 'https://cdn.jacobmaynard.dev/creatures/piatnitzkysaurus-floresi.webp', 0.75);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('7071f47e181a1803c7c1c', 'Pinacosaurus', 'Pinacosaurus grangeri', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 5.0, 1000.0, 'common', 'Pinacosaurus (meaning "Plank lizard") is a genus of ankylosaurid thyreophoran dinosaur that lived in Asia during the Late Cretaceous (Campanian, roughly 75 to 71 million years ago), mainly in Mongolia and China.
The first remains of the genus were found in 1923, and the type species Pinacosaurus grangeri was named in 1933. Pinacosaurus mephistocephalus named in 1999, is a second possibly valid species differing from the type species in details of the skull armour. At least 24 Pinacosaurus skeletons have been found, possibly more than of any other ankylosaur. These predominantly consist of juveniles. Adult fossils have not been found in groups.
Pinacosaurus was a medium-sized ankylosaurine, about 5 metres (16 ft) long and weighed up to 1.9 metric tons (2.1 short tons). Its body was flat and low-slung but not as heavily built as in some other members of the Ankylosaurinae. The head was protected by bone tiles, hence its name.', '[]', 'https://cdn.jacobmaynard.dev/creatures/pinacosaurus-grangeri.webp', 1.5345);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('48b2061a3dff8f81461dc', 'Plateosaurus', 'Plateosaurus engelhardti', 'Triassic', 'Late Triassic', 'Herbivorous', 7.0, 4000.0, 'uncommon', 'Plateosaurus (probably meaning "broad lizard", often mistranslated as "flat lizard") is a genus of plateosaurid dinosaur that lived during the Late Triassic epoch of the Triassic period, around 214 to 204 million years ago, in what is now Central and Northern Europe. Plateosaurus is a basal (early) sauropodomorph dinosaur, a so-called "prosauropod". The type species is Plateosaurus trossingensis; before 2019, that honor was given to Plateosaurus engelhardti, but it was ruled as undiagnostic (i.e. indistinguishable from other dinosaurs) by the ICZN. Currently, there are three valid species; in addition to P. trossingensis, P. longiceps and P. gracilis are also known. However, others have been assigned in the past, and there is no broad consensus on the species taxonomy of plateosaurid dinosaurs.', '[]', 'https://cdn.jacobmaynard.dev/creatures/plateosaurus-engelhardti.webp', 1.6807);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('b82ee879e59b434eddcba', 'Podokesaurus', 'Podokesaurus holyokensis', 'Jurassic', NULL, 'Carnivorous', 0.9, NULL, 'common', 'Podokesaurus is a genus of coelophysoid dinosaur that lived in what is now the eastern United States during the Early Jurassic Period. The first fossil was discovered by the geologist Mignon Talbot near Mount Holyoke, Massachusetts, in 1910. The specimen was fragmentary, preserving much of the body, limbs, and tail. In 1911, Talbot described and named the new genus and species Podokesaurus holyokensis based on it. The full name can be translated as "swift-footed lizard of Holyoke". This discovery made Talbot the first woman to find and describe a non-bird dinosaur. The holotype fossil was recognized as significant and was studied by other researchers, but was lost when the building it was kept in burned down in 1917; no unequivocal Podokesaurus specimens have since been discovered.', '[]', 'https://cdn.jacobmaynard.dev/creatures/podokesaurus-holyokensis.webp', 2.2059);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('02c4342da9080c6e79aa8', 'Poekilopleuron', 'Poekilopleuron bucklandii', 'Jurassic', NULL, 'Carnivorous', 9.0, NULL, 'uncommon', 'Poekilopleuron (meaning "varied ribs") is a genus of carnosaurian theropod dinosaur, which lived during the middle Bathonian of the Jurassic, about 168 to 166 million years ago. The genus has been used under many different spelling variants, although only one, Poekilopleuron, is valid. The type species is P. bucklandii, named after William Buckland, and many junior synonyms of it have also been erected. Little material is currently known, as the holotype was destroyed in World War II, although many casts of the material still exist.', '[]', 'https://cdn.jacobmaynard.dev/creatures/poekilopleuron-bucklandii.webp', 2.1978);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('39b7bc16f4d564eef2aec', 'Polacanthus', 'Polacanthus foxii', 'Cretaceous', 'Early Cretaceous', 'Herbivorous', 5.0, NULL, 'common', 'Polacanthus is an extinct genus of ankylosaurian dinosaurs from the early Cretaceous (130–125 million years ago) of England. Several species have been named in the genus Polacanthus, but only the type species, Polacanthus foxii, is currently seen as valid. There are not many fossil remains of this dinosaur, and some important anatomical features, such as its skull, are poorly known. It grew to about 4–5 metres (13–16 ft) long. Its body was covered with armour plates and spikes. It may be a basal member of the Nodosauridae or part of a separate family, the Polacanthidae.', '[]', 'https://cdn.jacobmaynard.dev/creatures/polacanthus-foxii.webp', 1.4095);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('4bd4b26d52a6f414e652b', 'Prenocephale', 'Prenocephale prenes', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 2.4, NULL, 'common', 'Prenocephale (meaning "sloping head") is a genus of small pachycephalosaurid dinosaur from the Late Cretaceous Nemegt Formation of Mongolia. It was similar in many ways to its close relative, Homalocephale.', '[]', 'https://cdn.jacobmaynard.dev/creatures/prenocephale-prenes.webp', 2.8037);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('c5f3ed95caadebee329cb', 'Probactrosaurus', 'Probactrosaurus gobiensis', 'Cretaceous', 'Early Cretaceous', 'Herbivorous', 6.0, NULL, 'uncommon', 'Probactrosaurus (meaning "before Bactrosaurus") is an extinct genus of basal hadrosauroid iguanodontian dinosaur that lived in China during the Early Cretaceous period.', '[]', 'https://cdn.jacobmaynard.dev/creatures/probactrosaurus-gobiensis.webp', 1.1009);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('87ef90137e2c856fc5a06', 'Proceratosaurus', 'Proceratosaurus bradleyi', 'Jurassic', NULL, 'Carnivorous', 4.1, NULL, 'common', 'Proceratosaurus is a genus of theropod dinosaur that lived during the Middle Jurassic in what is now England. The holotype and only known specimen consists of a mostly complete skull with an accompanying lower jaw and a hyoid bone, found near Minchinhampton, a town in Gloucestershire. It was originally described in 1910 as a species of Megalosaurus, M. bradleyi, but was moved to its own genus, Proceratosaurus, in 1926. The genus was named for its supposed close relationship with Ceratosaurus, later shown to be erroneous, due to perceived resemblance of Proceratosaurus''s incomplete cranial crest to Ceratosaurus''s nasal horn.
A small to medium-sized dinosaur, the skull of Proceratosaurus is 26.9 cm (10.6 in) long as preserved, and the dinosaur is estimated to have measured around 3 metres (10 ft) in length.', '[]', 'https://cdn.jacobmaynard.dev/creatures/proceratosaurus-bradleyi.webp', 0.7937);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('d769310dae4f22e40d17f', 'Procompsognathus', 'Procompsognathus triassicus', 'Triassic', 'Late Triassic', 'Carnivorous', 1.0, NULL, 'rare', 'Procompsognathus is an extinct genus of coelophysid theropod dinosaur that lived approximately 210 million years ago during the later part of the Triassic Period, in what is now Germany. Procompsognathus was a small-sized, lightly built, ground-dwelling, bipedal carnivore, that could grow up to 1 m (3.3 ft) long.', '[]', 'https://cdn.jacobmaynard.dev/creatures/procompsognathus-triassicus.webp', 1.3333);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('b32acbe3ce81a224ea5ba', 'Prosaurolophus', 'Prosaurolophus maximus', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 7.6, NULL, 'uncommon', 'Prosaurolophus (; meaning "before Saurolophus", in comparison to the later dinosaur with a similar head crest) is a genus of hadrosaurid (or duck-billed) dinosaur from the Late Cretaceous of North America. It is known from the remains of at least 25 individuals, including skulls and skeletons, but this remains obscure. Its fossils have been found in the late Campanian-aged Dinosaur Park Formation in Alberta, and the roughly contemporaneous Two Medicine Formation in Montana, dating to around 75.7 to 74.1 million years ago. Its most recognizable feature is a small solid crest formed by the nasal bones, sticking up in front of the eyes. The type species is P. maximus, described by American paleontologist Barnum Brown of the American Museum of Natural History in 1916. A second species, P. blackfeetensis, was described by Jack Horner of the Museum of the Rockies in 1992. However, subsequent research has found P. blackfeetensis to be synonymous with P. maximus making the genus monotypic.', '[]', 'https://cdn.jacobmaynard.dev/creatures/prosaurolophus-maximus.webp', 1.3953);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('faaada05aab585e47c838', 'Protarchaeopteryx', 'Protarchaeopteryx robusta', 'Cretaceous', 'Early Cretaceous', 'Carnivorous', 2.0, NULL, 'legendary', 'Protarchaeopteryx (meaning "before Archaeopteryx" although it is from the Cretaceous and Archaeopteryx is from the Jurassic) is a genus of turkey-sized feathered theropod dinosaur from China. Known from the Jianshangou bed of the Yixian Formation, it lived during the early Aptian age of the Early Cretaceous, approximately 124.6 million years ago. It was probably a herbivore or omnivore, although its hands were very similar to those of small carnivorous dinosaurs. It appears to be one of the most basal members of the Oviraptorosauria, closely related to Incisivosaurus, or a taxon slightly less closely related to birds than oviraptorosaurs were.', '[]', 'https://cdn.jacobmaynard.dev/creatures/protarchaeopteryx-robusta.webp', 1.0);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('365205dc9a01f366cf580', 'Protoceratops', 'Protoceratops andrewsi', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 1.8, 400.0, 'common', 'Protoceratops is a genus of small protoceratopsid dinosaurs that lived in Asia during the Late Cretaceous, around 75 to 71 million years ago. The genus Protoceratops includes two species: P. andrewsi and the larger P. hellenikorhinus. The former was described in 1923 with fossils from the Mongolian Djadokhta Formation, and the latter in 2001 with fossils from the Chinese Bayan Mandahu Formation. Protoceratops was initially believed to be an ancestor of ankylosaurians and larger ceratopsians, such as Triceratops and relatives, until the discoveries of other protoceratopsids. Populations of P. andrewsi may have evolved into Bagaceratops rozhdestvenskyi through anagenesis.
Protoceratops were small ceratopsians, up to 2–2.5 m (6.6–8.2 ft) long and around 62–104 kg (137–229 lb) in body mass. While adults were largely quadrupedal, juveniles had the capacity to walk around bipedally if necessary.', '[]', 'https://cdn.jacobmaynard.dev/creatures/protoceratops-andrewsi.webp', 2.0);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('00dd762949faeba57bc03', 'Protohadros', 'Protohadros byrdi', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 6.0, NULL, 'uncommon', 'Protohadros (meaning "first hadrosaur") is a genus of herbivorous ornithopod dinosaur from the Late Cretaceous (Cenomanian stage) of what is now North America.
Gary Byrd, a part-time palaeontologist, discovered some remains of this euornithopod (ribs and an ungual) during early 1994 at Flower Mound, Denton County, north-central Texas. He informed professional palaeontologist Yuong-Nam Lee of the find, who arranged for the entire preserved fossil to be excavated. It was first reported upon in 1996 by Jason Head of the Dedman College of Humanities and Sciences, Southern Methodist University. The type species Protohadros byrdi was described and named by Head in 1998. The genus name is derived from Greek πρῶτος, protos, "first", en ἁδρός, hadros, "thick", a reference to the fact that Head considered the species the oldest known hadrosaur.', '[]', 'https://cdn.jacobmaynard.dev/creatures/protohadros-byrdi.webp', 1.0545);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('5f20b0fd353a961d83a2b', 'Psittacosaurus', 'Psittacosaurus mongoliensis', 'Cretaceous', 'Early Cretaceous', 'Herbivorous', 2.0, NULL, 'common', 'Psittacosaurus is a genus of extinct ceratopsian dinosaur from the Early Cretaceous of what is now Asia, existing between 125 and 105 million years ago. It is notable for being the most species-rich non-avian dinosaur genus. Up to 13 species are known, from across China, Mongolia, Russia, and Thailand. The species of Psittacosaurus were obligate bipeds at adulthood, with a high skull and a robust beak. One individual was found preserved with long filaments on the tail, similar to those of Tianyulong. Psittacosaurus probably had complex behaviours, based on the proportions and relative size of the brain. It may have been active for short periods of time during the day and night, and had well-developed senses of smell and vision.
Psittacosaurus was one of the earliest ceratopsians, but closer to Triceratops than Yinlong.', '[]', 'https://cdn.jacobmaynard.dev/creatures/psittacosaurus-mongoliensis.webp', 1.4528);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('38142a939240aa97e7250', 'Quaesitosaurus', 'Quaesitosaurus orientalis', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 23.0, NULL, 'rare', 'Quaesitosaurus (meaning "extraordinary lizard") is a genus of nemegtosaurid sauropod containing only the type species, Q. orientalis, described in 1983. It lived from 72 to 71 million years ago during the Late Cretaceous epoch in the Barun Goyot Formation. With long, low and horse-like with frontally located peg-teeth, the skull of Quaesitosaurus is similar enough to the skull of Diplodocus and its kin to have prompted informed speculation that the missing body was built like those of diplodocids.', '[]', 'https://cdn.jacobmaynard.dev/creatures/quaesitosaurus-orientalis.webp', 1.3483);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('1be6369b1a44d794e7ee9', 'Rebbachisaurus', 'Rebbachisaurus garasbae', 'Cretaceous', 'Early Cretaceous', 'Herbivorous', 20.0, NULL, 'rare', 'Rebbachisaurus (meaning "Aït Rebbach lizard") is a genus of sauropod dinosaur of the superfamily Diplodocoidea, that lived during the Late Cretaceous period in Africa and possibly also South America about 99-97 million years ago. Remains attributed to Rebbachisaurus have been found in Morocco, Niger, Algeria, Tunisia, and possibly also Argentina (if Rayososaurus is the same animal as Rebbachisaurus), although only the Moroccan remains can be referred to the genus without doubt. The discovery of Rayososaurus, a South American sauropod nearly identical to Rebbachisaurus which may have actually been the same animal, supports the theory that there was still a land connection between Africa and South America during the Early Cretaceous, long after it was commonly thought the two continents had separated.', '[]', 'https://cdn.jacobmaynard.dev/creatures/rebbachisaurus-garasbae.webp', 2.4463);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('714ae77a5055561399833', 'Rhabdodon', 'Rhabdodon priscus', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 4.0, NULL, 'rare', 'Rhabdodon (meaning "fluted tooth") is a genus of ornithopod dinosaur that lived in Europe approximately 72-69 million years ago in the Late Cretaceous. The genus contains a single species, R. priscus. It is similar in build to a very robust "hypsilophodont" (non-iguanodont ornithopod), though all modern phylogenetic analyses find this to be an unnatural grouping, and Rhabdodon to be a basal member of Iguanodontia. It was large amongst its relatives, measuring 4 m (13 ft) long and weighing 250 kg (550 lb), with some specimens possibly reaching up to 6 m (20 ft) long.', '[]', 'https://cdn.jacobmaynard.dev/creatures/rhabdodon-priscus.webp', 1.5);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('f29a98b5e5f55789723c3', 'Rhoetosaurus', 'Rhoetosaurus brownei', 'Jurassic', NULL, 'Herbivorous', 15.0, NULL, 'uncommon', 'Rhoetosaurus (meaning "Rhoetus lizard", after a titan in Greek mythology) is a genus of sauropod dinosaur from the Late Jurassic (Oxfordian) Walloon Coal Measures of what is now eastern Australia. Rhoetosaurus is estimated to have been about 15 metres (49 ft) long, weighing about 9 tonnes (8.9 long tons; 9.9 short tons). Subsequent authors have sometimes misspelled the name: Rhaetosaurus (de Lapparent & Laverat, 1955); Rheteosaurus (Yadagiri, Prasad & Satsangi, 1979).', '[]', 'https://cdn.jacobmaynard.dev/creatures/rhoetosaurus-brownei.webp', 2.5);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('fc7177bf09651218034c3', 'Rinchenia', 'Rinchenia mongoliensis', 'Cretaceous', 'Late Cretaceous', 'Omnivorous', 2.5, NULL, 'common', 'Rinchenia (named after Byambyn Rinchen) is a genus of oviraptorid dinosaur that lived in Asia during the Late Cretaceous epoch in what is now Mongolia, Nemegt Formation, around 70 million years ago. The type and only known species, Rinchenia mongoliensis, was originally classified as a species within the genus Oviraptor (named Oviraptor mongoliensis), but a subsequent reexamination found differences significant enough to warrant a separate genus. The name Rinchenia was coined for this new genus, though not formally described in detail.', '[]', 'https://cdn.jacobmaynard.dev/creatures/rinchenia-mongoliensis.webp', 1.3575);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('c667e35f77f2f52c2c210', 'Riojasaurus', 'Riojasaurus incertus', 'Triassic', 'Late Triassic', 'Herbivorous/omnivorous', 5.2, NULL, 'uncommon', 'Riojasaurus (meaning "lizard from La Rioja") was a herbivorous sauropodomorph dinosaur named after La Rioja Province in Argentina where it was found in the Los Colorados Formation in the Ischigualasto-Villa Unión Basin by José Bonaparte. It lived during the Late Triassic (Norian stage) and grew to about 6.6 metres (22 ft) long. Riojasaurus is the only known riojasaurid to live in South America.', '[]', 'https://cdn.jacobmaynard.dev/creatures/riojasaurus-incertus.webp', 1.9868);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('d212b3eeda3ff93463a37', 'Rugops', 'Rugops primus', 'Cretaceous', 'Late Cretaceous', 'Carnivorous', 7.0, NULL, 'uncommon', 'Rugops (meaning ''wrinkle face'') is a monospecific genus of basal abelisaurid theropod dinosaur that lived during the Late Cretaceous period (Cenomanian stage, approximately 95 million years ago) in what is now the Echkar Formation in Niger. The type and only species, Rugops primus, is known only from a partial skull. It was named and described in 2004 by Paul Sereno, Jeffery Wilson and Jack Conrad. Rugops has an estimated length of 4.4–5.3 metres (14–17 ft) and weight of 410 kilograms (900 lb). The top of its skull bears several pits which correlates with overlaying scale and the front of the snout would have had an armour-like dermis.', '[]', 'https://cdn.jacobmaynard.dev/creatures/rugops-primus.webp', 2.7149);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('519aecd65d119d48e7140', 'Saichania', 'Saichania chulsanensis', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 6.6, NULL, 'uncommon', 'Saichania (Mongolian meaning "beautiful one") is a genus of herbivorous ankylosaurid dinosaur from the Late Cretaceous period of Mongolia and China. The first fossils of Saichania were found in the early 1970s in the Baruungoyot Formation. In 1977, the type species Saichania chulsanensis was named.
Saichania is more robustly built than other members of the Ankylosauridae, measuring 5–7 metres (16–23 ft) in length and 1.4–2.0 metric tons (1.5–2.2 short tons) in body mass. Neck vertebrae, the shoulder girdle, and ribs were fused or firmly connected. Its body is flat and low-slung, standing on four short legs. The forelimbs were very powerful. The head was protected by bulbous armour tiles. It could defend itself against predators like Tarbosaurus with a tail club. On the torso, keeled osteoderms were present. Saichania bit off plants in its desert habitat with a horny beak and processed them in its wide hindgut.', '[]', 'https://cdn.jacobmaynard.dev/creatures/saichania-chulsanensis.webp', 1.3333);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('d7ee9699615e6e033dbf0', 'Saltasaurus', 'Saltasaurus loricatus', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 12.0, NULL, 'uncommon', 'Saltasaurus (which means "lizard from Salta") is a genus of saltasaurid dinosaur of the Late Cretaceous period of Argentina. Small among sauropods, though still heavy by the standards of modern creatures, Saltasaurus was characterized by a short neck and stubby limbs. It was the first genus of sauropod known to possess armour of bony plates embedded in its skin. Such small bony plates, called osteoderms, have since been found on other titanosaurians.', '[]', 'https://cdn.jacobmaynard.dev/creatures/saltasaurus-loricatus.webp', 2.3346);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('b98c6465c8490ad88d7ad', 'Saltopus', 'Saltopus elginensis', 'Triassic', 'Late Triassic', 'Carnivorous', NULL, NULL, 'common', 'Saltopus ("hopping foot") is a genus of very small bipedal dinosauriform containing the single species Saltopus elginensis from the late Triassic period of Scotland. It is one of the most famous Elgin Reptiles.', '[]', 'https://cdn.jacobmaynard.dev/creatures/saltopus-elginensis.webp', 1.9544);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('2f68b82f53f0253551e31', 'Sarcosaurus', 'Sarcosaurus woodi', 'Jurassic', 'Early Jurassic', 'Carnivorous', 3.0, NULL, 'common', 'Sarcosaurus (Latin: "flesh lizard") is a genus of basal neotheropod dinosaur, roughly 3.5 metres (11 ft) long. It lived in what is now England and maybe Ireland and Scotland during the Hettangian-Sinemurian stages of the Early Jurassic, about 199-196 million years ago. Sarcosaurus is one of the earliest known Jurassic theropods, and one of only a handful of theropod genera from this time period. Along with Dracoraptor hanigani it is one of the two described neotheropods from the lowermost Jurassic of the United Kingdom.', '[]', 'https://cdn.jacobmaynard.dev/creatures/sarcosaurus-woodi.webp', 1.3793);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('e7108db50e0135ebab521', 'Saurolophus', 'Saurolophus osborni', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 9.0, NULL, 'uncommon', 'Saurolophus (; meaning "lizard crest") is a genus of large hadrosaurid dinosaur that lived during the Late Cretaceous period of North America and Asia, in what is now the Horseshoe Canyon and Nemegt formations respectively (about 70 to 66 million years ago). It is one of the few dinosaur genera known from multiple continents. The type species, S. osborni, was described by Barnum Brown in 1912 from Canadian fossils. A second valid species, S. angustirostris, is represented by numerous specimens from Mongolia, and was described by Anatoly Konstantinovich Rozhdestvensky. Saurolophus is distinguished by a spike-like crest which projects up and back from the skull. It was a herbivorous dinosaur which could move either bipedally or quadrupedally.', '[]', 'https://cdn.jacobmaynard.dev/creatures/saurolophus-osborni.webp', 2.8037);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('490e2e5eef23dd904082e', 'Sauropelta', 'Sauropelta edwardsorum', 'Cretaceous', 'Early Cretaceous', 'Herbivorous', 6.5, NULL, 'uncommon', 'Sauropelta is a genus of nodosaurid dinosaur that existed in the Early Cretaceous Period of North America. One species (S. edwardsorum) has been named. Anatomically, Sauropelta is one of the most well-understood nodosaurids, with fossilized remains recovered in the U.S. states of Wyoming, Montana, and possibly Utah. It is also the earliest known genus of nodosaurine; most of its remains are found in a section of the Cloverly Formation dated to 108.5 million years ago.
Sauropelta is a medium-sized nodosaurid, measuring about 5.2–6 metres (17.1–19.7 ft) long. Sauropelta had a distinctively long tail which made up about half of its body length. Although its body was smaller than a modern black rhinoceros, Sauropelta was about the same mass, weighing up to about 1.5–2 metric tons (1.7–2.2 short tons). The extra weight was largely due to its extensive covering of bony armor, including the characteristically large spines projecting from its neck.', '[]', 'https://cdn.jacobmaynard.dev/creatures/sauropelta-edwardsorum.webp', 2.9126);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('b41151dd4bd2a55f9e019', 'Saurophaganax', 'Saurophaganax maximus', 'Jurassic', 'Late Jurassic', 'Carnivorous', 12.0, NULL, 'uncommon', 'Saurophaganax ("lord of lizard-eaters") is a dubious, chimeric genus of large saurischian dinosaur, possibly a sauropod, from the Late Jurassic (Kimmeridgian) Morrison Formation of Oklahoma, United States. This taxon was historically considered to represent a species of Allosaurus or very large allosaurid. However, re-examinations of the attributed specimens suggested that it is a chimera of multiple dinosaur genera, since some specimens most likely belong to a diplodocid sauropod, while the other referred specimens could be reassigned to a novel species of Allosaurus.', '[]', 'https://cdn.jacobmaynard.dev/creatures/saurophaganax-maximus.webp', 1.9868);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('59da9b4a64e814b247117', 'Saurornithoides', 'Saurornithoides mongoliensis', 'Cretaceous', 'Late Cretaceous', 'Carnivorous', 3.0, NULL, 'common', 'Saurornithoides is a genus of troodontid maniraptoran dinosaur, which lived during the Late Cretaceous period. These creatures were predators, which could run fast on their hind legs and had excellent sight and hearing. The name is derived from the Greek stems saur~ (lizard), ornith~ (bird) and eides (form), referring to its bird-like skull.', '[]', 'https://cdn.jacobmaynard.dev/creatures/saurornithoides-mongoliensis.webp', 1.467);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('099e6c319347abfeaef0a', 'Scelidosaurus', 'Scelidosaurus harrisonii', 'Jurassic', 'Early Jurassic', 'Herbivorous', 4.0, NULL, 'common', 'Scelidosaurus is a genus of herbivorous armoured ornithischian dinosaur from the Jurassic of England.
Scelidosaurus lived during the Early Jurassic Period, during the Sinemurian to Pliensbachian stages around 191 million years ago, at the time when Europe formed an island archipelago. Its fossils have been found in the Charmouth Mudstone Formation near Charmouth in Dorset, England, and these fossils are known for their excellent preservation. Scelidosaurus has been claimed as one of the earliest complete dinosaurs, and is among the most completely known dinosaur of the British Isles. Despite this, a modern description only materialised in 2020. After initial finds in the 1850s, comparative anatomist Richard Owen named and described Scelidosaurus in 1859.', '[]', 'https://cdn.jacobmaynard.dev/creatures/scelidosaurus-harrisonii.webp', 1.5831);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('32419e01ca328076cee94', 'Scutellosaurus', 'Scutellosaurus lawleri', 'Jurassic', 'Early Jurassic', 'Herbivorous', 1.2, NULL, 'common', 'Scutellosaurus is a genus of basal thyreophoran dinosaur that lived approximately 196 million years ago during the early part of the Jurassic Period in what is now Arizona, USA. It is classified in Thyreophora, the armoured dinosaurs; its closest relatives may have been Emausaurus and Scelidosaurus, another armored dinosaur which was mainly a quadrupedal dinosaur, unlike bipedal Scutellosaurus. It is one of the earliest representatives of the armored dinosaurs and the basalmost form discovered to date. Scutellosaurus was a small, lightly-built, ground-dwelling herbivore, that could grow up to an estimated 1.3 metres (4.3 ft) long.', '[]', 'https://cdn.jacobmaynard.dev/creatures/scutellosaurus-lawleri.webp', 0.7438);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('8d9429859d7872d3184af', 'Secernosaurus', 'Secernosaurus koerneri', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 3.0, NULL, 'common', 'Secernosaurus (meaning "severed lizard") is a genus of herbivorous hadrosaurid dinosaur that lived during the Late Cretaceous of what is now Argentina. This genus and its close relatives lived in South America, unlike most hadrosaurids, which lived in the Laurasian continents of Eurasia and North America. It has been suggested that the ancestors of Secernosaurus crossed into South America when a land bridge temporarily formed between North and South America during the Late Cretaceous and allowed biotic interchange between the two continents.', '[]', 'https://cdn.jacobmaynard.dev/creatures/secernosaurus-koerneri.webp', 2.4194);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('53f17855cb1d6bd5121f3', 'Segisaurus', 'Segisaurus halli', 'Jurassic', NULL, 'Carnivorous', 1.5, NULL, 'common', 'Segisaurus (meaning "Tsegi Canyon lizard") is a genus of small coelophysid theropod dinosaur, that measured approximately 1 metre (3.3 feet) in length. The only known specimen was discovered in early Jurassic strata in Tsegi Canyon, Arizona, for which it was named. Segisaurus is the only dinosaur to have ever been excavated from the area.', '[]', 'https://cdn.jacobmaynard.dev/creatures/segisaurus-halli.webp', 2.5751);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('0f8a4bcabc2228afb0752', 'Segnosaurus', 'Segnosaurus galbinensis', 'Cretaceous', 'Late Cretaceous', 'Carnivorous', 4.0, NULL, 'common', 'Segnosaurus is a genus of therizinosaurid dinosaur that lived in what is now southeastern Mongolia during the Late Cretaceous, about 102–86 million years ago. Multiple incomplete but well-preserved specimens were discovered in the Gobi Desert in the 1970s, and in 1979 the genus and species Segnosaurus galbinensis were named. The generic name Segnosaurus means "slow lizard" and the specific name galbinensis refers to the Galbin region. The known material of this dinosaur includes the lower jaw, neck and tail vertebrae, the pelvis, shoulder girdle, and limb bones. Parts of the specimens have gone missing or become damaged since they were collected. Remains from Japan originally assigned to Allosaurus were reassigned to Segnosaurus sp. (of unspecified species) in 2025.
Segnosaurus was a large-bodied therizinosaur that is estimated to have been about 6–7 m (20–23 ft) long and to have weighed about 1.3 t (1.4 short tons).', '[]', 'https://cdn.jacobmaynard.dev/creatures/segnosaurus-galbinensis.webp', 1.1788);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('a2b078f559af05959962f', 'Shamosaurus', 'Shamosaurus scutatus', 'Cretaceous', 'Early Cretaceous', 'Herbivorous', NULL, NULL, 'common', 'Shamosaurus is an extinct genus of herbivorous basal ankylosaurid ankylosaur from Early Cretaceous (Aptian to Albian stage) deposits of Höövör, Mongolia.', '[]', 'https://cdn.jacobmaynard.dev/creatures/shamosaurus-scutatus.webp', 1.1583);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('6975b86e1dbe76c9a4429', 'Shanag', 'Shanag ashile', 'Cretaceous', 'Early Cretaceous', 'Carnivorous', 0.5, NULL, 'common', 'Shanag is a genus of paravian theropod dinosaur from the Early Cretaceous Period of Mongolia. It may be a dromaeosaurid, but some researchers are skeptical of this classification. The type species is S. ashile.', '[]', 'https://cdn.jacobmaynard.dev/creatures/shanag-ashile.webp', 2.6201);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('17414182a9f7c047c8d2f', 'Shantungosaurus', 'Shantungosaurus giganteus', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 15.0, NULL, 'uncommon', 'Shantungosaurus is a genus of very large saurolophine hadrosaurid dinosaur found in the Late Cretaceous Wangshi Group of the Shandong Peninsula in China, containing a single species, Shantungosaurus giganteus. The stratigraphic interval of Shantungosaurus ranges from the top of the Xingezhuang Formation to the middle of the Hongtuya Formation, middle to late Campanian in age. Shantungosaurus is so far the largest hadrosauroid taxon in the world, with size estimates around 15–17 metres (49–56 ft) in length and 13–16 metric tons (14–18 short tons) in body mass.', '[]', 'https://cdn.jacobmaynard.dev/creatures/shantungosaurus-giganteus.webp', 2.1739);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('6e29f263882c3619e1286', 'Shunosaurus', 'Shunosaurus lii', 'Jurassic', NULL, 'Herbivorous', 10.0, NULL, 'uncommon', 'Shunosaurus is a genus of sauropod dinosaur from Late Jurassic (Oxfordian) beds in Sichuan Province in China, from 161 to 157 Million years ago. The name derives from "Shu", an ancient name for the Sichuan province.', '[]', 'https://cdn.jacobmaynard.dev/creatures/shunosaurus-lii.webp', 1.7751);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('d53d69d75e426d539edd4', 'Shuvuuia', 'Shuvuuia deserti', 'Cretaceous', 'Late Cretaceous', 'Omnivorous', 0.6, NULL, 'common', 'Shuvuuia is a genus of bird-like theropod dinosaur from the late Cretaceous period of Mongolia. It is a member of the family Alvarezsauridae, small coelurosaurian dinosaurs which are characterized by short but powerful forelimbs specialized for digging. The type (and only known) species is Shuvuuia deserti, or "desert bird". The name Shuvuuia is derived from the Mongolian word shuvuu (шувуу) meaning "bird".', '[]', 'https://cdn.jacobmaynard.dev/creatures/shuvuuia-deserti.webp', 1.662);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('1e9974e80c67d3788bdba', 'Silvisaurus', 'Silvisaurus condrayi', 'Cretaceous', 'Early Cretaceous', 'Herbivorous', 4.0, NULL, 'common', 'Silvisaurus, from the Latin silva "woodland" and Greek sauros "lizard", is a nodosaurid ankylosaur from the Early to Late Cretaceous period. It is the only known dinosaur species named from terrestrial deposits in Kansas and was designated the official state land fossil in 2023.', '[]', 'https://cdn.jacobmaynard.dev/creatures/silvisaurus-condrayi.webp', 1.9608);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('bba0ef4e3f7170f00b805', 'Sinocalliopteryx', 'Sinocalliopteryx gigas', 'Cretaceous', 'Early Cretaceous', 'Carnivorous', 2.37, NULL, 'common', 'Sinocalliopteryx (meaning ''Chinese beautiful feather'') is a genus of carnivorous coelurosaurian theropod dinosaurs from the Lower Cretaceous Yixian Formation of China (Jianshangou Beds, dating to 124.6 Ma). While similar to the related Huaxiagnathus, Sinocalliopteryx were larger. In 2007, the type specimen was the largest known compsognathid exemplar, at 2.37 metres (7.8 ft) in length. In 2012, an even larger specimen was reported.', '[]', 'https://cdn.jacobmaynard.dev/creatures/sinocalliopteryx-gigas.webp', 1.3333);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('eaa3eb2ac5b8d391648fd', 'Sinornithosaurus', 'Sinornithosaurus millenii', 'Cretaceous', 'Early Cretaceous', 'Carnivorous', 2.0, NULL, 'common', 'Sinornithosaurus (derived from a combination of Latin and Greek, meaning ''Chinese bird-lizard'') is a genus of feathered dromaeosaurid dinosaur from the early Cretaceous Period (late Barremian) of the Yixian Formation in what is now China. It was the fifth non–avian feathered dinosaur genus discovered by 1999. The original specimen was collected from the Sihetun locality of western Liaoning. It was found in the Jianshangou beds of the Yixian Formation, dated to 124.5 million years ago. Additional specimens have been found in the younger Dawangzhangzi bed, dating to around 122 million years ago.
Xu Xing described Sinornithosaurus and performed a phylogenetic analysis which demonstrated that it is basal, or primitive, among the dromaeosaurs. He has also demonstrated that features of the skull and shoulder are very similar to Archaeopteryx and other avialans.', '[]', 'https://cdn.jacobmaynard.dev/creatures/sinornithosaurus-millenii.webp', 1.9737);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('353f4a288008e596391da', 'Sinosauropteryx', 'Sinosauropteryx prima', 'Cretaceous', 'Early Cretaceous', 'Carnivorous', 1.1, NULL, 'common', 'Sinosauropteryx (meaning "Chinese reptilian wing") is an extinct genus of coelurosaurian theropod dinosaurs. Described in 1996, it was the first dinosaur taxon outside of Avialae (birds and their immediate relatives) to be found with evidence of feathers. It was covered with a coat of very simple filament-like feathers. Structures that indicate the colour pattern have also been preserved in some of its feathers, which show that Sinosauropteryx had a countershading pattern in its body with a banded tail. The reddish brown colouration previously inferred for Sinosauropteryx is based on the melanosomes preserved in the specimen of a separate genus, Huadanosaurus. Some contention has arisen with an alternative interpretation of the filamentous impression as remains of collagen fibres, but this has not been widely accepted.
Sinosauropteryx was a small theropod with an unusually long tail and short arms.', '[]', 'https://cdn.jacobmaynard.dev/creatures/sinosauropteryx-prima.webp', 0.6937);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('5450fad5358e288131538', 'Sinovenator', 'Sinovenator changii', 'Cretaceous', 'Early Cretaceous', 'Carnivorous', 1.0, NULL, 'common', 'Sinovenator (meaning "Chinese hunter") is a genus of troodontid dinosaur from China. It is from the early Cretaceous Period.', '[]', 'https://cdn.jacobmaynard.dev/creatures/sinovenator-changii.webp', 2.9557);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('c38dad33ddde89fcc2640', 'Sinraptor', 'Sinraptor hepingensis', 'Jurassic', NULL, 'Carnivorous', 7.6, NULL, 'uncommon', 'Sinraptor () is a genus of metriacanthosaurid theropod dinosaur from the Shishugou Formation China. Sinraptor and its close relatives were among the earliest members of the Jurassic carnosaurian radiation. Sinraptor still remains the best-known member of the family Metriacanthosauridae, with some older sources even using the name "Sinraptoridae" for the family.', '[]', 'https://cdn.jacobmaynard.dev/creatures/sinraptor-hepingensis.webp', 2.381);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('a9386f5c807a562cf3c04', 'Sonidosaurus', 'Sonidosaurus saihangaobiensis', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 9.0, NULL, 'uncommon', 'Sonidosaurus (meaning "Sonid lizard", after Sonid, the large geographical area that includes the type locality) is a genus of sauropod dinosaur from the Late Cretaceous. It was a titanosaur which lived in what is now Inner Mongolia. The type species, Sonidosaurus saihangaobiensis, was described by Xu, Zhang, Tan, Zhao, and Tan in 2006. It was a small titanosaur, about 9 meters (30 ft) long. It was first discovered in the Saihangaobi, Iren Dabasu (Erlian) Formation, in 2001 in a quarry which would later yield the remains of Gigantoraptor.', '[]', 'https://cdn.jacobmaynard.dev/creatures/sonidosaurus-saihangaobiensis.webp', 1.3333);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('8d2d6a354f29a724a74f4', 'Spinosaurus', 'Spinosaurus aegyptiacus', 'Cretaceous', 'Late Cretaceous', 'Carnivorous', 18.0, NULL, 'legendary', 'Spinosaurus is a genus of large spinosaurid theropod dinosaurs that lived in what is now North Africa during the Cenomanian stage of the Late Cretaceous period, about 100 to 94 million years ago. The genus was known first from Egyptian remains discovered in 1912 and described by German palaeontologist Ernst Stromer in 1915. The original remains were destroyed in World War II, but additional material came to light in the early 21st century. It is unclear whether one or two species are represented in the fossils reported in the scientific literature. The type species, S. aegyptiacus, is mainly known from the Bahariya Formation in Egypt and the Kem Kem beds in Morocco. The other species, S. mirabilis, is known from the Farak Formation in Niger. Although another potential species, S. maroccanus, has been recovered from the Kem Kem beds, this dubious species is likely a junior synonym of S. aegyptiacus.', '[]', 'https://cdn.jacobmaynard.dev/creatures/spinosaurus-aegyptiacus.webp', 1.7751);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('b5582fa90b4b0089736c3', 'Staurikosaurus', 'Staurikosaurus pricei', 'Triassic', 'Late Triassic', 'Carnivorous', 2.0, NULL, 'common', 'Staurikosaurus is a genus of herrerasaurid dinosaur from the Late Triassic of Brazil, found in the Santa Maria Formation.', '[]', 'https://cdn.jacobmaynard.dev/creatures/staurikosaurus-pricei.webp', 1.7751);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('5cd1514fc0589b71c4785', 'Stegoceras', 'Stegoceras validum', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 2.4, NULL, 'common', 'Stegoceras is a genus of pachycephalosaurid (dome-headed) dinosaur that lived in what is now North America during the Late Cretaceous period, about 77.5 to 74 million years ago (mya). The first specimens from Alberta, Canada, were described in 1902, and the type species Stegoceras validum was based on these remains. The generic name means "horn roof", and the specific name means "strong". Several other species have been placed in the genus over the years, but these have since been moved to other genera or deemed junior synonyms. Currently only S. validum and S. novomexicanum, named in 2011 from fossils found in New Mexico, remain. The validity of the latter species has also been debated, and it may not even belong to the genus Stegoceras.
Stegoceras was a small, bipedal dinosaur about 2 to 2.5 metres (6.6 to 8.2 ft) long, and weighed around 10 to 40 kilograms (22 to 88 lb).', '[]', 'https://cdn.jacobmaynard.dev/creatures/stegoceras-validum.webp', 1.9934);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('5da306ca1959a51f1c551', 'Stegosaurus', 'Stegosaurus armatus', 'Jurassic', 'Late Jurassic', 'Herbivorous', 9.0, NULL, 'legendary', 'Stegosaurus is a genus of herbivorous four-legged armored dinosaurs from the Late Jurassic, characterized by the distinctive kite-shaped upright plates along their backs and spikes on their tails. Fossils of the genus have been found in the western United States and in Portugal, where they are found in Kimmeridgian- to Tithonian-aged strata, dating to between 155 and 145 million years ago. Of the species that have been classified in the upper Morrison Formation of the western US, only three are universally recognized: S. stenops, S. ungulatus and S. sulcatus. The remains of over 80 individual animals of this genus have been found. Stegosaurus would have lived alongside dinosaurs such as Apatosaurus, Diplodocus, Camarasaurus and Allosaurus, the latter of which may have preyed on it.
They were large, heavily built, herbivorous quadrupeds with rounded backs, short fore limbs, long hind limbs, and tails held high in the air.', '[]', 'https://cdn.jacobmaynard.dev/creatures/stegosaurus-armatus.webp', 2.3346);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('e9eedf7c28d5374824f70', 'Stenopelix', 'Stenopelix valdensis', 'Cretaceous', 'Early Cretaceous', 'Herbivorous', 1.5, NULL, 'common', 'Stenopelix (meaning "narrow pelvis") is a genus of basal ceratopsian from the Early Cretaceous (late Berriasian stage, approximately 140 million years ago) of Germany. The genus is based on a partial skeleton lacking the skull, and its classification is based on characteristics of the hips.', '[]', 'https://cdn.jacobmaynard.dev/creatures/stenopelix-valdensis.webp', 2.459);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('4f5466d020f6f83b19c0c', 'Struthiomimus', 'Struthiomimus altus', 'Cretaceous', 'Late Cretaceous', 'Omnivorous', 4.0, 150.0, 'common', 'Struthiomimus is a genus of ornithomimid dinosaurs from the Late Cretaceous of what is now western North America. They were long-legged, bipedal, ostrich-like dinosaurs with toothless beaks. The type species, Struthiomimus altus, is one of the more common, smaller dinosaurs found in Dinosaur Provincial Park. Their overall abundance, in addition to their toothless beak, suggests that these animals were mainly herbivorous or (more likely) omnivorous, rather than purely carnivorous. Similar to the modern ostriches, emus, and rheas (among other birds), these dinosaurs likely lived as opportunistic omnivores, supplementing a largely plant-based diet with a variety of small mammals, reptiles, amphibians, insects, invertebrates, and anything else they could fit into their mouth, as they foraged.', '[]', 'https://cdn.jacobmaynard.dev/creatures/struthiomimus-altus.webp', 1.5);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('e6b4add6344968bdd2bee', 'Struthiosaurus', 'Struthiosaurus austriacus', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 2.5, NULL, 'common', 'Struthiosaurus (Latin struthio = ostrich + Greek sauros = lizard) is a genus of nodosaurid dinosaurs from the Late Cretaceous period (Santonian-Maastrichtian) of Austria, Romania, France, and possibly Hungary. It was a small dinosaur, measuring 2–3 m (6.6–9.8 ft) in length and weighing 300–400 kg (660–880 lb).', '[]', 'https://cdn.jacobmaynard.dev/creatures/struthiosaurus-austriacus.webp', 1.0471);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('2d99894077c527fb052eb', 'Styracosaurus', 'Styracosaurus albertensis', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 5.5, NULL, 'uncommon', 'Styracosaurus is an extinct genus of herbivorous dinosaur from the Late Cretaceous (Campanian stage) of North America. It had four to six long parietal spikes extending from its neck frill, a smaller jugal horn on each of its cheeks, and a single horn protruding from its nose, which may have been up to 60 centimeters (2 feet) long and 15 centimeters (6 inches) wide. The function or functions of the horns and frills have been debated for many years.
Styracosaurus was a relatively large dinosaur, reaching lengths of 5–5.5 metres (16–18 ft) and weighing about 1.8–2.7 metric tons (2.0–3.0 short tons). It stood about 1.8 meters (5.9 feet) tall. Styracosaurus possessed four short legs and a bulky body. Its tail was rather short.', '[]', 'https://cdn.jacobmaynard.dev/creatures/styracosaurus-albertensis.webp', 1.662);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('9c4a6b0a2a7ca4e37ef3e', 'Suchomimus', 'Suchomimus tenerensis', 'Cretaceous', 'Early Cretaceous', 'Carnivorous', 11.0, NULL, 'uncommon', 'Suchomimus is a genus of large theropod dinosaur that lived in what is now Niger during the Albian to Aptian stages of the Early Cretaceous period, 112 million years ago. The only known species is S. tenerensis, originally described in 1998 by paleontologist Paul Sereno and colleagues from several fossils discovered one year earlier in the Elrhaz Formation. Although these fossils come from multiple specimens, they represent one of the most anatomically well-documented spinosaurids. The animal''s generic name, which means "crocodile mimic", alludes to its elongated skull and piscivorous adaptations, while the specific name refers to the Ténéré Desert, where the fossils were discovered.
With an estimated length of 9.5–11 metres (31–36 ft) and a body mass ranging from 2.5–3.8 metric tons (2.8–4.2 short tons), Suchomimus was a particularly large theropod. As its generic name suggests, the animal’s skull was elongated, low, and narrow, resembling that of crocodilians.', '[]', 'https://cdn.jacobmaynard.dev/creatures/suchomimus-tenerensis.webp', 2.0979);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('036b717556b15f687b2ee', 'Supersaurus', 'Supersaurus vivianae', 'Cretaceous', 'Early Cretaceous', 'Herbivorous', 35.0, NULL, 'rare', 'Supersaurus (meaning "super lizard") is a genus of diplodocid sauropod dinosaur that lived in North America during the Late Jurassic period. The type species, S. vivianae, was first discovered by Vivian Jones of Delta, Colorado, in the middle Morrison Formation of Colorado in 1972. The fossil remains came from the Brushy Basin Member of the formation, dating between 153 and 145 million years ago. It is among the longest dinosaurs ever discovered, with the three known specimens reaching 33–40 meters (108–131 ft) in length, with the largest individual possibly exceeding 40 meters (130 ft) in size. Mass estimates for the WDC and BYU specimens tend to be around 35–44 metric tons (39–49 short tons) in body mass. A potential second species, S. lourinhanensis (Dinheirosaurus), is known from Portugal and has been dated to a similar time.', '[]', 'https://cdn.jacobmaynard.dev/creatures/supersaurus-vivianae.webp', 1.1673);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('37d36853e52491b9bca5d', 'Talarurus', 'Talarurus plicatospineus', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 6.0, NULL, 'uncommon', 'Talarurus is a genus of ankylosaurid dinosaur that lived in Asia during the Late Cretaceous period, about 96 million to 89 million years ago. The first remains of Talarurus were discovered in 1948 and later described by the Russian paleontologist Evgeny Maleev with the type species T. plicatospineus. It is known from multiple yet sparse specimens, making it one of the most well known ankylosaurines, along with Pinacosaurus. Elements from the specimens consists of various bones from the body; five skulls have been discovered and assigned to the genus, although the first two were very fragmented.
It was a medium-sized, heavily built, ground-dwelling, quadrupedal herbivore, that could grow up to 5–6 m (16–20 ft) long and weighed about 454 to 907 kg (1,001 to 2,000 lb), nearly a ton. Like other ankylosaurs it had heavy armour and a club on its tail, limiting its speed.', '[]', 'https://cdn.jacobmaynard.dev/creatures/talarurus-plicatospineus.webp', 2.5532);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('38dbb53d0e26132188d41', 'Tanius', 'Tanius sinensis', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', NULL, NULL, 'common', 'Tanius (meaning "of Tan") is a genus of hadrosauroid dinosaur. It lived in the Late Cretaceous of China. The type species, named and described in 1929 by Carl Wiman, is Tanius sinensis. The generic name honours the Chinese paleontologist Tan Xichou ("H.C. Tan"). The specific epithet refers to China. In 2010 Gregory S. Paul estimated the length of Tanius at 7 metres (23 ft) and its weight at 2 metric tons (2.2 short tons).', '[]', 'https://cdn.jacobmaynard.dev/creatures/tanius-sinensis.webp', 1.0017);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('7a960fe2b3e98d46a5ec0', 'Tarbosaurus', 'Tarbosaurus bataar', 'Cretaceous', 'Late Cretaceous', 'Carnivorous', 10.0, NULL, 'uncommon', 'Tarbosaurus is a genus of large tyrannosaurid dinosaur that lived in Asia during the Maastrichtian age of the Late Cretaceous epoch. It contains the type and single species Tarbosaurus bataar, which is known from the Nemegt Formation of Mongolia, with more fragmentary remains found further afield in the Subashi Formation of China. Tarbosaurus is represented by dozens of fossil specimens, including several complete skulls and skeletons. These remains have allowed studies focusing on its phylogeny, skull mechanics, and brain structure.', '[]', 'https://cdn.jacobmaynard.dev/creatures/tarbosaurus-bataar.webp', 1.5);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('4e78e9754ec82b6f41d6f', 'Tarchia', 'Tarchia gigantea', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 8.5, NULL, 'uncommon', 'Tarchia (meaning "brainy one") is a genus of herbivorous ankylosaurid dinosaur from the late Cretaceous of Mongolia.', '[]', 'https://cdn.jacobmaynard.dev/creatures/tarchia-gigantea.webp', 1.5464);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('db10f04b70fa8af57e0f4', 'Telmatosaurus', 'Telmatosaurus transsylvanicus', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 5.0, NULL, 'common', 'Telmatosaurus (meaning "marsh lizard") is a genus of basal hadrosauromorph dinosaur from the Late Cretaceous of Romania. It was relatively small for its group, measuring approximately 5 m (16 ft) in length and 600 kg (1,300 lb) in body mass, which has been explained as an instance of insular dwarfism.', '[]', 'https://cdn.jacobmaynard.dev/creatures/telmatosaurus-transsylvanicus.webp', 1.1009);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('3084d8849220789566016', 'Tenontosaurus', 'Tenontosaurus tillettorum', 'Cretaceous', 'Early Cretaceous', 'Herbivorous', 7.0, NULL, 'uncommon', 'Tenontosaurus is a genus of iguanodontian ornithopod dinosaur. It had an unusually long, broad tail, which like its back was stiffened with a network of bony tendons. The genus is known from the late Aptian to Albian ages of the Early Cretaceous period sediments of western North America, dating between 115 and 108 million years ago. It contains two species, Tenontosaurus tilletti (described by John Ostrom in 1970) and Tenontosaurus dossi (described by Winkler, Murry, and Jacobs in 1997). Many specimens of T. tilletti have been collected from several geological formations throughout western North America. T. dossi is known from only a handful of specimens collected from the Twin Mountains Formation of Parker County, Texas.', '[]', 'https://cdn.jacobmaynard.dev/creatures/tenontosaurus-tillettorum.webp', 1.5625);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('328255651f790799b04dd', 'Thecodontosaurus', 'Thecodontosaurus antiquus', 'Triassic', 'Late Triassic', 'Omnivorous', 2.5, NULL, 'common', 'Thecodontosaurus ("socket-tooth lizard") is a genus of herbivorous basal sauropodomorph dinosaur that lived during the late Triassic period (Carnian age). Its remains are known mostly from Triassic "fissure fillings" in southern England. Thecodontosaurus was a small bipedal animal, about 2 m (6.6 ft) long. It is one of the first dinosaurs to be discovered and is one of the oldest that ever existed. Many species have been named within the genus, but only the type species Thecodontosaurus antiquus is seen as valid today.', '[]', 'https://cdn.jacobmaynard.dev/creatures/thecodontosaurus-antiquus.webp', 3.0928);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('553b44e80e9a0168bbe7d', 'Therizinosaurus', 'Therizinosaurus cheloniformis', 'Cretaceous', 'Late Cretaceous', 'Unknown', 10.0, NULL, 'epic', 'Therizinosaurus ( ; meaning ''scythe lizard'') is a genus of very large therizinosaurid dinosaurs that lived during the Late Cretaceous period in what is now Asia. It contains a single species, Therizinosaurus cheloniformis, known from the fossiliferous Nemegt Formation. The first remains of Therizinosaurus were found in 1948 by a Mongolian field expedition in the Gobi Desert and later described by Evgeny Maleev in 1954. The genus is only known from a few bones, including gigantic manual unguals (claw bones), from which it gets its name, and additional findings comprising fore and hindlimb elements that were discovered from the 1960s through the 1980s.
Therizinosaurus was a colossal therizinosaurid that could grow up to 9–10 m (30–33 ft) long and 4–5 m (13–16 ft) tall, and weigh possibly over 5 t (5.5 short tons). Like other therizinosaurids, it would have been a slow-moving, long-necked, high browser equipped with a rhamphotheca (horny beak) and a wide torso for food processing.', '[]', 'https://cdn.jacobmaynard.dev/creatures/therizinosaurus-cheloniformis.webp', 1.6304);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('85333a6a4f3edaa4ef79c', 'Thescelosaurus', 'Thescelosaurus neglectus', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 3.5, NULL, 'common', 'Thescelosaurus is a genus of ornithischian dinosaur that lived during the Late Cretaceous period in western North America. It was named and described in 1913 by the paleontologist Charles W. Gilmore; the type species is T. neglectus. Two other species, T. garbanii and T. assiniboiensis, were named in 1976 and 2011, respectively. Additional species have been suggested but are currently not accepted. Thescelosaurus is the eponymous member of its family, the Thescelosauridae. Thescelosaurids are either considered to be basal ("primitive") ornithopods, or are placed outside of this group within the broader group Neornithischia.
Adult Thescelosaurus would have measured roughly 3–4 m (10–13 ft) long and probably weighed 200 to 300 kg (440 to 660 lb). It moved on two legs, and its body was counter-balanced by its long tail, which made up half of the body length and was stiffened by rod-like ossified tendons.', '[]', 'https://cdn.jacobmaynard.dev/creatures/thescelosaurus-neglectus.webp', 1.7341);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('88e8d0c0af47af15f0547', 'Torosaurus', 'Torosaurus latus', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 7.5, NULL, 'uncommon', 'Torosaurus (meaning "perforated lizard", in reference to the large openings in its frill) is a genus of herbivorous chasmosaurine ceratopsian dinosaur that lived during the late Maastrichtian age of the Late Cretaceous period, between 68 and 66 million years ago, though it is possible that the species range might extend to as far back as 69 million years ago. Fossils have been discovered across the Western Interior of North America, from as far north as Saskatchewan to as far south as Texas.
Measuring between 7.5 and 9 m (25 and 30 ft) and weighing around 8 t (18,000 lb), Torosaurus possessed the largest skulls of any known land animal, with the frilled skull reaching 2.77 metres (9.1 ft) in length.', '[]', 'https://cdn.jacobmaynard.dev/creatures/torosaurus-latus.webp', 1.467);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('ae8819dce88a19e423056', 'Torvosaurus', 'Torvosaurus tanneri', 'Jurassic', 'Late Jurassic', 'Carnivorous', 10.0, NULL, 'uncommon', 'Torvosaurus () is a genus of large megalosaurine theropod dinosaur that lived approximately 165 to 146.5 million years ago during the Callovian to Tithonian ages of the late Middle and Late Jurassic period in what is now Colorado, Portugal, Germany, and possibly England, Spain, Tanzania, and Uruguay. It contains two currently recognized species, Torvosaurus tanneri and Torvosaurus gurneyi, plus a third unnamed species from Germany.
In 1979, the type species Torvosaurus tanneri was named. Measuring around 9 meters (30 ft) long and weighing approximately 2–2.4 metric tons (2.2–2.6 short tons), T. tanneri was among the largest terrestrial carnivores in North America during the Late Jurassic. Specimens of Torvosaurus gurneyi were measured up to 10 meters (33 ft) in length and 4–5 metric tons (4.4–5.5 short tons) in body mass, suggesting that it was much larger than T. tanneri and was the largest terrestrial carnivore in Europe during the Late Jurassic.', '[]', 'https://cdn.jacobmaynard.dev/creatures/torvosaurus-tanneri.webp', 3.0);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('948cb61dbae7e6b5bea3a', 'Triceratops', 'Triceratops horridus', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 9.0, 10000.0, 'legendary', 'Triceratops is a genus of chasmosaurine ceratopsian dinosaur that lived during the late Maastrichtian age of the Late Cretaceous period, about 68 to 66 million years ago on the island continent of Laramidia, now forming western North America. It was one of the last-known non-avian dinosaurs and lived until the Cretaceous–Paleogene extinction event 66 million years ago. The name Triceratops, which means ''three-horned face'', is derived from the Ancient Greek words τρί- (trí-), meaning "three", κέρας (kéras), meaning "horn", and ὤψ (ṓps), meaning "face".
Bearing a large bony frill, three horns on the skull, and a large, four-legged body, exhibiting convergent evolution with rhinoceroses, Triceratops is one of the most recognizable of all dinosaurs and the best-known ceratopsian. It was also one of the largest, measuring around 8–9 m (26–30 ft) long and weighing up to 6–10 t (5.9–9.8 long tons; 6.6–11.0 short tons).', '[]', 'https://cdn.jacobmaynard.dev/creatures/triceratops-horridus.webp', 2.4);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('05de4653da2ee777b38fb', 'Troodon', 'Troodon formosus', 'Cretaceous', 'Late Cretaceous', 'Carnivorous', 2.0, NULL, 'common', 'Troodon is a controversial genus of relatively small, bird-like theropod dinosaurs definitively known from the Campanian age of the Late Cretaceous period (about 77 million years ago). It includes at least one species, Troodon formosus, known from Montana. Discovered in October 1855, T. formosus was among the first dinosaurs found in North America, although it was thought to be a lizard until 1877. 
Several well-known troodontid specimens from the Dinosaur Park Formation in Alberta have been historically considered members of this genus. In a 2017 analysis, the genus was considered undiagnostic, and some of its specimens were referred to the genus Stenonychosaurus (long believed to be synonymous with Troodon), some to the genus Latenivenatrix, and some to the genus Pectinodon. However, this has been disputed since, and a 2025 paper recommended the designation of a neotype to preserve Troodon''s validity, with Stenonychosaurus as a junior synonym.', '[]', 'https://cdn.jacobmaynard.dev/creatures/troodon-formosus.webp', 2.449);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('e108008e361f751e06ccf', 'Tsagantegia', 'Tsagantegia longicranialis', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', NULL, NULL, 'common', 'Tsagantegia (; meaning Tsagan Teg) is a genus of medium-sized ankylosaurid thyreophoran dinosaur that lived in Asia during the Late Cretaceous period. The genus is monotypic, including only the type species, T. longicranialis. The specimen consists of a very partial individual, comprising the skull and lacking postcranial remains. Since it only preserves the skull, Tsagantegia is mainly characterized by its elongated snout and the flattened facial osteoderms, greatly differing from other ankylosaurs.', '[]', 'https://cdn.jacobmaynard.dev/creatures/tsagantegia-longicranialis.webp', 2.2305);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('994bd732dac2a074cd83e', 'Tsintaosaurus', 'Tsintaosaurus spinorhinus', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 12.0, NULL, 'uncommon', 'Tsintaosaurus (; sic for the old transliteration "Tsingtao", meaning "Qingdao lizard") is a genus of hadrosaurid dinosaur from the Late Cretaceous of China. It was about 8.3 metres (27 ft) long and weighed 2.5 tonnes (2.8 short tons). The type species is Tsintaosaurus spinorhinus, first described by Chinese paleontologist C. C. Young in 1958. As a hadrosaur, Tsintaosaurus had the characteristic ''duck bill'' snout and a battery of powerful teeth which it used to chew vegetation. It usually walked on all fours, but could rear up on its hind legs to scout for predators and flee when it spotted one. Like other hadrosaurs, Tsintaosaurus probably lived and traveled in herds.', '[]', 'https://cdn.jacobmaynard.dev/creatures/tsintaosaurus-spinorhinus.webp', 2.4691);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('a1241edae50ae275cf104', 'Tuojiangosaurus', 'Tuojiangosaurus multispinus', 'Jurassic', 'Late Jurassic', 'Herbivorous', 7.0, NULL, 'uncommon', 'Tuojiangosaurus (meaning "Tuo River lizard") is a genus of herbivorous stegosaurian dinosaur from the Late Jurassic Period, recovered from the Upper Shaximiao Formation of what is now Sichuan Province in China.', '[]', 'https://cdn.jacobmaynard.dev/creatures/tuojiangosaurus-multispinus.webp', 2.0619);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('ebba6200582dd9b08db15', 'Tylocephale', 'Tylocephale gilmorei', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 1.4, NULL, 'common', 'Tylocephale (meaning "swollen head") is a genus of pachycephalosaurid dinosaur, a group of dome-headed, herbivorous ornithischians, that lived during the Maastrichtian stage of the Late Cretaceous in what is now Mongolia. It is known from a partial skull and associated mandible that were unearthed in 1971 by a Polish-Mongolian Expedition to the Barun Goyot Formation of the Gobi Desert. The specimen was described in 1974 by Polish paleontologists Teresa Maryańska and Halszka Osmólska as a new genus and species. 
It was average-sized for a pachycephalosaur, reaching 2 m (6.6 ft) in length and 40 kg (88 lb) in body mass. The skull is triangular in back view, the widest point being at the jugals with an apex at the top of the dome. Tylocephale''s dome is the tallest known from a pachycephalosaur. This dome is also unusually thick and rugose on its exterior. Behind the dome, an array of spikes, nodes, and tubercules protrude posteriorly over the neck.', '[]', 'https://cdn.jacobmaynard.dev/creatures/tylocephale-gilmorei.webp', 1.222);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('06b921acce773fc9d5879', 'Tyrannosaurus', 'Tyrannosaurus rex', 'Cretaceous', 'Late Cretaceous', 'Carnivorous', 12.0, 7000.0, 'legendary', 'Tyrannosaurus () is a genus of large theropod dinosaur. The type species Tyrannosaurus rex (rex meaning ''king'' in Latin), often shortened to T. rex or colloquially t-rex, is one of the best represented theropods. It lived throughout what is now western North America, on what was then an island continent known as Laramidia. Tyrannosaurus had a much wider range than other tyrannosaurids. Fossils are found in a variety of geological formations dating to the late Maastrichtian age of the late Cretaceous period, 69 to 66 million years ago, with isolated specimens possibly indicating an earlier origin in the middle Campanian age. It was one of the last known members of the tyrannosaurids and among the last non-avian dinosaurs to exist before the Cretaceous–Paleogene extinction event.
Like other tyrannosaurids, Tyrannosaurus was a bipedal carnivore with a massive skull balanced by a long, heavy tail.', '[]', 'https://cdn.jacobmaynard.dev/creatures/tyrannosaurus-rex.webp', 2.0);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('9609bae7b3f24beff7d62', 'Udanoceratops', 'Udanoceratops tschizhovi', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', NULL, NULL, 'common', 'Udanoceratops (meaning "Udan-Sayr horned face") is a genus of large leptoceratopsid dinosaur that lived during the Late Cretaceous period of Mongolia. The holotype specimen, the partial skeleton of an adult with its bones encapsulated in calcium carbonate, was discovered in the 1980s as part of the Joint Soviet-Mongolian Paleontological Expedition, and was subsequently transported to the Paleontological Institute of the Russian Academy of Sciences. In 1992, it was described by palaeontologist Sergei Kurzanov. The sole species of Udanoceratops, also the type species, is Udanoceratops tschizhovi, named after a colleague of Kurzanov, D. O. Tschizhov. Additional remains have been assigned to Udanoceratops, though these may be misattributions.
Udanoceratops is the largest known leptoceratopsid, with some estimates placing it at about 4 m (13 ft) in length and 700 kg (1,500 lb) in weight.', '[]', 'https://cdn.jacobmaynard.dev/creatures/udanoceratops-tschizhovi.webp', 1.3043);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('ed6cdbc5998367517db41', 'Unenlagia', 'Unenlagia comahuensis', 'Cretaceous', 'Late Cretaceous', 'Carnivorous', 2.4, NULL, 'common', 'Unenlagia (meaning "half-bird" in Latinized Mapudungun) is a genus of unenlagiine theropod dinosaur that lived in South America during the Late Cretaceous period. The genus Unenlagia has been assigned two species: U. comahuensis, the type species described by Novas and Puerta in 1997, and U. paynemili, described by Calvo et al. in 2004.', '[]', 'https://cdn.jacobmaynard.dev/creatures/unenlagia-comahuensis.webp', 1.3966);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('edc4b6ea43c06a7fd0001', 'Urbacodon', 'Urbacodon itemirensis', 'Cretaceous', 'Late Cretaceous', 'Carnivorous', 1.0, NULL, 'common', 'Urbacodon (meaning "URBAC tooth") is a genus of troodontid theropod dinosaur. Two species have been described, both of which are known from a partial dentary: U. itemirensis from the Dzharakuduk Formation (Cenomanian) of Uzbekistan and U. norelli from the Iren Dabasu Formation of China. Possible remains are also known from the Bissekty Formation (Turonian) of Uzbekistan.', '[]', 'https://cdn.jacobmaynard.dev/creatures/urbacodon-itemirensis.webp', 2.1277);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('cb54e2bcc58979a2f1ef6', 'Utahraptor', 'Utahraptor ostrommaysorum', 'Cretaceous', 'Early Cretaceous', 'Carnivorous', 6.0, NULL, 'uncommon', 'Utahraptor (meaning "Utah''s predator") is a genus of large dromaeosaurid (a group of feathered carnivorous theropods) dinosaur that lived during the Early Cretaceous period from around 139 to 135 million years ago in what is now the United States. The genus was described in 1993 by American paleontologist James Kirkland and colleagues with the type species Utahraptor ostrommaysi, based on fossils that had been unearthed earlier from the Cedar Mountain Formation of Utah. Later, many additional specimens were described including those from the skull and postcranium in addition to those of younger individuals.
It is the largest known member of the family Dromaeosauridae, measuring about 6–7 metres (20–23 ft) long and typically weighing around 500 kilograms (1,100 lb). As a heavily built, ground-dwelling, bipedal carnivore, its large size and variety of unique features have earned it attention in both pop culture and the scientific community.', '[]', 'https://cdn.jacobmaynard.dev/creatures/utahraptor-ostrommaysorum.webp', 2.4896);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('0eab89ee2e04750d68f1c', 'Valdosaurus', 'Valdosaurus canaliculatus', 'Cretaceous', 'Early Cretaceous', 'Herbivorous', 3.0, NULL, 'common', 'Valdosaurus ("Weald lizard") is a genus of bipedal herbivorous dryosaurid dinosaur known from the Early Cretaceous of the Isle of Wight and elsewhere in England. Originally its remains were believed to belong to Hypsilophodon. In 1889, Richard Lydekker assigned them to Camptosaurus, alongside a partial lower jaw, and applied the name Camptosaurus valdensis. In the 1970s, Peter Galton reassigned these remains to a new species of Dryosaurus, then to an entirely new genus and species, that being Valdosaurus proper. The type and only species of Valdosaurus, named by Galton, is V. canaliculatus.
Numerous specimens have been assigned to Valdosaurus over the years. Some, namely those found in Niger (now Elrhazosaurus), have been reassigned to different genera, while others have simply been redesignated as indeterminate. With that said, additional specimens of V. canaliculatus have been discovered.', '[]', 'https://cdn.jacobmaynard.dev/creatures/valdosaurus-canaliculatus.webp', 1.4706);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('93dceb99ae11326c2b94f', 'Velociraptor', 'Velociraptor mongoliensis', 'Cretaceous', 'Late Cretaceous', 'Carnivorous', 1.8, 7.0, 'legendary', 'Velociraptor is a genus of small dromaeosaurid dinosaurs that lived in Asia during the Late Cretaceous epoch, about 75 million to 71 million years ago (Mya). Two species are currently recognized, although others have been assigned in the past. The type species is V. mongoliensis, named and described in 1924. Fossils of this species have been discovered in the Djadochta Formation, Mongolia. A second species, V. osmolskae, was named in 2008 for skull material from the Bayan Mandahu Formation, China. A possible record is known from the Nemegt Formation.
Smaller than other dromaeosaurids like Deinonychus and Achillobator, Velociraptor was about 1.5–2.07 m (4.9–6.8 ft) long with a body mass of around 14.1–19.7 kg (31–43 lb). It nevertheless shared many of the same anatomical features. It was a bipedal, feathered carnivore with a long tail and an enlarged sickle-shaped claw on each hindfoot, which is thought to have been used to tackle and restrain prey.', '[]', 'https://cdn.jacobmaynard.dev/creatures/velociraptor-mongoliensis.webp', 1.6304);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('6274acb6258fb0bfd42b3', 'Vulcanodon', 'Vulcanodon karibaensis', 'Jurassic', 'Early Jurassic', 'Herbivorous', 6.5, NULL, 'uncommon', 'Vulcanodon (meaning "volcano tooth") is an extinct genus of sauropod dinosaur from the Early Jurassic uppermost Forest Sandstone of southern Africa. The only known species is V. karibaensis. Discovered in 1969 in Zimbabwe, it was regarded as the earliest known sauropod for decades, and is still one of the most primitive genera that has been discovered.
As a quadrupedal, ground-dwelling herbivore, Vulcanodon already showed the typical sauropod body plan with column-like legs and a long neck and tail. It was smaller than most other sauropods, measuring approximately 11 metres (36 ft) in length. Vulcanodon is known from a fragmentary skeleton including much of the pelvic girdle, hindlimbs, forearms, and tail, but lacking the trunk and neck vertebrae as well as the skull. Originally, this genus was believed to be a "prosauropod" because of the knife-shaped teeth found near its fossils, which fit in with the idea that they were omnivorous.', '[]', 'https://cdn.jacobmaynard.dev/creatures/vulcanodon-karibaensis.webp', 1.5);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('c73101232fd122d429890', 'Yandusaurus', 'Yandusaurus hongheensis', 'Jurassic', NULL, 'Herbivorous', 3.0, NULL, 'common', 'Yandusaurus is a genus of basal neornithischian dinosaur from the middle Jurassic (Bathonian age, approximately 168 to 162 Ma) of eastern Asia. The type species is Y. hongheensis, described in 1979 from the Lower Shaximiao Formation of Sichuan Province, China.', '[]', 'https://cdn.jacobmaynard.dev/creatures/yandusaurus-hongheensis.webp', 2.459);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('e3f2a7d8f3fe7bae03f4b', 'Yangchuanosaurus', 'Yangchuanosaurus shangyouensis', 'Jurassic', 'Late Jurassic', 'Carnivorous', 10.0, NULL, 'uncommon', 'Yangchuanosaurus is an extinct genus of metriacanthosaurid theropod dinosaur that lived in China from the Middle Jurassic to Late Jurassic periods (Bathonian to Tithonian stages), and was similar (although slightly larger) in size and appearance to its North American and European relative, Allosaurus. Yangchuanosaurus hails from the Upper Shaximiao Formation and was the largest predator in a landscape that included the sauropods Mamenchisaurus and Omeisaurus and the stegosaurs Chialingosaurus, Tuojiangosaurus and Chungkingosaurus. This theropod was named after the area in which was discovered, Yongchuan, in China.', '[]', 'https://cdn.jacobmaynard.dev/creatures/yangchuanosaurus-shangyouensis.webp', 1.5);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('6bdda4a5b4f5f5f45f794', 'Yimenosaurus', 'Yimenosaurus youngi', 'Jurassic', 'Early Jurassic', 'Herbivorous', 9.0, NULL, 'uncommon', 'Yimenosaurus (meaning "Yiman reptile") is an extinct genus of plateosaurid sauropodomorph dinosaur that lived in China in the Early Jurassic. The genus was first named in 1990 by Ziqi Bai, Jie Yang and Guohui Wang, along with its type and only species, Yimenosaurus youngi. The species name honours renowned Chinese paleontologist Yang Zhongjian, the father of Chinese paleontology, known as C.C. Young in English. Known material includes the holotype, an almost complete skull and mandible, as well as incomplete cervical and dorsal vertebrae, a mostly complete sacrum, an ilium, ischia, partial ribs and complete femur, and a paratype, a well-preserved postcrania with a fragmentary skull. In 2010 Paul estimated its length at 9 metres (30 ft) and its weight at 2 tonnes (2.2 short tons).', '[]', 'https://cdn.jacobmaynard.dev/creatures/yimenosaurus-youngi.webp', 3.6145);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('5e5da8147c1fcd0396cdd', 'Yingshanosaurus', 'Yingshanosaurus jichuanensis', 'Jurassic', 'Late Jurassic', 'Herbivorous', NULL, NULL, 'common', 'Yingshanosaurus (meaning "Yingshan lizard") is an extinct genus of stegosaurian dinosaurs from the Middle Jurassic of what is now Southwestern China. It is known from a partial skeleton discovered in 1983, including back, sacrum, and tail vertebrae, forelimb and hindlimb bones, shoulder and hip bones, and several osteoderms, including plates and a shoulder spine. The genus contains a single species, Yingshanosaurus jichuanensis, named and described in 1994. For some time after its discovery and scientific description, many paleontologists were unaware of the Chinese research published on it and questioned its validity.
Like other stegosaurs, Yingshanosaurus was a slow-moving, quadrupedal herbivore. At 4–5 metres (13–16 ft) long, it is a medium-sized member of this group. It''s forelimbs are relatively short in relation to its hindlimbs, and it has a wide torso with a broad back. Several flattened, semi-triangular plates were arranged in pairs along the neck, back, and tail.', '[]', 'https://cdn.jacobmaynard.dev/creatures/yingshanosaurus-jichuanensis.webp', 2.5974);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('cf96688778fbbbe1c22c4', 'Yinlong', 'Yinlong downsi', 'Jurassic', NULL, 'Herbivorous', 1.2, NULL, 'common', 'Yinlong (simplified Chinese: 隐龙; traditional Chinese: 隱龍; pinyin: yǐn lóng, meaning "hidden dragon") is a genus of basal ceratopsian dinosaur from the Late Jurassic Period of China. By far the earliest known ceratopsian, it was a small, primarily bipedal herbivore.', '[]', 'https://cdn.jacobmaynard.dev/creatures/yinlong-downsi.webp', 1.4218);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('d7194b14f0648c2c582d2', 'Yuanmousaurus', 'Yuanmousaurus jiangyiensis', 'Jurassic', NULL, 'Herbivorous', 17.0, NULL, 'rare', 'Yuanmousaurus ("Yuanmou lizard") was a sauropod dinosaur from the Middle Jurassic period of China. It is known from incomplete remains, recovered in 2000 from the Zhanghe Formation in Yuanmou County in Yunnan Province. Yuanmousaurus was a relatively large sauropod and may have reached about 17 meters (56 ft) in length. It was a basal member of the Sauropoda, but its exact systematic position is unclear. A recent study placed Yuanmousaurus within the family Mamenchisauridae. It may be a dubious genus. The only and type species was Yuanmousaurus jiangyiensis.', '[]', 'https://cdn.jacobmaynard.dev/creatures/yuanmousaurus-jiangyiensis.webp', 1.4963);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('9626fbed8e850ed6a8912', 'Yunnanosaurus', 'Yunnanosaurus huangi', 'Jurassic', 'Early Jurassic', 'Omnivorous', 7.0, NULL, 'uncommon', 'Yunnanosaurus is an extinct genus of sauropodomorph dinosaur that lived approximately 199 to 183 million years ago in what is now the Yunnan Province, in China, for which it was named. Yunnanosaurus was a large sized, moderately-built, ground-dwelling, quadrupedal herbivore, that could also walk bipedally, and ranged in size from 7 meters (23 feet) long and 2 m (6.5 ft) high to 4 m (13 ft) high in the largest species.', '[]', 'https://cdn.jacobmaynard.dev/creatures/yunnanosaurus-huangi.webp', 1.6854);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('70bfc887b7451b08dbd37', 'Zalmoxes', 'Zalmoxes robustus', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', 3.0, NULL, 'common', 'Zalmoxes is a genus of probable rhabdodontid ornithopod dinosaur from the Maastrichtian age of the Late Cretaceous in what is now Romania. The genus is known from specimens first named as the species Mochlodon robustum in 1899 by Franz Nopcsa before being reclassified as Rhabdodon robustum by him in 1915. In 1990, this name was corrected to Rhabdodon robustus by George Olshevsky and, in 2003, the species was once more reclassified as the type species Zalmoxes robustus. Zalmoxes represents one of the most common vertebrates of Transylvania during the latest Cretaceous period. The generic name refers to the Dacian deity Zalmoxis and the specific name robustus refers to the robustness of the remains. Another species, Zalmoxes shqiperorum, was named in 2003, but this species has since been reassigned to a separate genus of ceratopsian, Ferenceratops.', '[]', 'https://cdn.jacobmaynard.dev/creatures/zalmoxes-robustus.webp', 1.2024);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('d53317fe255c45b6207ae', 'Zephyrosaurus', 'Zephyrosaurus schaffi', 'Cretaceous', 'Early Cretaceous', 'Herbivorous', 1.8, NULL, 'common', 'Zephyrosaurus (meaning "westward wind lizard") is a genus of orodromine ornithischian dinosaur based on a partial skull and postcranial fragments discovered in the Early Cretaceous (Aptian-Albian) Cloverly Formation of Carbon County, Montana, USA. New remains are under description, and tracks from Maryland and Virginia, also in the US, have been attributed to animals similar to Zephyrosaurus.', '[]', 'https://cdn.jacobmaynard.dev/creatures/zephyrosaurus-schaffi.webp', 1.3825);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('645a6daa83f75a524efb9', 'Zuniceratops', 'Zuniceratops christopheri', 'Cretaceous', 'Late Cretaceous', 'Herbivorous', NULL, NULL, 'common', 'Zuniceratops (''Zuni horned face'') is a genus of ceratopsian dinosaurs that lived during the Turonian stage of the Late Cretaceous in what is now New Mexico, United States. Only a single species is known, Zuniceratops christopheri.', '[]', 'https://cdn.jacobmaynard.dev/creatures/zuniceratops-christopheri.webp', 1.7931);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('0e15d7874ccd5076e7d40', 'Pteranodon', 'Pteranodon longiceps', 'Cretaceous', 'Late Cretaceous', 'Unknown', 6.1, NULL, 'legendary', 'Pteranodon (; from Ancient Greek: πτερόν, romanized: pteron ''wing'' and ἀνόδων, anodon ''toothless'') is a genus of pterosaur that included some of the largest known flying reptiles, with P. longiceps having a wingspan of over 6 m (20 ft). They lived during the late Cretaceous geological period of North America in present-day Kansas, Nebraska, Wyoming, South Dakota and Alabama. More fossil specimens of Pteranodon have been found than any other pterosaur, with about 1,200 specimens known to science, many of them well preserved with nearly complete skulls and articulated skeletons. It was an important part of the animal community in the Western Interior Seaway.
When the first fossils of Pteranodon were found, they were assigned to toothed pterosaur genera, such as Ornithocheirus and Pterodactylus. In 1876, Othniel Charles Marsh recognised it as a genus of its own, making particular note of its complete lack of teeth, which at the time was unique among pterosaurs.', '[]', 'https://cdn.jacobmaynard.dev/creatures/pteranodon-longiceps.webp', 2.0);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('6fca9014e8ce049aca94f', 'Quetzalcoatlus', 'Quetzalcoatlus northropi', 'Cretaceous', 'Late Cretaceous', 'Unknown', 25.9, NULL, 'legendary', 'Quetzalcoatlus () is a genus of azhdarchid pterosaur that lived during the Maastrichtian age of the Late Cretaceous in North America. The type specimen, recovered in 1971 from the Javelina Formation of Texas, United States, consists of several wing fragments and was described as Quetzalcoatlus northropi in 1975 by Douglas Lawson. The generic name refers to the Aztec serpent god of the sky, Quetzalcōātl, while the specific name honors Jack Northrop, designer of a tailless fixed-wing aircraft. The remains of a second species were found between 1972 and 1974, also by Lawson, around 40 km (25 mi) from the Q. northropi locality.', '[]', 'https://cdn.jacobmaynard.dev/creatures/quetzalcoatlus-northropi.webp', 1.4151);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('30561de62981b69fb4471', 'Dimorphodon', 'Dimorphodon macronyx', 'Jurassic', 'Early Jurassic', 'Unknown', NULL, NULL, 'common', 'Dimorphodon is a genus of medium-sized pterosaur that lived in Europe during the early Jurassic Period (about 201-191 million years ago). It was named by paleontologist Richard Owen in 1859. Dimorphodon means "two-form tooth", derived from the Greek di- (δι-) meaning ''two'', morphḗ (μορφή) meaning ''shape'' and odṓn (ὀδών) meaning ''tooth'', referring to the fact that it had two distinct types of teeth in its jaws – which is comparatively rare among reptiles. The diet of Dimorphodon has been questioned among researchers, with earlier interpretations depicting it as an insectivore or a piscivore. Recent studies have suggested that Dimorphodon likely hunted small vertebrates, though it still would have consumed small invertebrates like insects.', '[]', 'https://cdn.jacobmaynard.dev/creatures/dimorphodon-macronyx.webp', 1.6086);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('3c7ef7ccd0e0a2c48e5af', 'Rhamphorhynchus', 'Rhamphorhynchus muensteri', 'Jurassic', NULL, 'Unknown', NULL, NULL, 'common', 'Rhamphorhynchus (, from Ancient Greek rhamphos meaning "beak" and rhynchus meaning "snout") is a genus of long-tailed pterosaurs in the Jurassic period. Less specialized than contemporary, short-tailed pterodactyloid pterosaurs such as Pterodactylus, it had a long tail, stiffened with ligaments, which ended in a characteristic soft-tissue tail vane. The mouth of Rhamphorhynchus housed needle-like teeth, which were angled forward, with a curved, sharp, beak-like tip lacking teeth, indicating a diet mainly of fish; indeed, fish and cephalopod remains are frequently found in Rhamphorhynchus abdominal contents, as well as in their coprolites.
Although fragmentary fossil remains possibly belonging to Rhamphorhynchus have been found in England, Tanzania, and Spain, the best preserved specimens come from the Solnhofen limestone of Bavaria, Germany. Many of these fossils preserve not only the bones but impressions of soft tissues, such as wing membranes and probably pycnofibers.', '[]', 'https://cdn.jacobmaynard.dev/creatures/rhamphorhynchus-muensteri.webp', 3.0);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('44ef73b0d8d32937bd772', 'Pterodactylus', 'Pterodactylus antiquus', 'Unknown', NULL, 'Unknown', NULL, NULL, 'common', 'Pterodactylus (from Ancient Greek: πτεροδάκτυλος, romanized: pterodáktylos ''winged finger'') is a genus of extinct pterosaurs. It is thought to contain only a single species, Pterodactylus antiquus, which was the first pterosaur to be named and identified as a flying reptile and one of the first prehistoric reptiles ever to be discovered.
Fossil remains of Pterodactylus have primarily been found in the Solnhofen limestone of Bavaria, Germany, which dates from the Late Jurassic period (Tithonian stage), about 150.8 to 148.5 million years ago. More fragmentary remains of Pterodactylus have tentatively been identified from elsewhere in Europe and in Africa.
Pterodactylus was a generalist carnivore that probably fed on a variety of invertebrates and vertebrates. Like all pterosaurs, Pterodactylus had wings formed by a skin and muscle membrane stretching from its elongated fourth finger to its hind limbs. It was supported internally by collagen fibres and externally by keratinous ridges.', '[]', 'https://cdn.jacobmaynard.dev/creatures/pterodactylus-antiquus.webp', 1.0);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('9df22cd1641192ec61071', 'Tropeognathus', 'Tropeognathus mesembrinus', 'Cretaceous', 'Early Cretaceous', 'Unknown', 8.5, NULL, 'uncommon', 'Tropeognathus (meaning "keel jaw") is a genus of large pterosaurs from the late Early Cretaceous of South America. This genus is considered to be a member of the family Anhangueridae, but several studies have also recovered it within another family called Ornithocheiridae. Both of these families are diverse groups of pterosaurs known for their keel-tipped snouts and large size. With an estimated wingspan around 8.5 m (28 ft), Tropeognathus is regarded as the largest pterosaur found in the Southern Hemisphere, only rivaled by the huge azhdarchids. The type and only species is Tropeognathus mesembrinus. Fossil remains of Tropeognathus have been recovered from the Romualdo Formation, which is a Lagerstätte located in the Santana Group of the Araripe Basin in northeastern Brazil.', '[]', 'https://cdn.jacobmaynard.dev/creatures/tropeognathus-mesembrinus.webp', 1.3072);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('e6798a5218dd154052af2', 'Tapejara', 'Tapejara wellnhoferi', 'Cretaceous', NULL, 'Unknown', 1.3, NULL, 'common', 'Tapejara (from a Tupi word meaning "the lord of the path") is a genus of Brazilian pterosaur from the Cretaceous Period (Santana Group, dating to about 127 to 112 million years ago). Tapejara crests consisted of a semicircular crest over the snout, and a bony prong which extended back behind the head. It was a small pterosaur, with a wingspan of approximately 1.23–1.3 metres (4.0–4.3 ft).', '[]', 'https://cdn.jacobmaynard.dev/creatures/tapejara-wellnhoferi.webp', 1.3015);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('c1b63ab663ed94f74a88b', 'Anhanguera', 'Anhanguera blittersdorffi', 'Cretaceous', 'Late Cretaceous', 'Unknown', NULL, NULL, 'common', 'Anhanguera is a genus of pterodactyloid pterosaur known from the Early Cretaceous (Albian age, 112 to 100 million years ago) Romualdo Formation of Brazil (precisely in Araripe Basin) and the Late Cretaceous (Cenomanian age, 98 to 93 million years ago) Kem Kem Group of Morocco. This pterosaur is closely related to Ornithocheirus, but belongs in the family Anhangueridae. The generic name comes from the Tupi words añanga, meaning "spirit protector of the animals" + wera "bygone".', '[]', 'https://cdn.jacobmaynard.dev/creatures/anhanguera-blittersdorffi.webp', 1.3333);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('c572e8eca28cb22ce13d4', 'Dsungaripterus', 'Dsungaripterus weii', 'Cretaceous', 'Early Cretaceous', 'Unknown', NULL, NULL, 'common', 'Dsungaripterus is a genus of dsungaripterid pterosaur which lived during the Early Cretaceous in what is now China and possibly South Korea. Its fossils come from the Wuerho Pterosaur Fauna group (WPF) of the Tugulu Group, comprising sections of the Lianmuqin and Shengjinkou Formations of the Junggar Basin. Both formations have been given various age estimates, with data suggesting at least some of the WPF date to the middle Valanginian, but the upper and lower bounds of these pterosaur bearing deposits remain unclear.', '[]', 'https://cdn.jacobmaynard.dev/creatures/dsungaripterus-weii.webp', 1.0169);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('d96282be99da9f1b92e1b', 'Nyctosaurus', 'Nyctosaurus gracilis', 'Cretaceous', 'Late Cretaceous', 'Unknown', NULL, NULL, 'common', 'Nyctosaurus (meaning "night lizard") is a genus of nyctosaurid pterosaur from the Late Cretaceous period of what is now the Niobrara Formation of the mid-western United States, which, during the time Nyctosaurus was alive, was covered in an extensive shallow sea. Some remains belonging to a possible Nyctosaurus species called "N." lamegoi have been found in Brazil, though it likely belongs to a different genus Simurghia. The genus Nyctosaurus has had numerous species referred to it, though how many of these may actually be valid requires further study. At least one species possessed an extraordinarily large antler-like cranial crest.
Nyctosaurus was a mid-sized pterosaur that lived along the shores of the Niobrara Formation of the United States, which back then was within a large inland sea called the Western Interior Seaway.', '[]', 'https://cdn.jacobmaynard.dev/creatures/nyctosaurus-gracilis.webp', 0.8759);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('beb976161acead93ea06d', 'Plesiosaur', 'Plesiosaurus dolichodeirus', 'Jurassic', 'Early Jurassic', 'Unknown', 3.4, NULL, 'epic', 'Plesiosaurus (Greek: πλησίος (plesios), near to + σαῦρος (sauros), lizard) is a genus of extinct, large marine sauropterygian reptile that lived during the Early Jurassic. It is known by nearly complete skeletons from the Lias of England. Measuring around 3.5 m (11 ft) long, it is distinguishable by its small head, long and slender neck, broad turtle-like body, a short tail, and two pairs of large, elongated paddles. It lends its name to the order Plesiosauria, of which it is an early, but fairly typical member. It contains only one species, the type, Plesiosaurus dolichodeirus. Other species once assigned to this genus, including P. brachypterygius, P. guilielmiimperatoris, and P. tournemirensis have been reassigned to new genera, such as Hydrorion, Seeleyosaurus and Microcleidus.', '[]', 'https://cdn.jacobmaynard.dev/creatures/plesiosaurus-dolichodeirus.webp', 1.3986);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('8e06e085e774aa8e506ce', 'Mosasaurus', 'Mosasaurus hoffmannii', 'Cretaceous', 'Late Cretaceous', 'Unknown', 11.9, NULL, 'legendary', 'Mosasaurus (; "lizard of the Meuse River") is the type genus (defining example) of the Mosasauridae, an extinct group of aquatic squamate reptiles. It lived from about 82 to 66 million years ago during the Campanian and Maastrichtian stages of the Late Cretaceous. The genus was one of the first Mesozoic marine reptiles known to science—the first fossils of Mosasaurus were found as skulls in a chalk quarry near the Dutch city of Maastricht in the late 18th century, and were initially thought to be crocodiles or whales. One skull discovered around 1780 was famously nicknamed the "great animal of Maastricht". In 1808, naturalist Georges Cuvier concluded that it belonged to a giant marine lizard with similarities to monitor lizards but otherwise unlike any known living animal. This concept was revolutionary at the time and helped support the then-developing ideas of extinction.', '[]', 'https://cdn.jacobmaynard.dev/creatures/mosasaurus-hoffmannii.webp', 2.5751);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('8a38a0445fb72578e4397', 'Ichthyosaurus', 'Ichthyosaurus communis', 'Jurassic', 'Early Jurassic', 'Unknown', NULL, NULL, 'epic', 'Ichthyosaurus meaning ''fish'' and σαῦρος (sauros) meaning ''lizard'') is a genus of ichthyosaurs from the Early Jurassic (Hettangian - Pliensbachian) of Europe (Belgium, England, Germany and Portugal). Some specimens of the ichthyosaurid Protoichthyosaurus from England and Switzerland have been erroneously referred to this genus in the past. It is among the best known ichthyosaur genera, as it is the type genus of the order Ichthyosauria.', '[]', 'https://cdn.jacobmaynard.dev/creatures/ichthyosaurus-communis.webp', 1.6216);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('20c8c6f8d9d68645b928e', 'Elasmosaurus', 'Elasmosaurus platyurus', 'Cretaceous', 'Late Cretaceous', 'Unknown', 10.4, NULL, 'epic', 'Elasmosaurus () is a genus of plesiosaur that lived in North America during the Campanian stage of the Late Cretaceous period, at about 80.6 to 77 million years ago. The first specimen was discovered in 1867 near Fort Wallace, Kansas, US, and was sent to the American paleontologist Edward Drinker Cope, who named it E. platyurus in 1868. The generic name means "thin-plate reptile", and the specific name means "flat-tailed". Cope originally reconstructed the skeleton of Elasmosaurus with the skull at the end of the tail, an error which was made light of by the paleontologist Othniel Charles Marsh, and became part of their "Bone Wars" rivalry. Only one incomplete Elasmosaurus skeleton is definitely known, consisting of a fragmentary skull, the spine, and now lost pectoral and pelvic girdles, and a single species is recognized today; other species are now considered invalid or have been moved to other genera.', '[]', 'https://cdn.jacobmaynard.dev/creatures/elasmosaurus-platyurus.webp', 3.256);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('a2fbf311fcf132b485355', 'Liopleurodon', 'Liopleurodon ferox', 'Jurassic', 'Late Jurassic', 'Carnivorous', 25.0, NULL, 'epic', 'Liopleurodon (; meaning ''smooth-sided teeth'') is an extinct genus of carnivorous pliosaurid plesiosaurs that lived from the Callovian stage of the Middle Jurassic to the Kimmeridgian stage of the Late Jurassic period (approximately 166 to 155 million years ago). The type species is L. ferox, which is probably the only valid species. Some studies also include the second species L. pachydeirus, but this latter is considered as a probable junior synonym of L. ferox due to its lack of viable diagnosis. Fossils attributed to Liopleurodon, including some skeletons, are mainly known from Europe, with one occurrence reported in Mexico. As the holotype specimen of L. ferox consists of a single tooth preserving questionable distinctive features, recent studies therefore recommend the necessary identification of a neotype in order to preserve its validity.', '[]', 'https://cdn.jacobmaynard.dev/creatures/liopleurodon-ferox.webp', 1.3333);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('b6576d7fe9ef666887970', 'Kronosaurus', 'Kronosaurus queenslandicus', 'Cretaceous', 'Early Cretaceous', 'Unknown', 13.1, NULL, 'uncommon', 'Kronosaurus is an extinct genus of large short-necked pliosaur that lived during the Aptian to Albian stages of the Early Cretaceous in what is now Australia. The first known specimen was received in 1899 and consists of a partially preserved mandibular symphysis, which was first thought to come from an ichthyosaur according to Charles De Vis. However, it was in 1924 that Albert Heber Longman formally described this specimen as the holotype of an imposing pliosaurid, to which he gave the scientific name K. queenslandicus, which is still the only recognized species nowadays. The genus name, meaning "lizard of Kronos", refers to its large size and possible ferocity reminiscent of the Titan of the Greek mythology, while the species name alludes to Queensland, the Australian state of its discovery.', '[]', 'https://cdn.jacobmaynard.dev/creatures/kronosaurus-queenslandicus.webp', 1.6086);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('3639dfbb50dd61ccc3784', 'Nothosaurus', 'Nothosaurus mirabilis', 'Triassic', NULL, 'Unknown', NULL, NULL, 'common', 'Nothosaurus is an extinct genus of sauropterygian reptile from the Triassic period, approximately 245–228 million years ago, with fossils being distributed throughout the former Tethys Ocean, from North Africa and Europe to China. It is the best known member of the nothosaur order.', '[]', NULL, NULL);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('d8f775ec4c8cd95c65a13', 'Tylosaurus', 'Tylosaurus proriger', 'Cretaceous', 'Late Cretaceous', 'Carnivorous', NULL, NULL, 'common', 'Tylosaurus (; "knob lizard") is a genus of russellosaurine mosasaur (an extinct group of predatory marine lizards) that lived about 92 to 66 million years ago during the Turonian to Maastrichtian stages of the Late Cretaceous. Its fossils have been found primarily around North Atlantic Ocean including in North America, Europe, and Africa.', '[]', 'https://cdn.jacobmaynard.dev/creatures/tylosaurus-proriger.webp', 1.6173);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('002657e553f794dca683e', 'Thalassomedon', 'Thalassomedon haningtoni', 'Unknown', NULL, 'Unknown', NULL, NULL, 'common', 'Thalassomedon (from Greek, thalassa, "sea" and Greek, medon, "lord" or "ruler", meaning "sea lord") is a genus of plesiosaur, named by Welles in 1943.', '[]', 'https://cdn.jacobmaynard.dev/creatures/thalassomedon-haningtoni.webp', 1.7804);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('69b0db2b27de8a6d6cf5f', 'Shonisaurus', 'Shonisaurus popularis', 'Triassic', 'Late Triassic', 'Unknown', NULL, NULL, 'common', 'Shonisaurus is a genus of very large ichthyosaurs. At least 37 incomplete fossil specimens of the type species, Shonisaurus popularis, have been found in the Luning Formation of Nevada, USA. This formation dates to the late Carnian-early Norian age of the Late Triassic, around 227 million years ago. Other possible species of Shonisaurus have been discovered from the middle Norian deposits of Canada and Alaska.', '[]', 'https://cdn.jacobmaynard.dev/creatures/shonisaurus-popularis.webp', 1.3333);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('f6bbef1b5233c9c472015', 'Ophthalmosaurus', 'Ophthalmosaurus icenicus', 'Cretaceous', NULL, 'Unknown', 4.0, 940, 'common', 'Ophthalmosaurus is a genus of ichthyosaur known from the Middle-Late Jurassic. Possible remains from the earliest Cretaceous (Berriasian stage) are also known. It was a relatively medium-sized ichthyosaur, measuring 4 m (13 ft) long and weighing 940 kg (2,070 lb). Named for its extremely large eyes, it had a jaw containing many small but robust teeth. Major fossil finds of this genus have been recorded in Europe with a second species possibly being found in North America.', '[]', 'https://cdn.jacobmaynard.dev/creatures/ophthalmosaurus-icenicus.webp', 1.2172);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('637452ad2f84747e04a67', 'Temnodontosaurus', 'Temnodontosaurus platyodon', 'Jurassic', NULL, 'Unknown', 9.1, NULL, 'uncommon', 'Temnodontosaurus (meaning "cutting-tooth lizard") is an extinct genus of large ichthyosaurs that lived during the Lower Jurassic in what is now Europe and possibly Chile. The first known fossil is a specimen consisting of a complete skull and partial skeleton discovered on a cliff by Joseph and Mary Anning around the early 1810s in Dorset, England. The anatomy of this specimen was subsequently analyzed in a series of articles written by Sir Everard Home between 1814 and 1819, making it the very first ichthyosaur to have been scientifically described. In 1822, the specimen was assigned to the genus Ichthyosaurus by William Conybeare, and more precisely to the species I. platyodon. Noting the large dental differences with other species of Ichthyosaurus, Richard Lydekker suggested in 1889 moving this species into a separate genus, which he named Temnodontosaurus.', '[]', 'https://cdn.jacobmaynard.dev/creatures/temnodontosaurus-platyodon.webp', 1.8634);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('e9619a98955ac222e38d7', 'Tanystropheus', 'Tanystropheus longobardicus', 'Triassic', NULL, 'Unknown', 6.1, NULL, 'uncommon', 'Tanystropheus (Ancient Greek: τανυ~ ''long'' + στροφευς ''hinged'') is an extinct genus of archosauromorph reptile which lived during the Triassic Period in Europe, Asia, and North America. It is recognisable by its extremely elongated neck, longer than the torso and tail combined. The neck was composed of 13 vertebrae strengthened by extensive cervical ribs. Tanystropheus is one of the most well-described non-archosauriform archosauromorphs, known from numerous fossils, including nearly complete skeletons. Some species within the genus may have reached a total length of 6 meters (20 ft), making Tanystropheus the longest non-archosauriform archosauromorph as well. Tanystropheus is the namesake of the family Tanystropheidae, a clade collecting many long-necked Triassic archosauromorphs previously described as "protorosaurs" or "prolacertiforms".
Tanystropheus contains at least two valid species as well as fossils which cannot be referred to a specific species.', '[]', 'https://cdn.jacobmaynard.dev/creatures/tanystropheus-longobardicus.webp', 1.9355);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('8d91db4c0a2f2add638b2', 'Smilodon', 'Smilodon fatalis', 'Quaternary', 'Pleistocene', 'Unknown', NULL, 78, 'legendary', 'Smilodon is a genus of extinct felids. It is one of the best-known saber-toothed predators and prehistoric mammals. Although commonly known as the saber-toothed tiger, it was not closely related to the tiger or other modern cats, belonging to the extinct subfamily Machairodontinae, with an estimated date of divergence from the ancestor of living cats around 20 million years ago. Smilodon was one of the last surviving machairodonts alongside Homotherium. Smilodon lived in the Americas during the Pleistocene to early Holocene epoch (2.5 mya – at latest 8,200 years ago). The genus was named in 1842 based on fossils from Brazil; the generic name means ''scalpel'' or ''two-edged knife'' combined with ''tooth''. Three species are recognized today: S. gracilis, S. fatalis, and S. populator. The two latter species were probably descended from S. gracilis, which itself probably evolved from Megantereon.', '[]', 'https://cdn.jacobmaynard.dev/creatures/smilodon-fatalis.webp', 1.7143);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('a7a243b0d225c69d82e21', 'Woolly Mammoth', 'Mammuthus primigenius', 'Quaternary', 'Pleistocene', 'Unknown', 2.4, 90, 'legendary', 'The woolly mammoth (Mammuthus primigenius) is an extinct species of mammoth that lived from the Middle Pleistocene until its extinction in the Holocene epoch. It was one of the last in a line of mammoth species, beginning with the African Mammuthus subplanifrons in the early Pliocene. The woolly mammoth began to diverge from the steppe mammoth about 800,000 years ago in Siberia. Its closest extant relative is the Asian elephant. The Columbian mammoth (Mammuthus columbi) lived alongside the woolly mammoth in North America, and DNA studies show that the two hybridised with each other. Mammoth remains were long known in Asia before they became known to Europeans. The origin of these remains was long debated and often explained as the remains of legendary creatures.', '[]', 'https://cdn.jacobmaynard.dev/creatures/mammuthus-primigenius.webp', 0.8141);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('436be1eef56d05ac3eda9', 'Woolly Rhinoceros', 'Coelodonta antiquitatis', 'Quaternary', 'Pleistocene', 'Unknown', NULL, NULL, 'common', 'The woolly rhinoceros (Coelodonta antiquitatis) is an extinct species of rhinoceros that inhabited northern Eurasia during the Pleistocene epoch. The woolly rhinoceros was large, comparable in size to the largest living rhinoceros species, the white rhinoceros (Ceratotherium simum), and covered with long, thick hair that allowed it to survive in the extremely cold, harsh mammoth steppe. It had a massive hump reaching from its shoulder and fed mainly by grazing on herbaceous plants that grew in the steppe. Mummified carcasses preserved in permafrost and many bone remains of woolly rhinoceroses have been found. Images of woolly rhinoceroses are found among cave paintings in Europe and Asia, and evidence has been found suggesting that the species was hunted by humans. Like other Pleistocene megafauna, the species became extinct as part of the end-Pleistocene extinction event.', '[]', 'https://cdn.jacobmaynard.dev/creatures/coelodonta-antiquitatis.webp', 1.6949);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('255eda55daf6cc9ec52c7', 'Megatherium', 'Megatherium americanum', 'Neogene', 'Pliocene', 'Unknown', NULL, NULL, 'epic', 'Megatherium ''great'' + theríon ''beast'') is an extinct genus of large ground sloths endemic to South America that lived from the Early Pliocene through the end of the Late Pleistocene. It is best known for the elephant-sized, 3.5–4 tonnes (7,700–8,800 lb) type species Megatherium americanum, primarily known from the Pampas, but ranging southwards to northernmost Patagonia and northwards to southern Bolivia during the late Middle Pleistocene and Late Pleistocene. Various other species have been described, including those belonging to the Andean subgenus Pseudomegatherium, which range in size from comparable to M. americanum down to approximately 1 tonne (2,200 lb).
The first (holotype) specimen of Megatherium americanum was discovered in 1787 on the bank of the Luján River in what is now northern Argentina.', '[]', 'https://cdn.jacobmaynard.dev/creatures/megatherium-americanum.webp', 1.3333);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('fb877ca85386b4716ee41', 'Glyptodon', 'Glyptodon clavipes', 'Neogene', 'Pliocene', 'Herbivorous', 2.0, 400, 'rare', 'Glyptodon ''sculptured'' and ὀδοντ-, ὀδούς (odont-, odoús) ''tooth'') is a genus of glyptodont, an extinct group of large, herbivorous armadillos that lived from the Pliocene, around 3.2 million years ago, to the early Holocene, around 11,000 years ago, in South America. It is one of, if not the, best known genus of glyptodont. Glyptodon has a long and storied past, being the first named extinct cingulate and the type genus of the subfamily Glyptodontinae. Fossils of Glyptodon have been recorded as early as 1814 from Pleistocene aged deposits from Uruguay, though many were incorrectly referred to the ground sloth Megatherium by early paleontologists.
The type species, G. clavipes, was described in 1839 by notable British paleontologist Sir Richard Owen.', '[]', 'https://cdn.jacobmaynard.dev/creatures/glyptodon-clavipes.webp', 1.3015);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('4f17c08268e7f9c578af6', 'Andrewsarchus', 'Andrewsarchus mongoliensis', 'Paleogene', 'Eocene', 'Unknown', NULL, NULL, 'common', 'Andrewsarchus (), meaning "Andrews'' ruler", is an extinct genus of artiodactyl that lived during the Middle Eocene in what is now China. The genus was first described by Henry Fairfield Osborn in 1924 with the type species A. mongoliensis based on a largely complete cranium. A second species, A. crassum, was described in 1977 based on teeth. A mandible, formerly described as Paratriisodon, does probably belong to Andrewsarchus as well. The genus has been historically placed in the families Mesonychidae or Arctocyonidae, or was considered to be a close relative of whales. It is now regarded as the sole member of its own family, Andrewsarchidae, and may have been related to entelodonts.', '[]', 'https://cdn.jacobmaynard.dev/creatures/andrewsarchus-mongoliensis.webp', 1.0545);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('0a219acbffbcfdcfa0768', 'Paraceratherium', 'Paraceratherium transouralicum', 'Paleogene', 'Oligocene', 'Unknown', 4.8, 17500, 'epic', 'Paraceratherium is an extinct genus of hornless rhinocerotoids belonging to the family Paraceratheriidae. It is one of the largest terrestrial mammals that has ever existed and lived from the Early to Late Oligocene epoch (34–23 million years ago). The first fossils were discovered in what is now Pakistan, and remains have been found across Eurasia between China and the Balkans. Paraceratherium means "near the hornless beast", in reference to Aceratherium, the genus in which the type species P. bugtiense was originally placed.
The exact size of Paraceratherium is unknown because of the incompleteness of the fossils. The shoulder height was about 4.8 metres (15.7 feet), and the length about 7.4 metres (24.3 feet). Its weight is estimated to have been about 15 to 20 tonnes (33,000 to 44,000 lb). The long neck supported a skull that was about 1.3 metres (4.3 ft) long. It had large, tusk-like incisors and a nasal incision that suggests it had a prehensile upper lip or proboscis (trunk).', '[]', 'https://cdn.jacobmaynard.dev/creatures/paraceratherium-transouralicum.webp', 0.735);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('6df23c7e0c56737ab70bb', 'Basilosaurus', 'Basilosaurus cetoides', 'Paleogene', 'Eocene', 'Carnivorous', 20.1, 15000, 'epic', 'Basilosaurus (meaning "king lizard") is a genus of large, predatory, prehistoric archaeocete whale from the late Eocene, approximately 41.3 to 33.9 million years ago (mya). First described in 1834, it was the first archaeocete and prehistoric whale known to science. Fossils attributed to the type species B. cetoides were discovered in the southeastern United States. The generic name, meaning "king lizard", was given due to the initial misconception about the fossil material as that of a giant reptile. The animal was later found to be an early marine mammal, prompting attempts at renaming the creature, which failed as the rules of zoological nomenclature dictate using the original name given. The second species named in 1904, B. isis, lived in the region currently known as the Mediterranean Sea, with fossils found in North Africa and Jordan.
Basilosaurus is thought to have been one of the largest animals of the Paleogene, with the type species B.', '[]', 'https://cdn.jacobmaynard.dev/creatures/basilosaurus-cetoides.webp', 1.4388);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('9f0de63532b00cf3afe4b', 'Ambulocetus', 'Ambulocetus natans', 'Paleogene', 'Eocene', 'Unknown', NULL, NULL, 'common', 'Ambulocetus (from Latin ambulō, meaning "to walk", and cetus, meaning "whale", and thus, "walking whale") is a genus of early semiaquatic cetacean from the Kuldana Formation in Pakistan, roughly 48 or 47 million years ago during the Early Eocene (Lutetian). It contains one species, Ambulocetus natans (Latin natans "swimming"), known solely from one near-complete skeleton. Ambulocetus is among the best-studied of Eocene cetaceans, and serves as an instrumental find in the study of cetacean evolution and their transition from land to sea, as it was the first cetacean discovered to preserve a suite of adaptations consistent with an amphibious lifestyle.', '[]', 'https://cdn.jacobmaynard.dev/creatures/ambulocetus-natans.webp', 3.0457);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('f6acaebcc3fbcd84980aa', 'Pakicetus', 'Pakicetus inachus', 'Unknown', NULL, 'Unknown', 0.9, NULL, 'common', 'Pakicetus (meaning ''whale from Pakistan'') is an extinct genus of amphibious cetacean of the family Pakicetidae, which was endemic to South Asia during the Ypresian (early Eocene) period, about 50 million years ago. It was a wolf-like mammal, about 1–2 m (3 ft 3 in – 6 ft 7 in) long, and lived in and around water where it ate fish and other animals. The name Pakicetus comes from the fact that the first fossils of this extinct amphibious whale were discovered in Pakistan. The vast majority of paleontologists regard it as the most basal whale, representing a transitional stage between land mammals and whales. It belongs to the even-toed ungulates with the closest living non-cetacean relative being the hippopotamus.', '[]', 'https://cdn.jacobmaynard.dev/creatures/pakicetus-inachus.webp', 0.7812);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('e3387b189eade07f8393b', 'Deinotherium', 'Deinotherium giganteum', 'Neogene', 'Miocene', 'Unknown', 4.0, 12000, 'common', 'Deinotherium is an extinct genus of large, elephant-like proboscideans that lived from the Middle Miocene until the end of the Early Pleistocene. Although its appearance is reminiscent of modern elephants, Deinotherium differered considerably from modern elephants in several anatomical details: it possessed a notably more flexible neck, proportionally more slender limbs, tapir-like teeth, as well as tusks which grew down and curved back from the lower jaw (mandible), and lacked tusks growing from the upper jaw. Several species of Deinotherium grew larger than modern elephants, not uncommonly reaching shoulder heights of 4 metres (13 ft) and body masses of 12 tonnes (26,000 lb), making them among the largest land mammals ever. Deinotherium was a widespread genus, during the Miocene they ranged across East Africa, and Eurasia from Western Europe to the Indian subcontinent. They were browsing animals, with a diet largely consisting of leaves.', '[]', 'https://cdn.jacobmaynard.dev/creatures/deinotherium-giganteum.webp', 1.2695);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('96d3d4b393478c0e28380', 'Sivatherium', 'Sivatherium giganteum', 'Unknown', NULL, 'Unknown', NULL, NULL, 'common', 'Sivatherium is an extinct genus of giraffid that ranged throughout Africa and Eurasia. The species Sivatherium giganteum is, by weight, one of the largest giraffids known, and also one of the largest ruminants of all time. Sivatherium originated during the Late Miocene (around 7 million years ago) in Africa and survived through to the late Early Pleistocene (Calabrian) until around 1 million years ago.', '[]', 'https://cdn.jacobmaynard.dev/creatures/sivatherium-giganteum.webp', 0.8242);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('53017909764d7770114ba', 'Elasmotherium', 'Elasmotherium sibiricum', 'Unknown', NULL, 'Unknown', 4.6, 5000, 'common', 'Elasmotherium (from Ancient Greek ἔλασμα (élasma), meaning "metal plate" with the intended meaning "lamina" in reference to the tooth enamel, and θηρίον (theríon), meaning "beast") is an extinct genus of very large rhinoceros that lived in Eastern Europe, Central Asia and East Asia from the late Miocene through to the Late Pleistocene, until at least 39,000 years ago. It was the last surviving member of the subfamily Elasmotheriinae, a formerly diverse group of rhinoceroses separate from the subfamily Rhinocerotinae, that contains all living rhinoceroses.
Five species are recognised. The genus first appeared in the Late Miocene in present-day China, likely having evolved from Sinotherium, before spreading to the Pontic–Caspian steppe, the Caucasus and Central Asia.', '[]', 'https://cdn.jacobmaynard.dev/creatures/elasmotherium-sibiricum.webp', 1.3021);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('9d4d48ee5520774af3515', 'Megalodon', 'Otodus megalodon', 'Neogene', 'Miocene', 'Unknown', 24.4, NULL, 'legendary', 'Otodus megalodon, commonly known as megalodon, is an extinct species of giant mackerel shark that lived approximately 23 to 3.6 million years ago (Mya), from the Early Miocene to the Early Pliocene epochs. This prehistoric fish was once thought to be a member of the family Lamnidae and a close relative of the great white shark (Carcharodon carcharias), but has been reclassified into the extinct family Otodontidae, which diverged from the great white shark during the Early Cretaceous.
While regarded as one of the largest and most powerful predators to have ever lived, megalodon is only known from fragmentary remains, and its appearance and maximum size are uncertain. Scientists have argued whether its body form was more stocky or elongated than the modern lamniform sharks.', '[]', 'https://cdn.jacobmaynard.dev/creatures/otodus-megalodon.webp', 1.3333);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('f2d60f0bbadb61778ec14', 'Thylacosmilus', 'Thylacosmilus atrox', 'Neogene', 'Miocene', 'Unknown', NULL, 150, 'common', 'Thylacosmilus is an extinct genus of saber-toothed metatherian mammals that inhabited South America from the Late Miocene to Pliocene epochs. Though Thylacosmilus looks similar to the "saber-toothed cats", it was not a felid, like the well-known American Smilodon, but a sparassodont, a group closely related to marsupials, and only superficially resembled other saber-toothed mammals due to convergent evolution, with the aforementioned Thylacosmilus being one of the last known sparassodonts. A 2005 study found that the bite forces of Thylacosmilus and Smilodon were low, which indicates that the killing techniques of saber-toothed animals differed from those of extant species. Remains of Thylacosmilus have been found primarily in Catamarca, Entre Ríos, and La Pampa Provinces in northern Argentina. Mass estimates of Thylacosmilus have varied depending on mass regressions, weighing 41–150 kg (90–331 lb), this makes Thylacosmilus one of the largest known metatherian predators.', '[]', 'https://cdn.jacobmaynard.dev/creatures/thylacosmilus-atrox.webp', 1.5748);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('ff53621a5084d98725dd3', 'Thylacoleo', 'Thylacoleo carnifex', 'Neogene', 'Pliocene', 'Carnivorous', NULL, 116, 'common', 'Thylacoleo ("pouch lion") is an extinct genus of carnivorous marsupials that lived in Australia from the late Pliocene to the Late Pleistocene (until around 40,000 years ago), often known as marsupial lions. They were the largest and last members of the family Thylacoleonidae, occupying the position of apex predator within Australian ecosystems. The largest and last species, Thylacoleo carnifex, had an estimated average weight of 101 to 130 kg (223 to 287 lb), approaching the weight of a modern lioness (Panthera leo).', '[]', 'https://cdn.jacobmaynard.dev/creatures/thylacoleo-carnifex.webp', 1.7804);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('6a5d61a205e6ddbde7221', 'Diprotodon', 'Diprotodon optatum', 'Quaternary', 'Pleistocene', 'Unknown', 1.5, 3500, 'common', 'Diprotodon, from Ancient Greek δί- (dí-), meaning "two", πρῶτος (prôtos), meaning "first", and ὀδούς (odoús), meaning "tooth", is an extinct genus of diprotodontid marsupial from the Pleistocene of Australia containing one species, D. optatum. The earliest finds date to 1.77 million to 780,000 years ago, but most specimens are dated to after 110,000 years ago. Its remains were first unearthed in 1830, in Wellington Caves, New South Wales, and contemporary paleontologists guessed they belonged to rhinos, elephants, hippos or dugongs.
Diprotodon was formally described by English naturalist Richard Owen in 1838, and was the first named Australian fossil mammal. This led Owen to become the foremost authority of his time on other marsupials and Australian megafauna, which were enigmatic to European science.
Diprotodon is the largest-known marsupial to have ever lived; it greatly exceeds the size of its closest living relatives wombats and koalas.', '[]', 'https://cdn.jacobmaynard.dev/creatures/diprotodon-optatum.webp', 1.0);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('f05e044c4517283039aa3', 'Procoptodon', 'Procoptodon goliah', 'Quaternary', 'Pleistocene', 'Unknown', 2.0, 240, 'common', 'Procoptodon is an extinct genus of giant short-faced (sthenurine) kangaroos that lived in Australia during the Pleistocene Epoch. P. goliah, the largest known kangaroo species that ever existed, stood at about 2 m (6.6 ft). They weighed about 200–240 kg (440–530 lb). Other members of the genus were smaller, however; Procoptodon gilli was the smallest of all of the sthenurine kangaroos, standing approximately 1 m (3 ft 3 in) tall.
The genus is derived from Simosthenurus, making the latter genus paraphyletic.', '[]', 'https://cdn.jacobmaynard.dev/creatures/procoptodon-goliah.webp', 0.8174);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('cd40926c17c4002acda1a', 'Megalania', 'Varanus priscus', 'Quaternary', 'Pleistocene', 'Unknown', 2.4, NULL, 'rare', 'Megalania (Varanus priscus) is an extinct species of giant monitor lizard, part of the megafaunal assemblage that inhabited Australia during the Pleistocene. It is the largest terrestrial lizard known to have existed, but the fragmentary nature of known remains make estimates highly uncertain. Studies suggest that most known specimens would have reached around 2–2.4 m (6.6–7.9 ft) in body length excluding the tail, while some individuals would have been significantly larger, reaching sizes around 4.5 m (15 ft), 5.5 m (18 ft) or perhaps even 7 m (23 ft) in total length.
Megalania is thought to have had a similar ecology to the living Komodo dragon (Varanus komodoensis) which may be its closest living relative. The youngest fossil remains of giant monitor lizards in Australia date to around 50,000 years ago. The indigenous peoples of Australia might have encountered megalania when they first arrived on the continent and might have subsequently played a role in megalania''s extinction.', '[]', 'https://cdn.jacobmaynard.dev/creatures/varanus-priscus.webp', 1.0);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('9c1e69bccc04b0d4a59a7', 'Arctodus', 'Arctodus simus', 'Quaternary', 'Pleistocene', 'Unknown', 1.5, 950, 'common', 'Arctodus is an extinct genus of short-faced bears that inhabited North America during the Pleistocene (about 2.6 Mya until 12,800 years ago). The two recognized species are the lesser short-faced bear (Arctodus pristinus) and the giant short-faced bear (Arctodus simus). Of these species, A. simus was larger, is known from more complete remains, and is considered one of the best-known members of North America''s extinct Ice Age megafauna. A. pristinus was largely restricted to the Early Pleistocene of the eastern United States, whereas A. simus had a broader range, with most finds being from the Late Pleistocene of the United States, Mexico and Canada. A. simus evolved from A. pristinus, but both species likely overlapped in the Middle Pleistocene. Both species are relatively rare in the fossil record.
Today considered to be an enormous omnivore, Arctodus simus is believed to be one of the largest known terrestrial carnivorans that has ever existed.', '[]', 'https://cdn.jacobmaynard.dev/creatures/arctodus-simus.webp', 1.662);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('303b840e7b77d2b6fb1c6', 'Doedicurus', 'Doedicurus clavicaudatus', 'Unknown', NULL, 'Unknown', NULL, 1400, 'common', 'Doedicurus, from Ancient Greek δοῖδυξ (doîdux), meaning "pestle" and oυρά (ourá), meaning "tail", is an extinct genus of glyptodont from South America containing one species, D. clavicaudatus. Glyptodonts are a member of the family Chlamyphoridae, which also includes some modern armadillo species, and they are classified in the superorder Xenarthra alongside sloths and anteaters. Being a glyptodont, it was a rotund animal with heavy armor and a carapace. Averaging at an approximate 1,400 kg (3,100 lb), it was one of the largest glyptodonts to have ever lived. Though glyptodonts were quadrupeds, large ones like Doedicurus may have been able to stand on two legs like other xenarthrans.', '[]', 'https://cdn.jacobmaynard.dev/creatures/doedicurus-clavicaudatus.webp', 1.4851);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('07c7d34cfc8f5e02321c8', 'Josephoartigasia', 'Josephoartigasia monesi', 'Neogene', 'Pliocene', 'Unknown', 0.3, 500, 'common', 'Josephoartigasia is an extinct genus of enormous dinomyid rodent from the Early Pliocene to Early Pleistocene of Uruguay. Its closest living relative is the pacarana. Josephoartigasia is named after Uruguayan national hero José Artigas. It contains two species: J. magna, described in 1966 based on a left mandible, and J. monesi, described in 2008 based on a nearly complete skull. Both are reported from the San José Member of the Raigón Formation by the Barrancas de San Gregorio along Kiyú beach.
The skull of J. monesi measures 53 cm (1 ft 9 in), similar to a beef cow skull, equating to a full body length of 262.8 cm (8 ft 7 in)—though this is likely an overestimate—and a weight of about 480–500 kg (1,060–1,100 lb). This makes J. monesi the biggest rodent ever discovered. It was much larger than J. magna, giant hutia or the largest living rodent, the capybara, which averages 60 kg (130 lb). J.', '[]', 'https://cdn.jacobmaynard.dev/creatures/josephoartigasia-monesi.webp', 1.8927);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('7953e9585b3fe373132e0', 'Terror Bird', 'Phorusrhacos longissimus', 'Unknown', NULL, 'Unknown', NULL, NULL, 'epic', 'Phorusrhacos is an extinct genus of giant flightless terror birds that inhabited South America during the Miocene epoch. Phorusrhacos was one of the dominant land predators in South America at the time it existed. It is thought to have lived in woodlands and grasslands.', '[]', 'https://cdn.jacobmaynard.dev/creatures/phorusrhacos-longissimus.webp', 1.3333);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('d9d0d1ee8e40679c457e2', 'Gastornis', 'Gastornis gigantea', 'Paleogene', 'Eocene', 'Unknown', NULL, NULL, 'common', 'Gastornis is an extinct genus of large, flightless birds that lived during the mid-Paleocene to mid-Eocene epochs of the Paleogene period. Most fossils have been found in Europe, and some species typically referred to the genus are known from North America and Asia. Several genera, including the well-studied genus Diatryma, have historically been considered junior synonyms of Gastornis. However, this interpretation has been challenged recently, and some researchers currently consider Diatryma to be a valid genus.
Gastornis species were very large birds that were traditionally thought to have been predators of various smaller mammals, such as ancient, diminutive equids. However, several lines of evidence, including the lack of hooked claws (in known Gastornis footprints), studies of their beak structure and isotopic signatures of their bones, have caused scientists to now consider that these birds were probably herbivorous, feeding on tough plant material and seeds.', '[]', 'https://cdn.jacobmaynard.dev/creatures/gastornis-gigantea.webp', 1.4423);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('4ce99f43df3c6b75815be', 'Titanoboa', 'Titanoboa cerrejonensis', 'Paleogene', 'Eocene', 'Unknown', 12.8, 932, 'legendary', 'Titanoboa is a genus of extinct giant boid snake (being the biological family of all boas and anacondas) that lived during the middle and late Paleocene epoch. Titanoboa was first discovered in the early 2000s by members of the Smithsonian Tropical Research Institute, which–along with students from the University of Florida–recovered 186 fossils of Titanoboa from the Cerrejón coal mines in the La Guajira department of northeastern Colombia. It was named and described in 2009 as Titanoboa cerrejonensis, and lauded as the largest snake ever found at that time. The original type material consisted of thoracic vertebrae and ribs, but later expeditions collected parts of the skull and teeth.
Titanoboa is estimated to grow up to 12.8 m (42 ft) or perhaps even up to 14.3 m (47 ft) long, and weigh around 730 to 1,135 kg (1,610 to 2,500 lb).', '[]', 'https://cdn.jacobmaynard.dev/creatures/titanoboa-cerrejonensis.webp', 1.3825);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('39eae41eb01380c18a80d', 'Sarcosuchus', 'Sarcosuchus imperator', 'Cretaceous', 'Early Cretaceous', 'Unknown', 9.5, 4300, 'epic', 'Sarcosuchus (), from Ancient Greek σάρξ (sárx), meaning "flesh", and Σοῦχος (Soûkhos), meaning "Sobek", is an extinct genus of crocodyliform that lived during the Early Cretaceous, from the late Hauterivian to the early Albian stages, 130 to 112 million years ago of what is now Africa and South America. It was one of the largest pseudosuchians, with the largest specimen of S. imperator reaching approximately 9–9.5 metres (29.5–31.2 ft) long and weighing up to 3.45–4.3 metric tons (3.80–4.74 short tons). It is known from two species; S. imperator from the early Albian Elrhaz Formation of Niger, and S. hartti from the Late Hauterivian of northeastern Brazil. Other material is known from Morocco and Tunisia and possibly Libya and Mali.
The first remains were discovered during several expeditions led by the French paleontologist Albert-Félix de Lapparent, spanning from 1946 to 1959, in the Sahara. These remains were fragments of the skull, vertebrae, teeth, and scutes.', '[]', 'https://cdn.jacobmaynard.dev/creatures/sarcosuchus-imperator.webp', 2.0408);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('e6497d5606bbd2ee9d8ec', 'Deinosuchus', 'Deinosuchus hatcheri', 'Cretaceous', 'Late Cretaceous', 'Unknown', 10.7, NULL, 'uncommon', 'Deinosuchus is an extinct genus of eusuchian, either an alligatoroid crocodilian or a stem-group crocodilian, which lived during the Late Cretaceous around 82 to 73 million years ago. The first remains were discovered in North Carolina (United States) in the 1850s, and the genus was first described in 1909. Additional fragments were discovered in the 1940s and were later incorporated into an influential, though inaccurate, skull reconstruction at the American Museum of Natural History. Knowledge of Deinosuchus remains incomplete, but better cranial material found in recent years has expanded scientific understanding of this massive predator.
Although Deinosuchus was far larger than any modern crocodile or alligator, with the largest adults measuring 10.6 meters (35 ft) in total length, its overall appearance was fairly similar to its smaller relatives. It had large, robust teeth built for crushing, and its back was covered with thick hemispherical osteoderms.', '[]', 'https://cdn.jacobmaynard.dev/creatures/deinosuchus-hatcheri.webp', 1.3304);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('d8efff19fee494e3f4bc6', 'Kaprosuchus', 'Kaprosuchus saharicus', 'Cretaceous', NULL, 'Unknown', NULL, NULL, 'common', 'Kaprosuchus is an extinct genus of mahajangasuchid crocodyliform. It is known from a single nearly complete skull collected from the Upper Cretaceous Echkar Formation of Niger. The name means "boar crocodile" from the Greek κάπρος, kapros ("boar") and σοῦχος, soukhos ("crocodile") in reference to its unusually large caniniform teeth which resemble those of a boar. It has been nicknamed "BoarCroc" by Paul Sereno and Hans Larsson, who first described the genus in a monograph published in ZooKeys in 2009 along with other Saharan crocodyliforms such as Anatosuchus and Laganosuchus. The type species is K. saharicus.', '[]', 'https://cdn.jacobmaynard.dev/creatures/kaprosuchus-saharicus.webp', 2.1739);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('0ce7dfa0f699faf39a445', 'Quinkana', 'Quinkana fortirostrum', 'Unknown', NULL, 'Unknown', 3.0, 200, 'common', 'Quinkana is an extinct genus of mekosuchine crocodylians that lived in Australia from about 25 million to about 10,000 years ago, with the majority of fossils having been found in Queensland. Four species are currently recognized, all of which have been named between 1981 and 1997. The two best understood species are Q. fortirostrum, the type species, and Q. timara, a more gracile form from the Miocene. The other two species, Q. babarra and Q. meboldi, from the Pliocene and Oligocene respectively, are only known from a few poorly preserved bone fragments. The name Quinkana comes from the "Quinkans", a legendary folk spirit from Gugu-Yalanji mythology.
Quinkana is primarily known for its ziphodont teeth, meaning they were recurved, serrated and possessed flattened sides that gave them a blade-like shape.', '[]', 'https://cdn.jacobmaynard.dev/creatures/quinkana-fortirostrum.webp', 2.6043);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('72142fce5b2456d184b60', 'Dimetrodon', 'Dimetrodon grandis', 'Permian', 'Early Permian', 'Unknown', 4.6, 250, 'epic', 'Dimetrodon is an extinct genus of sphenacodontid synapsid that lived during the Cisuralian (Early Permian) epoch of the Permian period, around 295–272 million years ago. With most species measuring 1.7–4.6 m (5.6–15.1 ft) long and weighing 28–250 kg (62–551 lb), the most prominent feature of Dimetrodon is the large neural spine sail on its back formed by elongated spines extending from the vertebrae. It was an obligate quadruped (it could walk only on four legs) and had a tall, curved skull with large teeth of different sizes set along the jaws. Most fossils have been found in the Southwestern United States, the majority of these coming from a geological deposit called the Red Beds of Texas and Oklahoma.', '[]', 'https://cdn.jacobmaynard.dev/creatures/dimetrodon-grandis.webp', 1.7751);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('732348007567590971011', 'Edaphosaurus', 'Edaphosaurus pogonias', 'Unknown', NULL, 'Unknown', NULL, NULL, 'common', 'Edaphosaurus (, meaning "pavement lizard" for dense clusters of its teeth) is a genus of extinct edaphosaurid synapsids that lived in what is now North America and Europe around 303.4 to 272.5 million years ago, during the Late Carboniferous to Early Permian. The American paleontologist Edward Drinker Cope first described Edaphosaurus in 1882, naming it for the "dental pavement" on both the upper and lower jaws, from the Greek edaphos έδαφος ("ground"; also "pavement") and σαῦρος (sauros) ("lizard").
Edaphosaurus is important as one of the earliest-known, large, plant-eating (herbivorous), amniote tetrapods (four-legged land-living vertebrates). In addition to the large tooth plates in its jaws, the most characteristic feature of Edaphosaurus is a sail on its back. A number of other synapsids from the same time period also have tall dorsal sails, most famously the large apex predator Dimetrodon. However, the sail on Edaphosaurus is different in shape and morphology.', '[]', 'https://cdn.jacobmaynard.dev/creatures/edaphosaurus-pogonias.webp', 1.6484);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('4b1b23cfa5bb158bb2c4b', 'Gorgonops', 'Gorgonops torvus', 'Permian', 'Late Permian', 'Unknown', NULL, NULL, 'rare', 'Gorgonops (from Greek: Γοργών ''Gorgon'' and ὤψ ''eye, face'', literally ''Gorgon eye'' or ''Gorgon face'') is an extinct genus of gorgonopsian therapsid, of which it is the type genus. Gorgonops lived during the Late Permian (Wuchiapingian), about 260–254 million years ago in what is now South Africa.', '[]', 'https://cdn.jacobmaynard.dev/creatures/gorgonops-torvus.webp', 1.9417);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('7ae1799df4464720df41e', 'Inostrancevia', 'Inostrancevia alexandri', 'Permian', 'Late Permian', 'Carnivorous', 3.2, NULL, 'common', 'Inostrancevia is an extinct genus of large carnivorous therapsids which lived during the Late Permian in what is now European Russia and Southern Africa. The first-known fossils of this gorgonopsian were discovered in the context of a long series of excavations carried out from 1899 to 1914 in the Northern Dvina, Russia. Among these are two near-complete skeletons embodying the first described specimens of this genus, being also the first gorgonopsian identified in Russia. Several other fossil materials were discovered there, and the various finds led to confusion as to the exact number of valid species, before only two of them were formally recognized, namely I. alexandri and I. latifrons. A third species, I. uralensis, was erected in 1974, but the fossil remains of this taxon are very thin and could come from another genus. More recent research carried out in Southern Africa has discovered specimens identified as belonging to this genus, being classified within the species I.', '[]', 'https://cdn.jacobmaynard.dev/creatures/inostrancevia-alexandri.webp', 1.25);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('fd0df697f5670a99b6b02', 'Scutosaurus', 'Scutosaurus karpinskii', 'Unknown', NULL, 'Unknown', NULL, NULL, 'common', 'Scutosaurus ("shield lizard") is an extinct genus of pareiasaur parareptiles. Its genus name refers to large plates of armor scattered across its body. It was a large anapsid reptile that, unlike most reptiles, held its legs underneath its body to support its great weight. Fossils have been found in the Sokolki Assemblage Zone of the Malokinelskaya Formation in European Russia, close to the Ural Mountains, dating to the late Permian (Lopingian) between 259 and 252 million years ago.', '[]', 'https://cdn.jacobmaynard.dev/creatures/scutosaurus-karpinskii.webp', 1.3304);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('5917f2d60fc7252bec007', 'Moschops', 'Moschops capensis', 'Unknown', NULL, 'Unknown', NULL, NULL, 'common', 'Moschops (Greek for "calf face") is an extinct genus of therapsids that lived in the Guadalupian epoch, around 265–260 million years ago. They were heavily built plant eaters, and they may have lived partly in water, as hippopotamuses do. They had short, thick heads and might have competed by head-butting each other. Their elbow joints allowed them to walk with a more mammal-like gait rather than crawling. Their remains were found in the Karoo region of South Africa, belonging to the Tapinocephalus Assemblage Zone. Therapsids, such as Moschops, are synapsids, the dominant land animals in the Permian period, which ended 252 million years ago.', '[]', 'https://cdn.jacobmaynard.dev/creatures/moschops-capensis.webp', 0.9217);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('6149e77319d63f2ed4e08', 'Lystrosaurus', 'Lystrosaurus murrayi', 'Unknown', NULL, 'Herbivorous', 2.4, NULL, 'common', 'Lystrosaurus (; ''shovel lizard''; proper Ancient Greek is λίστρον lístron ''tool for leveling or smoothing, shovel, spade, hoe'') is an extinct genus of herbivorous dicynodont therapsids from the late Permian and Early Triassic epochs (around 248 million years ago). It lived in what is now Antarctica, India, China, Mongolia, European Russia and South Africa. Four to six species are currently recognized, although from the 1930s to 1970s the number of species was thought to be much higher. They ranged in size from that of a small dog to 8 feet (2.5 meters) long.
As a dicynodont, Lystrosaurus had only two teeth (a pair of tusk-like canines), and is thought to have had a horny beak that was used for biting off pieces of vegetation. Lystrosaurus was a heavily built, herbivorous animal. The structure of its shoulders and hip joints suggests that Lystrosaurus moved with a semi-sprawling gait.', '[]', 'https://cdn.jacobmaynard.dev/creatures/lystrosaurus-murrayi.webp', 1.3363);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('666beaab57e56943e2917', 'Diictodon', 'Diictodon feliceps', 'Permian', 'Late Permian', 'Unknown', NULL, NULL, 'common', 'Diictodon (meaning "two weasel teeth") is an extinct genus of pylaecephalid dicynodont that lived during the Late Permian period, approximately 255 million years ago. Fossils have been found in the Cistecephalus Assemblage Zone of the Madumabisa Mudstone of the Luangwa Basin in Zambia and the Tropidostoma Assemblage Zone of the Teekloof Formation, Tapinocephalus Assemblage Zone of the Abrahamskraal Formation, Dicynodon Assemblage Zone of the Balfour Formation, Cistecephalus Assemblage Zone of the Middleton or Balfour Formation of South Africa and the Guodikeng Formation of China. Roughly half of all Permian vertebrate specimens found in South Africa are those of Diictodon. This small herbivorous animal was one of the most successful synapsids in the Permian period.', '[]', 'https://cdn.jacobmaynard.dev/creatures/diictodon-feliceps.webp', 1.7751);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('f64b722101fc7b371eda5', 'Postosuchus', 'Postosuchus kirkpatricki', 'Triassic', 'Late Triassic', 'Unknown', 6.1, NULL, 'uncommon', 'Postosuchus, meaning "Crocodile from Post", is an extinct genus of rauisuchid reptiles comprising two species, P. kirkpatricki and P. alisonae, that lived in what is now North America during the Late Triassic. Postosuchus is a member of the clade Pseudosuchia, the lineage of archosaurs that includes modern crocodilians (the other main group of archosaurs is Avemetatarsalia, the lineage that includes all archosaurs more closely related to birds than to crocodilians). Its name refers to Post Quarry, a place in Texas where many fossils of the type species, P. kirkpatricki, were found. 
It was one of the apex predators of its area during the Triassic, larger than the small dinosaur predators of its time (such as Coelophysis). It was a hunter that probably preyed on large, bulky herbivores such as dicynodonts and many other creatures smaller than itself (such as early dinosaurs). The skeleton of Postosuchus is large and robust, with a deep skull and a long tail.', '[]', 'https://cdn.jacobmaynard.dev/creatures/postosuchus-kirkpatricki.webp', 1.4634);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('f033504f8e9239e47e26a', 'Desmatosuchus', 'Desmatosuchus spurensis', 'Unknown', NULL, 'Unknown', NULL, NULL, 'common', 'Desmatosuchus (, from Greek δεσμός desmos ''link'' + σοῦχος soûkhos ''crocodile'') is an extinct genus of archosaur belonging to the Order Aetosauria. It lived in North America and potentially India (cf. Desmatosuchus) during the Late Triassic.', '[]', 'https://cdn.jacobmaynard.dev/creatures/desmatosuchus-spurensis.webp', 4.4409);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('c51e42a8e78fb6a554ecd', 'Anomalocaris', 'Anomalocaris canadensis', 'Unknown', NULL, 'Unknown', NULL, NULL, 'legendary', 'Anomalocaris (from Ancient Greek ανώμαλος, meaning "unlike", and καρίς, meaning "shrimp", with the intended meaning "unlike other shrimp") is an extinct genus of radiodont, an order of early-diverging stem-group marine arthropods. It is best known from the type species A. canadensis, found in the Stephen Formation (particularly the Burgess Shale) of British Columbia, Canada. The other named species A. daleyae is known from the somewhat older Emu Bay Shale of Australia. Other unnamed Anomalocaris species are known from China and the United States. 
Like other radiodonts, Anomalocaris had swimming flaps running along its body, large compound eyes, and a single pair of segmented, frontal appendages, which in Anomalocaris were used to grasp prey.', '[]', 'https://cdn.jacobmaynard.dev/creatures/anomalocaris-canadensis.webp', 1.8018);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('ef2ebf8b7d371083642a5', 'Hallucigenia', 'Hallucigenia sparsa', 'Cambrian', NULL, 'Unknown', NULL, NULL, 'rare', 'Hallucigenia is a genus of lobopodian known from Cambrian-aged fossils in Burgess Shale-type deposits in Canada (Burgess Shale) and China, and from isolated spines around the world. The generic name reflects the type species'' unusual appearance and eccentric history of study; when it was erected as a genus, H. sparsa was reconstructed as an enigmatic animal upside down and back to front. Lobopodians are a grade of Paleozoic panarthropods from which the velvet worms, water bears, and arthropods arose.', '[]', 'https://cdn.jacobmaynard.dev/creatures/hallucigenia-sparsa.webp', 1.1811);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('67a94f428341aca1176c4', 'Opabinia', 'Opabinia regalis', 'Cambrian', NULL, 'Unknown', NULL, NULL, 'rare', 'Opabinia regalis is an extinct, stem group marine arthropod found in the Middle Cambrian Burgess Shale Lagerstätte (505 million years ago) of British Columbia. Opabinia was a soft-bodied animal, measuring up to 7 cm in body length, and had a segmented trunk with flaps along its sides and a fan-shaped tail. The head showed unusual features: five eyes, a mouth under the head and facing backwards, and a clawed proboscis that most likely passed food to its mouth. Opabinia lived on the seafloor, using the proboscis to seek out small, soft food. Fewer than twenty good specimens have been described; 3 specimens of Opabinia are known from the Greater Phyllopod bed, where they constitute less than 0.1% of the community.
When the first thorough examination of Opabinia in 1975 revealed its unusual features, it was thought to be unrelated to any known phylum, or perhaps a relative of arthropod and annelid ancestors.', '[]', 'https://cdn.jacobmaynard.dev/creatures/opabinia-regalis.webp', 1.8418);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('d9875d74f19d0146ba240', 'Wiwaxia', 'Wiwaxia corrugata', 'Cambrian', NULL, 'Unknown', NULL, NULL, 'common', 'Wiwaxia is a genus of prehistoric soft-bodied animals that were covered in carbonaceous scales and spines that protected it from predators. Wiwaxia fossils—mainly isolated scales, but sometimes complete, articulated fossils—are known from early Cambrian and middle Cambrian fossil deposits across the globe. The living animal would have measured up to 5 centimetres (2 in) when fully grown, although a range of juvenile specimens are known, the smallest being 2 millimetres (0.08 in) long.
Wiwaxia''s affinity has been a matter of debate, causing researchers to be long split between two possibilities. On the one hand, its rows of scales looked superficially similar to certain scale worms (annelids); conversely, its mouthparts and general morphology suggested a relationship to the shell-less molluscs. More recently, evidence for a molluscan affinity has been accumulating, based on new details of Wiwaxia''s mouthparts, scales, and growth history.', '[]', 'https://cdn.jacobmaynard.dev/creatures/wiwaxia-corrugata.webp', 1.3333);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('5c526097fcdc46eb4c220', 'Trilobite', 'Paradoxides davidis', 'Cambrian', NULL, 'Unknown', NULL, NULL, 'rare', 'Paradoxides is a genus of large to very large trilobite found throughout the world during the Middle Cambrian period. One record-breaking specimen of Paradoxides davidis, described by John William Salter in 1863, is 37 cm (15 in). The cephalon was semicircular with free cheeks ending in long, narrow, recurved spines. Eyes were crescent shaped providing an almost 360° view, but only in the horizontal plane. Its elongate thorax was composed of 19–21 segments and adorned with longish, recurved pleural spines. Its pygidium was comparatively small. Paradoxides is a characteristic Middle-Cambrian trilobite of the ''Atlantic'' (Avalonian) fauna. Avalonian rocks were deposited near a small continent called Avalonia in the Paleozoic Iapetus Ocean. Avalonian beds are now in a narrow strip along the East Coast of North America, and in Europe.', '[]', 'https://cdn.jacobmaynard.dev/creatures/paradoxides-davidis.webp', 0.6138);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('3be414611ffde1303b85b', 'Eurypterus', 'Eurypterus remipes', 'Silurian', NULL, 'Unknown', NULL, NULL, 'rare', 'Eurypterus is an extinct genus of eurypterid, a group of organisms commonly called "sea scorpions". The genus lived during the Silurian period, from around 432 to 418 million years ago. Eurypterus is by far the most well-studied and well-known eurypterid. Eurypterus fossil specimens probably represent more than 95% of all known eurypterid specimens.
There are fifteen species belonging to the genus Eurypterus, the most common of which is E. remipes, the first eurypterid fossil discovered and the state fossil of New York.
Members of Eurypterus averaged at about 13 to 23 cm (5 to 9 in) in length, but the largest individual discovered was estimated to be 60 cm (24 in) long. They all possessed spine-bearing appendages and a large paddle they used for swimming. They were generalist species, equally likely to engage in predation or scavenging.', '[]', 'https://cdn.jacobmaynard.dev/creatures/eurypterus-remipes.webp', 1.3333);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('44cab61385d17bb1dda1e', 'Cameroceras', 'Cameroceras trentonense', 'Ordovician', NULL, 'Unknown', 2.0, NULL, 'common', 'Cameroceras, from Ancient Greek καμάρα (kamára), meaning "chamber", and κέρας (kéras), meaning "horn", is an extinct genus of endocerid cephalopod which lived in equatorial oceans during the entire Ordovician period. Like other endocerids, it was an orthocone, meaning that its shell was fairly straight and pointed. It was particularly abundant and widespread in the Late Ordovician, inhabiting the shallow tropical seas in and around Laurentia, Baltica and Siberia (equivalent to modern North America, Europe, and Asia).
Cameroceras exhibited a broad range of sizes, and some species were fairly large by extinct cephalopod standards. One species, C. turrisoides from the Boda Limestone of Sweden, is estimated to have shell around 2 metres (6.6 ft) in length, while that of C. rowenaense was about 70 centimetres (2.3 ft).', '[]', 'https://cdn.jacobmaynard.dev/creatures/cameroceras-trentonense.webp', 1.4528);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('f16fae5af342a3e4dff6d', 'Dunkleosteus', 'Dunkleosteus terrelli', 'Devonian', 'Late Devonian', 'Unknown', 7.0, 4000, 'legendary', 'Dunkleosteus is an extinct genus of large arthrodire ("jointed-neck") fish that existed during the Late Devonian period, about 382–358 million years ago. It was a pelagic fish inhabiting open waters, and one of the first vertebrate apex predators of any ecosystem. Fossils of Dunkleosteus have been found in the United States, Canada, Poland, Belgium, and Morocco.
Dunkleosteus consists of ten species, some of which are among the largest placoderms ("plate-skinned") to have ever lived: D. terrelli, D. belgicus, D. denisoni, D. marsaisi, D. magnificus, D. missouriensis, D. newberryi, D. amblyodoratus, D. raveri, and D. tuderensis. However, the validity of several of these species is unclear. The largest and best known species is D. terrelli, the type species. 
Since body shape is not known, various methods of estimation put the living total length of the largest known specimen of D. terrelli between 4.1 to 10 m (13 to 33 ft) long and its weight around 1–4 t (1.1–4.4 short tons).', '[]', 'https://cdn.jacobmaynard.dev/creatures/dunkleosteus-terrelli.webp', 1.4563);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('10c5d62d87fbb2fdf23f0', 'Tiktaalik', 'Tiktaalik roseae', 'Devonian', 'Late Devonian', 'Unknown', 2.7, NULL, 'rare', 'Tiktaalik (; Inuktitut: ᑎᒃᑖᓕᒃ [tiktaːlik]) is a monospecific genus of extinct sarcopterygian (lobe-finned fish) from the late Devonian Period, about 375 Mya (million years ago), having many features similar to those of tetrapods (four-legged animals). Tiktaalik is estimated to have had a total length of 1.25–2.75 metres (4.1–9.0 ft) on the basis of various specimens.
Unearthed in Arctic Canada, Tiktaalik is a non-tetrapod member of Osteichthyes (bony fish), complete with scales and gills—but it has a triangular, flattened head and unusual, cleaver-shaped fins. Its fins have thin ray bones for paddling like most fish, but they also have sturdy interior bones that would have allowed Tiktaalik to prop itself up in shallow water and use its limbs for support as most four-legged animals do. Those fins and other mixed characteristics mark Tiktaalik as a crucial transition fossil, a link in evolution from swimming fish to four-legged vertebrates.', '[]', 'https://cdn.jacobmaynard.dev/creatures/tiktaalik-roseae.webp', 1.6086);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('b37784633a551e4bfd308', 'Acanthostega', 'Acanthostega gunnari', 'Devonian', 'Late Devonian', 'Unknown', NULL, NULL, 'rare', 'Acanthostega, from Ancient Greek ἄκανθα (ákantha), meaning "spine", and στέγη (stégē), meaning "roof", is an extinct genus of stem-tetrapod, among the first vertebrate animals to have recognizable limbs. It appeared in the late Devonian period (Famennian age) about 365 million years ago, and was anatomically intermediate between lobe-finned fishes and those that were able to come onto land.', '[]', 'https://cdn.jacobmaynard.dev/creatures/acanthostega-gunnari.webp', 2.0478);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('30a93e6d964e970d6006e', 'Helicoprion', 'Helicoprion davisii', 'Permian', NULL, 'Unknown', 11.9, NULL, 'epic', 'Helicoprion is an extinct genus of large shark-like cartilaginous fish that lived from the Early to the Middle Permian, about 290-270 million years ago. Helicoprion is a member of the Eugeneodontiformes, an extinct order of cartilaginous fish within the clade Holocephali, a group today represented only by chimaeras. It is also the type genus of the Helicoprionidae, a family of eugeneodonts characterised by distinctive tooth structures called tooth whorls. Helicoprion was first named in 1899 by Alexander Karpinsky on the basis of fossils discovered in Russia and Australia, the generic name meaning "spiral saw". Although numerous species were subsequently assigned to the genus, only H. bessonowi, H. davisii, and H. ergassaminon are recognized following a 2013 revision. The three species are distinguished by the shape and spacing of their tooth crowns.
Helicoprion is mainly known from its fused, spiral-shaped tooth whorls, which account for almost all documented fossils of the taxon.', '[]', 'https://cdn.jacobmaynard.dev/creatures/helicoprion-davisii.webp', 1.2931);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('6a863f7ce88a395aa43e3', 'Cooksonia', 'Cooksonia pertoni', 'Devonian', NULL, 'Unknown', NULL, NULL, 'common', 'Cooksonia is an extinct group of primitive land plants, treated as a genus, although probably not monophyletic. The earliest Cooksonia date from the middle of the Silurian (the Wenlock epoch); the group continued to be an important component of the flora until the end of the Early Devonian, a total time span of 433 to 393 million years ago. While Cooksonia fossils are distributed globally, most type specimens come from Britain, where they were first discovered in 1937. Cooksonia includes the oldest known plant to have a stem with vascular tissue and is thus a transitional form between the primitive non-vascular bryophytes and the vascular plants.', '[]', 'https://cdn.jacobmaynard.dev/creatures/cooksonia-pertoni.webp', 0.9631);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('9f9d5982ad3d16088c241', 'Aegirocassis', 'Aegirocassis benmoulai', 'Ordovician', NULL, 'Carnivorous', NULL, NULL, 'common', 'Aegirocassis (″Aegir''s helmet″) is an extinct genus of giant radiodont arthropod belonging to the family Hurdiidae that lived 480 million years ago during the early Ordovician in the Fezouata Formation of Morocco. It is known by a single species, Aegirocassis benmoulai. Van Roy initiated scientific study of the fossil, the earliest known of a "giant" filter-feeder discovered to date. Aegirocassis is considered to have evolved from early predatory radiodonts. This animal is characterized by its long, forward facing head sclerite, and the endites on its frontal appendages that bore copious amounts of baleen-like auxiliary spines. This animal evolving filter-feeding traits was most likely a result of the Great Ordovician Biodiversification Event, when environmental changes caused a diversification of plankton, which in turn allowed for the evolution of new suspension feeding lifeforms.', '[]', 'https://cdn.jacobmaynard.dev/creatures/aegirocassis-benmoulai.webp', 1.4599);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('b1dd5e246671097501d8c', 'Arthropleura', 'Arthropleura armata', 'Unknown', NULL, 'Unknown', 1.8, NULL, 'epic', 'Arthropleura, from Ancient Greek ἄρθρον (árthron), meaning "joint", and πλευρά (pleurá), meaning "rib", is an extinct genus of massive myriapod that lived in what is now Europe and North America around 344 to 292 million years ago, from the Viséan stage of the lower Carboniferous period to the Sakmarian stage of the lower Permian period. It was a millipede, and was capable of reaching at least 2 metres (6 ft 7 in) in length, possibly up to over 2.5 metres (8 ft 2 in), making it the largest known land arthropod of all time. Arthropleura is known from body fossils as well as trace fossils, particularly giant trackways up to 50 centimetres (20 in) wide, and potentially also large burrows. It lived in open, sparsely wooded environments near water, and may have been amphibious.', '[]', 'https://cdn.jacobmaynard.dev/creatures/arthropleura-armata.webp', 1.3245);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('bdc33468cbbacc15f0a77', 'Meganeura', 'Meganeura monyi', 'Carboniferous', NULL, 'Carnivorous', 0.7, NULL, 'common', 'Meganeura (Ancient Greek: μέγα (large) + νευρόν (vein or nerve)) is a genus of extinct insects from the Late Carboniferous (approximately 300 million years ago). It is a member of the extinct order Meganisoptera, which are closely related to and resemble dragonflies and damselflies (with dragonflies, damselflies and meganisopterans being part of the broader group Odonatoptera). Like other odonatopterans, they were predatory, with their diet mainly consisting of other insects. 
The genus belongs to the Meganeuridae, a family including other similarly giant dragonfly-like insects ranging from the Late Carboniferous to Middle Permian. With single wing length reaching 32 centimetres (13 in) and a wingspan about 65–75 cm (2.13–2.46 ft), M. monyi is one of the largest-known flying insect species. Fossils of Meganeura were first discovered in Late Carboniferous (Stephanian) Coal Measures of Commentry, France, in 1880.', '[]', 'https://cdn.jacobmaynard.dev/creatures/meganeura-monyi.webp', 1.4118);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('3f2a2017e4abb67c59072', 'Dodo', 'Raphus cucullatus', 'Unknown', NULL, 'Unknown', 0.7, 18, 'rare', 'The dodo (Raphus cucullatus) is an extinct flightless bird that was endemic to Mauritius, an island east of Madagascar in the Indian Ocean. The dodo''s closest relative was the also-extinct and flightless Rodrigues solitaire. The two formed the subtribe Raphina, a clade of extinct flightless birds that are a part of the group that includes pigeons and doves (the family Columbidae). The closest living relative of the dodo is the Nicobar pigeon. A white dodo was once thought to have existed on the nearby island of Réunion, but it is now believed that this assumption was merely confusion based on the also-extinct Réunion ibis and paintings of white dodos.
Subfossil remains show the dodo measured about 62.6–75 centimetres (2.05–2.46 ft) in height and may have weighed 10.6–17.5 kg (23–39 lb) in the wild. The dodo''s appearance in life is evidenced only by drawings, paintings, and written accounts from the 17th century.', '[]', 'https://cdn.jacobmaynard.dev/creatures/raphus-cucullatus.webp', 0.7633);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('6db5b0ed6a3f682d3c5ee', 'Moa', 'Dinornis robustus', 'Unknown', NULL, 'Unknown', NULL, NULL, 'rare', 'The South Island giant moa (Dinornis robustus) is an extinct species of moa in the genus Dinornis, known in Māori by the name moa nunui. It was one of the tallest-known bird species to walk the Earth, exceeded in weight only by the heavier but shorter extinct elephant bird of Madagascar.', '[]', 'https://cdn.jacobmaynard.dev/creatures/dinornis-robustus.webp', 1.2931);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('5ee386da7094c6c5e613a', 'Haast''s Eagle', 'Hieraaetus moorei', 'Unknown', NULL, 'Unknown', NULL, 18, 'common', 'Haast''s eagle (Hieraaetus moorei), sometimes known as Fuller''s eagle, is an extinct species of eagle that lived in the South Island of New Zealand, commonly accepted to be the pouākai of Māori mythology. It is the largest eagle known to have existed, with an estimated weight of 10–18 kilograms (22–40 pounds), compared to the next-largest and extant harpy eagle (Harpia harpyja), at up to 9 kg (20 lb). Its massive size is explained as an evolutionary response to the size of its prey—the flightless moa—the largest of which could weigh 200 kg (440 lb). Haast''s eagle became extinct around 1445, following the arrival of the Māori, who hunted moa to extinction, introduced the Polynesian rat (Rattus exulans), and destroyed large tracts of forest by fire.', '[]', 'https://cdn.jacobmaynard.dev/creatures/hieraaetus-moorei.webp', 1.0);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('896cd33089a52403c1cb9', 'Elephant Bird', 'Aepyornis maximus', 'Unknown', NULL, 'Unknown', NULL, NULL, 'common', 'Aepyornis is an extinct genus of elephant bird formerly endemic to Madagascar. The genus had two species, the smaller A. hildebrandti and the larger A. maximus, which is possibly the largest bird ever to have lived. Its closest living relative is the New Zealand kiwi. They became extinct sometime around AD 1000, probably as a result of human activity.', '[]', NULL, NULL);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('c5cd7263801dfae0608fd', 'Argentavis', 'Argentavis magnificens', 'Neogene', 'Miocene', 'Unknown', NULL, NULL, 'epic', 'Argentavis is an extinct genus of teratornithid known from three sites in the Epecuén and Andalhualá Formations in central and northwestern Argentina dating to the Late Miocene (Huayquerian). The type species, A. magnificens, is sometimes called the giant teratorn. Argentavis was among the largest flying birds to ever exist, holding the record for heaviest flying bird, although it was surpassed in wingspan after the 2014 description of Pelagornis sandersi, which is estimated to have possessed wings some 20% longer than those of Argentavis.', '[]', 'https://cdn.jacobmaynard.dev/creatures/argentavis-magnificens.webp', 2.2989);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('a06b549c9518c063bf076', 'Pelagornis', 'Pelagornis sandersi', 'Paleogene', 'Oligocene', 'Unknown', NULL, NULL, 'common', 'Pelagornis is an extinct genus of prehistoric pseudotooth birds, a group of extinct seabirds. Species span from the Oligocene to the Early Pleistocene. Members of Pelagornis represent among the largest pseudotooth birds, with one species, P. sandersi, having the widest wingspan of any bird known.', '[]', 'https://cdn.jacobmaynard.dev/creatures/pelagornis-sandersi.webp', 1.3333);
INSERT OR REPLACE INTO creature (id, name, scientific_name, era, period, diet, size_meters, weight_kg, rarity, description, fun_facts, image_url, image_aspect_ratio) VALUES ('2f7702d3e73f5056a7631', 'Yutyrannus', 'Yutyrannus huali', 'Cretaceous', 'Early Cretaceous', 'Unknown', NULL, NULL, 'epic', 'Yutyrannus (meaning "feathered tyrant") is a genus of proceratosaurid tyrannosauroid dinosaur which contains a single known species, Yutyrannus huali. This species lived during the early Cretaceous period in what is now northeastern China. Three fossils of Yutyrannus huali — all found in the rock beds of Liaoning Province — are the largest-known dinosaur specimens that preserve direct evidence of feathers.', '[]', 'https://cdn.jacobmaynard.dev/creatures/yutyrannus-huali.webp', 1.7192);

